package com.davidkazad.chantlouange.datas;

import com.davidkazad.chantlouange.R;
import com.davidkazad.chantlouange.models.Book;
import com.davidkazad.chantlouange.models.Page;

import java.util.ArrayList;
import java.util.List;

public class CS extends Book {

	private List<Page> pages;

	public CS() {
		super(8, "Crois Seulement", "CS", R.drawable.book_cs);
		this.bookComingSoon = false;
	}

	@Override
	public List<Page> getPages() {
		ArrayList<Page> pg = new ArrayList<>();

		pg.add(new Page(1, "1. ", "1. CROIS  SEULEMENT.   C", "Crains  point,  petit  troupeau,  de  la  croix \nau trône,\nDe  la  mort  à  la  vie,  Il  cherchait  les  Siens;\nTout  pouvoir  sur  terre,tout  pouvoir  au  Ciel,\nLui  est  donné  pour  Son  troupeau  bien-aimé.\n\nChoeur\nCrois  seulement,  crois  seulement,\nTout  est  possible,  crois  seulement;\nCrois  seulement,  crois  seulement,\nTout    est    possible,  crois  seulement.\n(Seigneur,    je  crois...)\n(Dieu,  je  reçois...)\n(Jésus  est  là  ...)\n\nCrains  point,  petit  troupeau,  Il  t’a  précédé,\nTon  Berger  a  choisi  le  sentier  à  suivre;\nPour    toi,  Il  rendra  pure  l’eau  de  Mara,\nIl  but  toute  l’amertume  à  Gethsémané.\n\n'Crains  point,  petit    troupeau,  peu\nimporte  ton  sort,\nIl  entre  dans  les  chambres  aux\n«portes  fermées»;\nIl  n’abandonne  point,  Il  n’est  point  absent,\nAinsi,  compte  sur  Sa  présence  le  jour,\nla nuit.", 8));
		pg.add(new Page(2, "2. ", "GRACE ETONNANTE ! Ab", "Grâce étonnante! quel doux son, qui\nSauva un vil comme moi!\nJ’étais perdu, je suis retrouvé,\nAveugle, maintenant je vois.\n\nCette grâce m’a enseigné la crainte,\nEt elle ôta mes peurs;\nCombien précieuse parut cette grâce\nAu moment où j’ai cru !\nDans les dangers, peines et pièges,\nPar où je suis passé;\nCette grâce qui m’a gardé sain et sauf\nMe conduira au Ciel.\n\nLe Seigneur m'a promis du bien,\nSa Parole me soutient,\nIl sera mon Abri, ma Part\nTant que j'aurai la vie.\n\nAprès dix mille ans passés là,\nBrillants comme le soleil,\nNous aurons plus de temps qu’avant\nPour louer notre Dieu.\n\nQuand tombera cette robe de chair,\nMa vie mortelle cessera;\nJe posséderai dans l’au-delà\nUne vie de joie et paix", 8));
		pg.add(new Page(3, "3. ", "ILS VIENNENT. Eb", "Ils viennent de l’Est et l’Ouest,\nIls viennent de lointains pays,\nFêter avec le Roi comme Ses convives;\nOh! quels pèlerins bénis !\nContemplant Son saint visage\nQui brille d’éclat divin;\nParticipants de Sa grâce,\nJoyaux brillants de Sa couronne.\n\nChoeur\nMon coeur est heureux depuis\nQue Jésus m’a libéré,\nJe ne porte plus le poids des soucis,\nSon joug est si doux pour moi.\n\nMon âme était noire comme nuit,\nMais les ténèbres ont fui;\nMaintenant je crie victoire,\nCar Jésus m’a libéré.\n\nJe regarde le grand trône blanc,\nDevant sont les rachetés;\nIl n’y a plus de larmes, ni chagrins connus\nNi mort dans ce beau pays.\n\nMon Sauveur m’a précédé,\nMe préparant la voie;\nBientôt nous serons ensemble,\nDans le temps ou l’éternité.\n\nLes portails de ce saint lieu\nDemeurent ouverts nuit et jour;\nRegarde au Seigneur\nqui «donne plus de grâce,»\nDont l'amour traça la voie;\nUne place dans ces belles demeures\nQu’Il réserva pour tous.\n\nPour te préparer aux noces,\nObéis à l' appel de grâce.\n\nOh! Jésus revient bientôt,\nAlors nos peines sont finies.\n\nSi notre Seigneur venait maintenant\nPour ceux qui sont sans péché,\nAuriez-vous alors la joie,\nLa peine, le désespoir ?\nQuand Il viendra dans Sa gloire,\nNous Le rencontrerons dans les airs", 8));
		pg.add(new Page(4, "4. ", "JE L’AIME. C", "Mon coeur affranchi du monde et ses\ncharmes;\nMaintenant, par le sang, libéré des\npeurs;\nAu pied de la croix, mon coeur\ns’incline là;\nLe sang précieux de Jésus rend plus\nblanc que neige.\n\nChoeur\nOh! Je L’aime, oh! Je L’aime\nCar Il m’aima le premier\nEt acquit mon salut sur le\nBois du Calvaire.\n\nJadis perdu, plongé dans le péché;\nJadis esclave de mes passions\nardentes;\nJadis craignant de croire le Dieu\nd’amour;\nMaintenant je suis lavé par le sang\nde Jésus.\n\nJadis lié mais maintenant libéré;\nJadis aveugle mais maintenant\nje peux voir;\nAutrefois mort, maintenant je vis en Christ,\nPour proclamer au monde entier la\npaix qu’Il donne", 8));
		pg.add(new Page(5, "5. ", "MOMENT DE PRIERE. Eb", "Moment de prière, moment de prière\nQui m'appelle d’un monde de soucis\nEt m’invite au trône de mon Père\nPour faire connaître mes désirs;\nEn temps de peines et de chagrins,\nMon âme est souvent consolée,\nEchappe aux pièges du tentateur,\nPar ton retour, moment de prière.\n\nMoment de prière, moment de prière\nQuelle joie! quel bonheur je\npartage\nAvec ceux-là dont les coeurs\nbrûlent\nD’ardents désirs pour ton retour!\nAvec eux je m’empresse là\nOù mon Sauveur révèle Sa face,\nEt joyeusement je me tiens là\nEt je t’attends, moment de prière.\n\nMoment de prière, moment de prière\nTes ailes porteront ma requête\nVers Celui dont la fidélité\nTient à bénir l’âme qui attend;\nIl m'invite à chercher Sa face,\nCroire Sa Parole, croire en Sa grâce;\nSur Lui je mets tous mes soucis,\nEt je t’attends, moment de prière", 8));
		pg.add(new Page(6, "6. ", "OH! COMBIEN J’AIME JESUS ! Ab", "Il y a un Nom que j’aime entendre,\nJ’aime chanter Ses mérites;\nC’est une musique à mes oreilles,\nLe plus doux Nom sur terre.\n\nChoeur\nOh! combien j’aime Jésus!\nOh! combien j’aime Jésus!\nOh! combien j’aime Jésus!\nCar Il m’aima le premier.\n\n(Je ne L’abandonnerai.\n\n)\nIl rappelle l’amour du Sauveur,\nMort pour me délivrer,\nMe parle de Son précieux Sang,\nPlaidoirie du pécheur.\n\nIl me dit ce que le Père garde\nEn réserve pour chaque jour,\nMême si je marche dans les\nténèbres,\nIl éclaire mon chemin.\n\nIl parle d'un Homme plein d’amour\nQui peut sentir ma peine,\nPorter dans le chagrin, la part\nQue nul ne peut porter", 8));
		pg.add(new Page(7, "7. ", "QUAND LES RACHETES S' Y ASSEMBLERONT G", "Je pense à l’enlèvement vers notre\nmaison bénie d’en haut,\nQuand les rachetés s’y assembleront;\nCombien nous chanterons l’hymne\ncéleste dans cette ville là-haut,\nQuand les rachetés s’y assembleront.\n\nChoeur\nQuand les rachetés s’y assembleront,\nBlancs comme neige et libres du\npéché;\nQue des cris! que des chants!\nQuand les rachetés s’y assembleront.\n\nLà, il y aura un grand défilé dans\nles rues pavées d’or,\nQuand les rachetés s’y assembleront;\nOh! quelle musique, oh! quel chant\nretentiront là dans la ville!\nQuand les rachetés s’y assembleront.\n\nLes saints chanteront la rédemption à\nvive et haute voix,\nQuand les rachetés s’y assembleront;\nLes anges l’écouteront seulement,\nne pouvant pas la chanter,\nQuand les rachetés s’y assembleront.\n\nLe Sauveur donnera l’ordre de préparer\nle festin,\nQuand les rachetés s’y assembleront;\nNous entendrons Son appel: «Venez,\nvous bénis du Seigneur,»\nQuand les rachetés s’y assembleront", 8));
		pg.add(new Page(8, "8. ", "OH! JE DESIRE LE VOIR! Ab", "Voyageant dans le pays, je chante en\nmarchant,\nGuidant les âmes au Calvaire, au flot\ncramoisi;\nMon âme percée par les flèches,\ndedans et dehors,\nMon Seigneur me conduit, par Lui je\nvaincrai.\n\nChoeur\nJe désire Le voir, contempler Sa face!\nEt chanter pour toujours Sa grâcequi\nsauve;\nDans les rues de gloire, élever ma voix;\nLes soucis sont passés, joie\nsans fin au Ciel!\nAu service de mon Seigneur, même\ndans la nuit sombre,\nJe m’accrocherai à Lui, Il va m’éclairer;\nEt les pièges de Satan peuvent troubler\nmon âme\nMon Seigneur est devant, dirigeant le tout.\n\nQuand du fond de la vallée,\nJe vois mon Sauveur\nDebout sur la haute montagne,\ndirigeant la guerre,\nPar Sa tendre main tendue\nvers la basse vallée,\nIl me guide, je peux voir, marchant en avant.\n\nQuand devant moi les flots montent\ndu fond de l’abîme,\nMon Seigneur dirige ma barque,\nIl prend soin de moi,\nIl me conduit tendrement\nà travers ce monde,\nIl est mon vrai Ami, oh! je L’aime tant", 8));
		pg.add(new Page(9, "9. ", "NOUS NOUS SENTONS SI BIEN F", "Nous nous sentons si bien en parlant\ndu bon vieux Chemin,\nNous nous sentons si bien en parlant\ndu Seigneur;\nContinuons, continuons à parler du\nbon vieux Chemin.\n\nContinuons, continuons à parler du\nSeigneur.\n\nLe diable n’aime pas cela: parler de\nce bon vieux Chemin,\nLe diable n’aime pas cela: parler du\nSeigneur;\n(Ainsi) continuons, continuons à\nparler du bon vieux Chemin,\nContinuons, continuons à parler du\nSeigneur", 8));
		pg.add(new Page(10, "10. ", "APPRENDS-MOI SEIGNEUR, A ATTENDRE F", "Apprends-moi, Seigneur, à attendre\nA genoux jusqu’à ce que Tu m’exauces,\nA me défier de ce que font les autres,\nEt à attendre de Toi une réponse en prière.\n\nChoeur\nCeux qui s’attendent au Seigneur,\nrenouvellent leurs forces,\nIls prendront l’envol comme des aigles,\nIls courront sans se fatiguer,\nmarcheront sans faiblir,\nApprends-moi, Seigneur, à attendre.\n\nApprends-moi, Seigneur à patienter,\nAide-moi à m’humilier, à T’invoquer;\nRenouvelle ma foi et garde mes yeux\nsur Toi,\nAide-moi à être ce que Tu veux que je sois", 8));
		pg.add(new Page(11, "11. ", "ALLELUIA, NOUS RESSUSCITERONS Bb", "Au matin de résurrection,\nLa trompette de Dieu sonnera,\nNous vivrons, (Alléluia!), nous vivrons!\nLes saints viendront se réjouissant,\nAucune larme ne sera versée,\nNous vivrons, (Alléluia!), nous vivrons.\n\nChoeur\nNous vivrons, (Alléluia!)\nNous vivrons! (Amen!)\nNous vivrons, (Alléluia!)\nAu matin de résurrection,\nLes liens de la mort sont brisés,\nNous vivrons, (Alléluia!), nous vivrons.\n\nAu matin de résurrection,\nOh! quelle rencontre ce sera!\nNous vivrons, (Alléluia!), nous vivrons!\nEt lorsque nous verrons nos pères,\nNos mères et tous nos bien-aimés,\nNous vivrons, (Alléluia!), nous vivrons.\n\nAu matin de résurrection,\nOh! quelle pensée bénie pour moi !\nNous vivrons, (Alléluia!), nous vivrons!\nJe verrai mon Seigneur béni,\nQui mourut librement pour moi,\nNous vivrons, (Alléluia!), nous vivrons.\n\nAu matin de résurrection,\nNous Le rencontrerons dans l'air,\nNous vivrons, (Alléluia!), nous\nvivrons!\nEtre enlevés dans la gloire,\nVers notre demeure pure et\nbelle,\nNous vivrons, (Alléluia!), nous\nvivrons", 8));
		pg.add(new Page(12, "12. ", "PORTER UNE COURONNE! Ab", "Suis-je bien un soldat de la Croix,\nDisciple de l’Agneau,\nCraindrai-je de soutenir Sa cause,\nDe parler de Son Nom ?\n\nChoeur\nA la fin de la bataille, nous serons\ncouronnés!\nNous serons couronnés! nous\nserons couronnés!\nA la fin de la bataille, nous serons cou-\nronnés,\nDans la nouvelle Jérusalem.\n\nCouronnés, couronnés d’une\nbrillante et belle couronne.\n\nA la fin de la bataille, nous serons\ncouronnés\nDans la nouvelle Jérusalem.\n\nDois-je être transporté au Ciel\nSur un beau lit d’aisance,\nQuand d’autres combattent,\ngagnent le prix,\nNaviguant sur le sang ?\nN’ai-je pas d’ennemis à\ncombattre,\nDes vagues à surmonter ?\nCe monde se joint-il à la grâce\nPour m’amener à Dieu ?\nOui, pour régner je dois\ncombattre,\nRedonne courage, Seigneur;\nSouffrances et peines\nj’endurerai,\nAidé par Ta Parole", 8));
		pg.add(new Page(13, "13. ", "MERVEILLEUSE GRACE. F", "Merveilleuse grâce du tendre Seigneur,\nGrâce qui dépasse nos péchés et torts.\n\nElle fut déversée au mont Calvaire,\nLà, le sang de l’Agneau fut versé.\n\nChoeur\nGrâce, grâce, grâce de Dieu\nQui pardonnera, purgera l’âme;\nGrâce, grâce, grâce de Dieu,\nGrâce qui est plus grande que nos péchés.\n\nDésespoirs, péchés, comme des\nvagues froides,\nMenacent l’âme d’une perte infinie;\nGrâce qui est si grande, oui, grâce inouïe,\nConduit au refuge : la puissante Croix.\n\nTache si noire qu’on ne peut la cacher,\nQu’y a-t-il d’efficace pour l’enlever?\nVoici couler un flot cramoisi;\nQui peut te rendre plus blanc que neige.\n\nMerveilleuse grâce incomparable,\nGratuitement accordée aux croyants;\nToi qui désires contempler Sa face,\nVeux-tu maintenant recevoir Sa grâce?", 8));
		pg.add(new Page(14, "14. ", "MONT SION. Ab", "Là m’attend un joyeux lendemain,\nOù portes perlées s’ouvrent large,\nLa vallée de peines traversée,\nDe l’autre côté je camperai.\n\nChoeur\nUn jour, hors de la portée des mortels,\nUn jour, Dieu seul sait juste où et quand,\nLes roues de la vie mortelle s’arrêteront\nEt j’irai habiter au mont Sion.\n\nUn jour, j’entendrai chanter les anges,\nLà, loin des ombres de la tombe;\nToutes les cloches du Ciel sonneront,\nQuand les Saints chantent :\n«Douce demeure».\n\nUn jour, je n’aurai plus de labeurs,\nMes errances seront finies,\nTerrestres liens brisés, rétablis,\nMes soupirs et pleurs cesseront.\n\nLes nuages sombres se fendront,\nEt la nuit obscure passera;\nTous les fardeaux de la vie ôtés,\nEt poindra le jour de repos", 8));
		pg.add(new Page(15, "15. ", "NOUS MARCHONS VERS SION. G", "Laissons voir notre joie,\nNous qui aimons le Seigneur,\nJoignons au chant un doux accord,\nJoignons au chant un doux accord,\nEt environnons le trône,\nEt environnons le trône.\n\nChoeur\nNous marchons vers Sion,\nMerveilleuse, merveilleuse Sion;\nNous montons tout droit vers Sion,\nLa merveilleuse Cité de Dieu.\n\nQu'ils refusent de chanter\nCeux qui ne connaissent pas Dieu\nMais tous les enfants du Roi céleste,\nMais tous les enfants du Roi céleste,\nProclameront leur joie,\nProclameront leur joie.\n\nLa colline de Sion\nProduit des délices sacrées\nAvant que nous atteignions le Ciel,\nAvant que nous atteignions le Ciel,\nOu marchions sur les rues d’or,\nOu marchions sur les rues d’or.\n\nPuissent nos chants abonder,\nEt chaque larme être séchée;\nNous marchons sur le sol d'Emmanuel,\nNous marchons sur le sol d'Emmanuel,\nVers les beaux pays d’En-haut,\nVers les beaux pays d’En-haut", 8));
		pg.add(new Page(16, "16. ", "PURIFIE-MOI. F", "Sonde-moi, ô Dieu, connais mon\ncoeur ce jour,\nEprouve-moi, Sauveur, connais mes\npensées;\nRegarde en moi, s’il y a des voies\nperverses;\nLave-moi de tout péché, délivre-moi.\n\nSeigneur, Je Te loue, Tu m’as purifié;\nHonore Ta Parole, et rends mon coeur pur;\nLà où j’avais honte, remplis-moi du feu;\nAgrée mon désir d’exalter Ton Nom.\n\nSeigneur, prends ma vie qu’elle soit\ntoute à Toi,\nRemplis mon coeur de Ton amour divin;\nOte mes passions, mon moi et mon\norgueil,\nJe m’abandonne, Seigneur, demeure\nen moi.\n\nO Saint-Esprit, le réveil vient de Toi;\nEnvoie-le, commence le travail en moi;\nTa Parole dit : Tu pourvois aux besoins;\nJ’implore, ô Seigneur, les bénédictions", 8));
		pg.add(new Page(17, "17. ", "MES BREBIS CONNAISSENT MA VOIX Bb", "Mes brebis connaissent\nMa voix et Mon chemin,\nElles Me suivent partout où Je vais;\nElles connaissent Ma voix,\nEt viennent, quand J’appelle,\nElles ignorent la voix d’un étranger.\n\nChoeur\nElles connaissent Ma voix,\nChaque jour elles sont\nLà, dans la bergerie\nEt ne s’égarent point;\nElles M’aiment parce que\nMon choix tomba sur elles,\nEt elles suivent Mon appel\nCar elles connaissent Ma voix.\n\nMes brebis connaissent\nMa voix et le vert pré\nOù très souvent Je les mène paître;\nElles connaissent Ma voix\nEt les cours d’eau fraîche,\nJe les conduis près de ses eaux calmes.\n\nElles connaissent Ma voix,\nLa vallée de la mort\nPar où Je les mènerai un jour;\nNi danger, ni mal\nN’en peut toucher une,\nCar Je serai toujours avec elles", 8));
		pg.add(new Page(18, "18. ", "EN AVANT SOLDATS CHRETIENS ! Eb", "En avant soldats chrétiens!\nMarchant au combat,\nAvec la croix de Jésus,\nAllant de l'avant;\nChrist, le Royal Maître,\nMène contre l'ennemi;\nTout droit dans la bataille,\nRegardez Ses bannières.\n\nChoeur\nEn avant, soldats chrétiens!\nMarchant au combat\nAvec la croix de Jésus,\nAllant de l’avant.\n\nComme une puissante armée\nS'avance l'Eglise,\nFrères, nous sommes en marche\nSur les traces des Saints;\nNous ne sommes pas divisés,\nNous sommes un seul corps,\nUn dans l’espérance, la doctrine\nEt la charité.\n\nCouronnes et trônes peuvent périr\nEt royaumes tomber;\nMais l’Eglise de Jésus\nRestera constante;\nLes portes de l’enfer ne peuvent\nPrévaloir contre Elle;\nNous avons la promesse\nInfaillible de Christ.\n\nAu signal de triomphe,\nSatan s’enfuira;\nAlors soldats chrétiens,\nA nous la victoire!\nLes fondements de l'enfer\nS'ebranlent aux louanges;\nFrères, élevez vos voix et\nQue vos hymnes montent!\nEn avant, vous les peuples,\nJoignez l' heureuse foule;\nMêlez vos voix aux nôtres,\nEn chants de victoire;\n\"Gloire, honneur et louange\nSoient à Christ le Roi,\"\nChantent les hommes et les anges\nDans les âges éternels", 8));
		pg.add(new Page(19, "19. ", "PARLONS DE JESUS Bb", "Parlons de Jésus,\nIl est le Roi des rois,\nLe Seigneur des seigneurs,\nDurant l’éternité;\nLe Grand JE SUIS, la Voie,\nLa Vie, la Vérité,\nParlons de Jésus de plus en plus.\n\nParlons de Jésus,\nQue tout le monde proclame\nPuissance et majesté\nD’un tel merveilleux Nom\nBébé de Bethlehem,\nL’Etoile du matin,\nChantons donc Ses louanges partout.\n\nParlons de Jésus,\nIl est le Pain de Vie,\nC’est le Sauveur du monde,\nL’Homme de Galilée\nProphète, Prêtre, Roi,\nIl est le Dieu-Puissant,\nLa Source de l’Eau de Vie gratuite.\n\nParlons de Jésus,\nC'est le Prince de la Paix,\nIl est le Grand Médecin,\nA travers toute l'histoire.\n\nIl est le Lys pur, blanc,\nLa belle Rose de Sharon,\nIl est le Berger aux soins tendres.\n\nParlons de Jésus,\nC'est le Rocher des Ages,\nAgneau, Homme du Calvaire,\nMort pour tous les pécheurs,\nLe Grand Emmanuel,\nParole de Dieu sublime,\nEt Il est notre Epoux si divin", 8));
		pg.add(new Page(20, "20. ", "QUAND NOTRE SEIGNEUR REVIENDRA. G", "Lorsque sur les nuées du ciel,\nChrist reviendra sur la terre,\nLe monde sera-t-il dans la joie,\nQuand le Seigneur reviendra?\n\nChoeur\n‘Y aura des chants, ’y aura des cris,\n‘Y aura souffrance, ’y aura tristesse,\n‘Y aura des pleurs, ’y aura prières\nQuand le Seigneur reviendra.\n\nSa venue apportera-t-elle\nLa joie, la peine ou des larmes?\nEs-tu prêt à Le recevoir,\nQuand le Seigneur reviendra?\nToi, te joindras-tu à des pleurs\nOu au chant joyeux des Anges?\nLe couronneras-tu aussi,\nQuand le Seigneur reviendra?\nTravaille jusqu’à ce qu’Il t’appelle,\nAide à rassembler le grain,\nJoyeux, tu Le rencontreras,\nQuand le Seigneur reviendra", 8));
		pg.add(new Page(21, "21. ", "C’EST LA BATAILLE C", "C’est la bataille, la trompette se fait\nentendre,\nLe cri «Aux armes!» est entendu\npartout;\nL’Eternel des armées marche vers la\nvictoire,\nLe triomphe du juste apparaîtra.\n\nChoeur\nC’est la bataille, ô soldats chrétiens!\nEt face à face en rangs serrés,\nAvec brillante armure, bannières\nflottantes,\nBien et mal s’affrontent aujourd’hui;\nC’est la bataille, ne vous lassez pas,\nSoyez forts et fermes par Sa force;\nSi Dieu est pour nous, Sa bannière sur\nnous,\nChant de victoire nous chanterons.\n\nC’est la bataille, levez-vous, fidèles\nbraves soldats,\nJéhovah mène, assure la victoire;\nRevêtez l’armure qui vous est donnée\npar Dieu,\nEt par Sa force, endurez jusqu’au\nbout.\n\nLe Seigneur conduit à une victoire\nbien certaine,\nL’arc de la promesse couvre l’Orient;\nSon Nom glorieux sera exalté en\ntout lieu;\nLe matin vient, l’aube de la paix est\nproche", 8));
		pg.add(new Page(22, "22. ", "VICTOIRE EN JESUS Ab", "J’ai appris une vieille histoire,\nComment vint de gloire un Sauveur,\nQui donna Sa vie là au Calvaire\nPour mon salut, moi vil;\nComment Il avait gémi,\nComment Son Précieux\nsang expie,\nAlors je me suis repenti,\nVictoire, j’ai remportée.\n\nChoeur\nO la victoire en Jésus,\nMon Sauveur pour toujours,\nMe chercha, me racheta,\nPar Son sang rédempteur;\nM’aima quand je L’ignorais,\nTout mon amour est pour Lui,\nMe plongea dans la victoire,\nDans le flot purifiant.\n\nOn m’a dit qu’Il guérissait,\nQue Sa puissance lave et révèle;\nComment Il fit marcher les boiteux\nEt fit voir les aveugles;\nPuis j’ai crié : «Cher Jésus,\nViens guérir mon esprit brisé.\n\n»\nJésus vint, je ne sais comment,\nM’apporter la victoire.\n\nJ’entends parler d'une demeure\nQu’Il bâtit pour moi dans la gloire;\nJ’entends parler des rues\npavées d’or\nPar delà la mer pure;\nEt aussi des chants des anges,\nDe la vieille histoire du rachat;\nUn jour je chanterai là-haut\nLe chant de la victoire", 8));
		pg.add(new Page(23, "23. ", "MA FOI REGARDE A TOI. Eb", "Ma foi regarde à Toi,\nToi, Agneau du Calvaire,\nSauveur divin;\nEcoute-moi quand je prie,\nOte tous mes péchés,\nO laisse-moi dès ce jour\nEtre à Toi!\nQue Ta grâce infinie\nFortifie mon coeur faible,\nInspire mon zèle;\nComme Tu mourus pour moi,\nQue mon amour pour Toi\nPur, chaud, inchangé soit\nUn feu vivant!\nDurant ma sombre vie,\nLes épreuves m’environnent,\nSois mon seul Guide;\nChange les ténèbres en jours,\nEssuie mes larmes des peines,\nNe me laisse jamais\nM'éloigner de Toi", 8));
		pg.add(new Page(24, "24. ", "VIVANT PAR LA FOI. Eb", "Aujourd’hui, je ne me soucie\ndu lendemain,\nQu’il y ait ombre, pluie ou soleil,\nJe sais, le Seigneur règne sur toutes\nchoses,\nEt toutes mes inquiétudes sont vaines.\n\nChoeur\nEn Jésus-Christ, je vis par la foi,\nConfiant, croyant en Son grand\namour;\nSon bras puissant me garde de\ntout mal,\nJe vis par la foi et je ne crains rien.\n\nQu’il y ait tempête ou des nuages\norageux ,\nEclipsant l’éclat de la vie,\nLes cieux assombris ne me font\njamais peur,\nLe Maître veille sur le combat.\n\nJe sais qu’Il me conduira sûrement\nau bout,\nQu’il survienne n’importe quel\nmalheur,\nPourquoi alors me soucier de la\ntempête,\nSi Jésus marche à mes côtés.\n\nUn beau jour, le Seigneur viendra\nsur cette terre,\nAlors nos troubles cesseront,\nLe Maître nous conduira si\ntendrement\nAu delà de cette rive céleste", 8));
		pg.add(new Page(25, "25. ", "J’ABANDONNE TOUT Eb", "Tout à Jésus j’abandonne,\nJe Lui donne tout librement;\nJe L’aimerai, croirai en Lui,\nJe vivrai dans Sa présence.\n\nChoeur\nJ’abandonne tout,\nJ’abandonne tout,\nTout à Toi, mon Sauveur béni,\nJ’abandonne tout.\n\nTout à Jésus j’abandonne,\nJe me prosterne à Ses pieds,\nLes plaisirs du monde oubliés,\nJésus prends-moi, maintenant.\n\nTout à Jésus j’abandonne,\nFais-moi, Sauveur, tout à Toi;\nLaisse-moi sentir le Saint-Esprit,\nSavoir que Tu es à moi.\n\nTout à Jésus j’abandonne,\nSeigneur, je me donne à Toi;\nEnvoie-moi Ta bénédiction.\n\nRemplis-moi de Ta puissance,\nTout à Jésus j’abandonne,\nEt je sens le feu sacré;\nOh! la joie du salut parfait!\nGloire, gloire à Son Nom!", 8));
		pg.add(new Page(26, "26. ", "QUAND J’ATTEINDRAI CETTE CITE Ab", "Au sommet du Mont Sion, ' y a une cité,\nEt la terre est remplie de sa gloire;\nUn matin, je contemplerai sa\nsplendeur,\nQuand j’atteindrai cette cité sur le Mont.\n\nChoeur\nOh! Cette cité sur Mont Sion,\nQuoique pèlerin, mais je t’aime;\nEt jamais je ne te quitterai,\nQuand j’atteindrai cette cité sur le Mont.\n\nOn m’invite à retourner dans cette cité,\nLa Parole invite celui qui veut,\nLà, je trouverai un palais qui m’attend,\nQuand j’atteindrai cette cité sur le Mont.\n\nLa mort ne m’affligera dans cette cité,\nNe me fera point gésir de froid;\nEt j’entrerai là pour vivre pour toujours,\nQuand j’atteindrai cette cité sur le Mont.\n\nJ’attendrai ici l’appel de mon Sauveur,\nFaisant chaque jour Sa volonté;\nAlors là-haut, Il me dira:\n«C’est bien fait»,\nQuand j’atteindrai cette cité sur le Mont", 8));
		pg.add(new Page(27, "27. ", "PLUS TARD. F", "Tentés, éprouvés, nous nous\ndemandons\nPourquoi c'est ainsi le long du jour,\nPendant qu’il y en a d’autres autour de\nnous,\nQuoique dans le mal, sont impunis.\n\nChoeur\nPlus tard nous saurons ce qu’il en est,\nPlus tard nous comprendrons\nle pourquoi,\nCourage, mon frère, vis dans la\nlumière,\nNous comprendrons tout dans peu de\ntemps.\n\nQuand la mort vient et prend nos\nbien-aimés,\nLaissant notre maison solitaire;\nAlors nous nous demandons bien\npourquoi\nLes méchants prospèrent jour\naprès jour.\n\nFidèles jusqu’à la mort, dit le Maître,\nNotre labeur est bientôt finie;\nLes peines du chemin seront oubliées\nQuand nous franchirons la belle porte.\n\nNous verrons Jésus venir dans\nla gloire,\nQuand Il vient de Sa maison céleste,\nNous Le rencontrerons dans ce palais,\nNous comprendrons tout dans peu\nde temps", 8));
		pg.add(new Page(28, "28. ", "REMPLIS-MOI D’AMOUR. Ab", "Laisse-moi marcher, Seigneur, par où\nTu es passé,\nChemin conduisant vers le ciel,\nPartout donnant la joie, aux gens\nabandonnés,\nRemplis-moi chaque jour d’Amour.\n\nChoeur\nRemplis-moi chaque jour d’Amour,\nComme je marche avec la colombe;\nLaisse-moi marcher toujours, avec\nchant et sourire,\nRemplis-moi chaque jour d’Amour.\n\nGarde-moi à côté de mon Sauveur\net Guide,\nNe me laisse pas dans les ténèbres,\nGarde-moi du courroux et satisfais\nmon âme,\nRemplis-moi chaque jour d’Amour.\n\nBientôt finie la course, la fin de mon\nvoyage,\nJ'habiterai au Ciel chez moi;\nQue je chante, Roi béni, sur la route\nvers la rive,\nRemplis-moi chaque jour d’Amour", 8));
		pg.add(new Page(29, "29. ", "J’AI RESOLU Bb", "J’ai résolu de ne plus m’attarder,\nCaptivé par le monde;\nChoses qui sont plus hautes, choses\nqui sont plus nobles,\nOnt attiré ma vue.\n\nChoeur\nJe me hâterai vers Lui,\nTout heureux et libre,\nJésus Le plus Grand, Le Très-Haut,\nJe viendrai à Toi.\n\nJ’ai résolu d’aller vers le Sauveur,\nLaissant péchés et luttes;\nIl est le Fidèle, Il est le Juste,\nSes Paroles ont la vie.\n\nJ’ai résolu de suivre le Sauveur,\nFidèle et vrai chaque jour;\nGardant ce qu’Il dit, faisant ce qu’Il veut,\nIl est la Voie vivante.\n\nJ’ai résolu d’entrer dans le Royaume,\nDélaissant les péchés;\nQu’amis s’opposent, qu’ennemis\nm’assaillent,\nJ’y entrerai quand même.\n\nJ’ai résolu, qui ira avec moi ?\nAmi, viens sans tarder,\nInstruis par la Bible, conduits par\nl’Esprit,\nNous irons là au Ciel", 8));
		pg.add(new Page(30, "30. ", "LIEUX PLUS HAUTS G", "Je me presse sur la route du Ciel,\nNouvelles hauteurs, chaque jour je\ngagne;\nSur mon chemin, je prie toujours:\n«Place-moi, Seigneur, aux lieux plus\nhauts».\n\nChoeur\nLève-moi, Seigneur, que je me tienne,\nPar la foi, sur le plateau du Ciel,\nLa plus haute plaine jamais trouvée;\nPlace-moi, Seigneur, aux lieux plus\nhauts.\n\nMon coeur ne désire point rester\nOù doutes s’élèvent et peurs abattent;\nQue certains restent où ils abondent,\nJe prie, visant les lieux plus hauts.\n\nJe veux atteindre le sommet,\nEt voir luire la gloire éclatante;\nAvant de voir le Ciel je prie :\n«Seigneur, mène-moi aux lieux plus\nhauts»", 8));
		pg.add(new Page(31, "31. ", "DEBOUT SUR LES PROMESSES Bb", "Debout sur les promesses de Christ,\nmon Roi,\nQue Ses louanges résonnent dans\nl'éternité;\nGloire dans les Lieux très-hauts je\nchanterai,\nDebout sur les promesses de Dieu.\n\nChoeur\nDebout, debout,\nDebout sur les promesses de Dieu,\nmon Sauveur;\nDebout, debout,\nJe me tiens sur les promesses de Dieu.\n\nDebout sur les promesses infaillibles,\nQuand les tempêtes de doutes et\nde peurs assaillent,\nPar la Parole vivante de Dieu je vaincrai,\nDebout sur les promesses de Dieu.\n\nDebout sur les promesses,\nmaintenant je vois,\nDans le sang, la purification pour moi;\nDebout dans la liberté qui vient de\nChrist,\nDebout sur les promesses de Dieu.\n\nDebout sur les promesses de Christ,\nSeigneur,\nAttaché à Lui par la corde d’amour,\nToujours victorieux par l’épée de l’Esprit,\nDebout sur les promesses de Dieu.\n\nDebout sur les promesses,\nje ne peux tomber,\nToujours écoutant la voix du\nSaint-Esprit;\nReposant en mon Sauveur,\nmon Tout en tout,\nDebout sur les promesses de Dieu", 8));
		pg.add(new Page(32, "32. ", "DANS PEU DE TEMPS, LE MATIN VIENDRA F", "Nous sommes souvent ballottés\nsur la mer houleuse du temps,\nLes tempêtes et les cieux sombres\nsuccèdent au soleil brillant;\nAu Pays du jour parfait, quand les\nbrumes sont dissipées,\nOui, nous le comprendrons mieux\ndans peu de temps.\n\nChoeur\nDans peu de temps, le matin viendra,\nQuand tous les saints de Dieu seront\nrassemblés,\nNous allons raconter comment nous\nvainquions,\nCar nous le comprendrons mieux\ndans peu de temps.\n\nNous sommes souvent dépourvus\ndes choses que cette vie demande;\nAffamés et sans abri, terres arides,\ncollines desséchées;\nNous nous confions au Seigneur,\nEt ce selon Sa Parole,\nOui, nous le comprendrons mieux\ndanspeu de temps.\n\nNous avons partout d' épreuves\net nous ne comprenons pas\nLa manière dont notre Dieu nous\nconduit à la terre promise;\nMais Son oeil veille sur nous,\nnous Le suivrons jusqu'au bout,\nCar nous le comprendrons mieux\ndans peu de temps.\n\nBien souvent les pièges cachés,\nles tentations nous surprennent,\nNos coeurs sont amenés à saigner\nà cause des paroles vaines;\nPourquoi sommes-nous éprouvés\nquand nous voulons faire le bien?\nMais nous le comprendrons mieux\ndans peu de temps", 8));
		pg.add(new Page(33, "33. ", "ROCHER D’AGES Bb", "Rocher d' âges, fendu pour moi,\nLaisse-moi me cacher en Toi;\nLaisse l’eau avec le sang,\nSortis de Ton flanc percé,\nEtre un double remède,\nMe sauver me rendre pur.\n\nQue mes larmes coulent à jamais,\nQue mon zèle ne s’éteigne point,\nCela n’ôte pas mon péché;\nC’est Toi seul qui dois sauver;\nEt ma main ne t'offre rien,\nJe ne m’attache qu’à Ta croix.\n\nAlors que j'aspire ce souffle,\nQuand mes yeux se fermeront,\nEt quand je me lèverai,\nJe Te verrai sur Ton trône,\nRocher d'âges, fendu pour moi,\nLaisse-moi me cacher en Toi", 8));
		pg.add(new Page(34, "34. ", "QUAND JE VERRAI LE SANG C", "Christ, Rédempteur, est mort sur la croix,\nPour le pécheur, paya toute sa dette;\nAspergez l'âme du sang de l'Agneau,\nEt je passerai par dessus vous.\n\nChoeur\nQuand je verrai le sang,\nQuand je verrai le sang,\nQuand je verrai le sang,\nEt je passerai par dessus vous.\n\nPire des pécheurs Jésus sauvera;\nIl fera tout ce qu’Il a promis;\nLavez-vous dans la fontaine ouverte,\nEt je passerai par dessus vous.\n\nLe jugement vient et tous seront là,\nChacun recevra juste son dû;\nCachez-vous dans le sang qui rend pur,\nEt je passerai par dessus vous.\n\nGrande compassion! Amour sans\nmesure!\nAmour bienveillant, fidèle, sincère!\nTrouvez paix et abri sous le sang,\nEt je passerai par dessus vous", 8));
		pg.add(new Page(35, "35. ", "L’AMOUR M’A SAUVE Bb", "Dans le péché je sombrais,\nLoin de la rive de paix,\nAu dedans si fort souillé,\nAu point de non-retour;\nMais le Maître de la mer\nPerçut mon cri d’angoisse,\nDes eaux Il m’a tiré et\nJe suis sain et sauf.\n\nChoeur\nL’amour m’a sauvé! l’amour m’a sauvé!\nQuand rien ne put m’aider, l’amour\nm’a sauvé.\n\nL’amour m’a sauvé! l’amour m’a sauvé!\nQuand rien ne put m’aider, l’amour\nm’a sauvé.\n\nJe Lui confie tout mon coeur,\nJe m’attache à Lui et\nVis dans Sa Présence bénie\nEn chantant Ses louanges.\n\nAmour si puissant, si vrai,\nMérite mes meilleurs chants;\nUn sincère et tendre\nCulte Lui revient.\n\nAme en danger, lève les yeux,\nJésus sauve complètement;\nSon amour te tirera\nHors des vagues en furie.\n\nIl est Maître de la mer,\nLes flots Lui sont soumis;\nIl veut être ton Sauveur;\nEt sois sauvé", 8));
		pg.add(new Page(36, "36. ", "PLUIES DE BENEDICTION Bb", "'Y aura pluies de bénédiction,\nC’est la promesse d’amour;\nLe Sauveur nous enverra du Ciel\nLe temps de rafraîchissement.\n\nChoeur\nPluies de bénédiction,\nOui, nous désirons ces pluies;\nLes gouttes de grâce tombent\nautour de nous,\nMais nous réclamons les pluies.\n\n'Y aura pluies de bénédiction\nPrécieuses et vivifiantes;\nSur les collines, dans les vallées,\nLe bruit d’une pluie abondante.\n\n'Y aura pluies de bénédiction,\nSeigneur, envoie-nous ces pluies,\nAccorde-nous un rafraîchissement,\nViens honorer Ta Parole.\n\n'Y aura pluies de bénédiction,\nPuissent-elles tomber aujourd’hui,\nComme à Dieu nous nous\nconfessons,\nEt nous invoquons Jésus !", 8));
		pg.add(new Page(37, "37. ", "COMME TU VEUX, SEIGNEUR Eb", "Comme Tu veux, Seigneur!\nComme Tu le veux!\nTu es le Potier,\nJe suis l’argile.\n\nTaille-moi, façonne-moi,\nSelon Ton gré,\nPendant que j’attends,\nCalme et soumis.\n\nComme Tu veux, Seigneur!\nComme Tu le veux!\nEprouve-moi, sonde-moi,\nMaître, aujourd’hui!\nRends-moi maintenant\nPlus blanc que neige,\nComme je me prosterne\nDans Ta présence.\n\nComme Tu veux, Seigneur!\nComme Tu le veux!\nBlessé, fatigué,\nAide-moi, je prie!\nPuissance, toute puissance,\nSûrement est Tienne!\nTouche et guéris-moi,\nSauveur divin!\nComme Tu veux, Seigneur!\nComme Tu le veux!\nTiens tout mon être\nSous Ta puissance.\n\nRemplis-moi d’Esprit\nAu point qu’on ne voie\nQue Christ seul, vivant\ntoujours en moi", 8));
		pg.add(new Page(38, "38. ", "ATTIRE-MOI PLUS PRES Ab", "Je suis Tien, Seigneur, j’ai saisi\nTa Voix,\nMe parlant de Ton amour;\nMon ardent désir : Grandir dans\nla foi\nEt être plus près de Toi.\n\nChoeur\nAttire-moi plus près, Seigneur béni,\nDe la croix où Tu mourus;\nAttire-moi plus près, plus près,\nSeigneur béni,\nDe Ton précieux flanc saignant.\n\nSeigneur, consacre-moi à Ton service,\nPar la puissance de Ta grâce;\nQue mon âme T’invoque avec\nferme espoir,\nQue Ta volonté soit mienne.\n\nOh! les pures délices d’une heure\nde prière\nQue je passe devant Ton trône,\nAvec Toi mon Dieu, quand je\nm’agenouille,\nJe communie en ami.\n\n‘Y a des profondeurs d’amour\nque j’ignore\nTant que je ne passe la mer,\n‘Y a degrés de joie que je ne\npeux atteindre\nQu’en me reposant en Toi", 8));
		pg.add(new Page(39, "39. ", "JE SUIS MARQUE Ab", "J’ai perdu mon renom depuis que\nj’ai cessé de pécher,\nTant d’amis m’ont quitté depuis que\nj’ai reçu mon Sauveur;\nJadis souriants, maintenant ils me\npassent comme un inconnu;\nDisant que je suis vraiment un\ninsensé, un démodé.\n\nChoeur\nJe suis marqué, marqué, marqué;\nJe suis marqué, maintenant où que\nj’aille;\nJe suis marqué, marqué, marqué\nEt ce que je suis, tous semblent\nsavoir.\n\nJe suis scellé, scellé, scellé,\nJe suis scellé par l’Esprit Divin;\nOh! Gloire à Dieu! Alléluia! Amen!\nJe suis Sien et je sais qu’Il est mien.\n\nIls disent que ma vie est ruinée,\nque mon talent est gâché,\nIls ne comprennent pas cela, car\nj’avais des plans là-dessus;\nJe sais ce que j’ai laissé quand\nj’ai promis d’aller jusqu'au bout;\nEt j’ai eu beaucoup plus de gloire\ndepuis que Dieu m’a changé", 8));
		pg.add(new Page(40, "40. ", "NE SERAIT-CE PAS MERVEILLEUX ? Bb", "Quand avec le Sauveur nous irons\ndans la Gloire,\nNe serait-ce pas merveilleux?\nFinis les ennuis et les soucis d’ici-bas,\nNe serait-ce pas merveilleux?\n\nChoeur\nNe serait-ce pas merveilleux là?\nPlus de fardeaux à porter,\nChantant avec joie, les cloches\ndu coeur sonnant,\nOh! ne serait-ce pas merveilleux?\nMarcher et parler avec Christ,\nle Céleste,\nNe serait-ce pas merveilleux ?\nLouer, adorer l’Incomparable Eternel,\nNe serait-ce pas merveilleux ?\nLà où la tempête ne nous\nemportera plus,\nNe serait-ce pas merveilleux ?\nSûrement le Seigneur nous\ngardera pour toujours,\nNe serait-ce pas merveilleux?", 8));
		pg.add(new Page(41, "41. ", "SUR LES AILES D’UNE COLOMBE Eb", "Noé avait navigué,\nSur les eaux plusieurs jours,\nIl chercha la terre ferme,\nDe plusieurs manières;\nDes ennuis, il en a eu\nMais non pas du Ciel,\nDieu lui donna Son signe\nSur les ailes d’une colombe.\n\nChoeur\nSur les ailes d’une colombe\nblanche comme neige,\nDieu envoya Son amour doux, pur,\nUn signe du Ciel,\nSur les ailes d’une colombe.\n\nJésus-Christ, notre Sauveur\nVint un jour sur la terre;\nNé dans une étable,\nDans une crèche de paille;\nIci-bas rejeté,\nMais non pas du Ciel,\nDieu nous donna Son signe\nSur les ailes d’une colombe.\n\nBien qu'ayant beaucoup souffert\nDe bien des manières,\nJ'ai crié pour la guérison\nLa nuit comme le jour;\nLa foi ne fut pas oubliée\nPar le Père du Ciel,\nIl me donna Son Signe\nSur les ailes d’une colombe", 8));
		pg.add(new Page(42, "42. ", "J’AI ENVIE D’Y ALLER G", "Ma demeure céleste est splendide,\nJ’ai envie d’y aller;\nNi mort, ni peines n’y entreront,\nJ’ai envie d’y aller.\n\nChoeur\nOui, j’ai envie d’y aller,\nJ’ai envie d’y aller;\nMa demeure céleste est splendide,\nJ’ai envie d’y aller.\n\nEt ses tours brillent plus que le soleil,\nJ’ai envie d’y aller;\nCe palais céleste sera mien,\nJ’ai envie d’y aller.\n\nD’autres cherchent une maison ici-bas,\nJ’ai envie d’y aller;\nQue des flammes dévorent,\nles vagues inondent,\nJ’ai envie d’y aller.\n\nLe Seigneur a été bon pour moi,\nJ’ai envie d’y aller;\nAvant de voir cette maison bénie,\nJ’ai envie d’y aller", 8));
		pg.add(new Page(43, "43. ", "VIENS DINER C", "Jésus a une table où les saints de\nDieu sont nourris,\nIl invite Son peuple élu: «Viens dîner»;\nIl nourrit avec Sa manne, pourvoit\nà tous nos besoins;\nC’est bon de souper avec Lui tout le\ntemps!\n\nChoeur\n«Viens dîner», le Maître appelle: «viens dîner»\nTu peux fêter à Sa table tout le temps;\nLui qui a nourri la foule et changé\nde l’eau en vin,\nIl appelle l’affamé: «Viens dîner».\n\nLes disciples débarquèrent, en\nobéissant à Christ,\nCar le Maître les appela : «Viens dîner»;\nLà, ils trouvèrent leur désir : pain\net poisson sur le feu;\nIl satisfait les affamés tout le temps.\n\nBientôt, l’Agneau prend l’Epouse\npour toujours à Ses côtés,\nEt tous les hôtes du Ciel vont\ns'assembler;\nCe sera une vue glorieuse,\ntous les saints vêtus de blanc;\nAvec Jésus ils vont fêter pour toujours", 8));
		pg.add(new Page(44, "44. ", "DIEU NOUS CONDUIT Eb", "Dans de verts pâturages,\nsi doux, si riches,\nDieu conduit Ses précieux enfants;\nLà où coule l'eau qui ravive\nles fatigués,\nDieu conduit Ses précieux enfants;\n\nChoeur\nCertains par les eaux ou par\nles vagues,\nD’autres par le feu mais tous par\nle sang;\nCertains par les peines mais Dieu\ndonne un chant,\nPendant la nuit et tout au long du jour.\n\nDes fois sur le mont où le soleil brille\nfort,\nDieu conduit Ses précieux enfants;\nDes fois dans la vallée au coeur\nde la nuit,\nDieu conduit Ses précieux enfants.\n\nQu'il nous arrive des peines, que\nSatan s’oppose,\nDieu conduit Ses précieux enfants;\nPar la grâce nous pouvons vaincre\nl'ennemi,\nDieu conduit Ses précieux enfants.\n\nBien loin de la boue et bien loin\nde l’argile,\nDieu conduit Ses précieux enfants;\nLà-haut dans la gloire, ô jour d’éternité!\nDieu conduit Ses précieux enfants", 8));
		pg.add(new Page(45, "45. ", "REPOSANT SUR LES BRAS ETERNELS Eb", "Oh! quelle communion ! oh ! quelle\njoie divine !\nReposant sur les bras éternels;\nQuelle félicité ! quelle paix est\nla mienne !\nReposant sur les bras éternels.\n\nChoeur\nReposant, reposant,\nA l’abri de toutes les terreurs;\nReposant, reposant,\nReposant sur les bras éternels.\n\nQu'il est doux de marcher en\npèlerin !\nReposant sur les bras éternels;\nLe sentier devient plus clair\nchaque jour !\nReposant sur les bras éternels.\n\nQue puis-je redouter? Que pourrais-\nje craindre?\nReposant sur les bras éternels?\nPrès de mon Seigneur j’ai la paix bénie,\nReposant sur les bras éternels", 8));
		pg.add(new Page(46, "46. ", "LUMIERE Eb", "J’errais dans la nuit jusqu’à ce\nQue Jésus vînt à moi\nEt dissipa ma nuit par la\nLumière de Son amour.\n\nChoeur\nLa lumière dans mon âme aujourd’hui,\nLumière, lumière, le long du chemin;\nLe Sauveur m’a trouvé, ôté mes péchés,\nDepuis, j'eus en moi lumière de Son\nAmour.\n\nQue les nuages s’assemblent\nOu que les vagues m’entourent;\nQue le monde soit si sombre, j’ai\nLa lumière dans mon âme.\n\nMarchant dans la lumière de Dieu,\nJ’ai la douce communion;\nJe m’empresse avec sainte vigueur,\nLaissant le monde derrière.\n\nJe traverse les champs étendus,\nJe parcours les plaines;\nDans la lumière de Son amour,\nJe moissonne le blé mûr.\n\nBientôt je Le vois tel qu’Il est,\nLumière qui vint à moi;\nContemplant l’éclat de Sa face,\nDurant l’éternité", 8));
		pg.add(new Page(47, "47. ", "JE SAIS EN QUI J’AI CRU Eb", "Je ne sais pourquoi Dieu\nme révèle\nSa grâce merveilleuse,\nNi pourquoi Christ dans\nSon amour\nM’a racheté pour Lui.\n\nChoeur\nMais moi, «je sais en qui j’ai cru,\nJe suis persuadé qu’Il est capable\nDe garder ce que je Lui ai soumis\nConfié pour ce jour-là.\n\n»\nJe ne sais comment Il m'a donné\nCette foi salvatrice,\nNi comment, croyant Sa Parole,\nJ'ai la paix dans mon coeur.\n\nJe ne sais comment l’Esprit se meut,\nConvainquant les pécheurs,\nRévèle Jésus par la Parole,\nEt crée la foi en Lui.\n\nJe ne sais pas quel bien ou quel mal\nPeut m’être réservé,\nDes jours de joie ou de tristesse,\nAvant de voir Sa face.\n\nJe ne sais quand mon Seigneur viendra,\nEn plein jour ou la nuit,\nSi je vais mourir avec Lui,\nOu Le rencontrer dans l'air", 8));
		pg.add(new Page(48, "48. ", "APPORTANT LES FRUITS Bb", "Semant dès le matin, les semences\nd’amour,\nEn plein midi et dans la rosée du soir;\nAttendant la moisson, le temps de récolte,\nNous serons dans la joie, apportant\nles fruits,\n\nChoeur\nApportant les fruits, apportant les fruits,\nNous serons dans la joie, apportant\nles fruits,\nApportant les fruits, apportant\nles fruits,\nNous serons dans la joie, apportant\nles fruits.\n\nSemant sous le soleil, semant dans\nles ombres,\nNe craignant ni nuages ni le froid d’hiver;\nBientôt la récolte et le travail finis,\nNous serons dans la joie apportant\nles fruits.\n\nAvançant avec des pleurs, semant\npour le Maître,\nBien qu' endurant souffrances, nos\nesprits s'affligent;\nQuand nos pleurs finiront, Il nous\naccueillera,\nNous serons dans la joie, apportant\nles fruits", 8));
		pg.add(new Page(49, "49. ", "UN MATIN DORE Ab", "Un glorieux matin, plus de tristesse,\nUn glorieux matin, tout sera paix;\nFinis les chagrins, finie l’école;\nLe Ciel s’ouvrira, Jésus viendra.\n\nChoeur\nUn matin doré, Jésus viendra;\nUn matin doré, batailles gagnées;\n«Victoire» Il criera, perçant l’azur,\nUn matin doré, pour toi, pour moi.\n\nCoeurs tristes réjouis,\ntout est radieux,\nAdieu terrestres et sombres nuits;\nSoudainement changé à Son image,\nOh! glorieux matin, je vois Jésus!\nOh! quelle rencontre là dans les cieux!\nPlus de pleurs ni larmes voilant nos yeux;\nLes bien-aimés unis à jamais,\nOh! quelle aube sera ce matin-là!", 8));
		pg.add(new Page(50, "50. ", "POURRONS-NOUS A LA RIVIERE Ab", "Pourrons-nous, à la rivière,\nSortant du Trône de Dieu,\nNous rassembler sur la rive\nOù l'ange brillant a marché ?\n\nChoeur\nOui, nous allons nous rassembler,\nA la merveilleuse rivière;\nAvec tous les Saints à la rivière\nQui coule du Trône de Dieu.\n\nAu sein de cette rivière,\nLe Roi Sauveur est à nous,\nNous serons là, plus de peines,\nSous la gloire du Trône.\n\nAux bords de cette rivière,\nQui nous baigne de son eau,\nNous marcherons en adorant,\nCe sera un jour doré.\n\nAvant d'atteindre la rivière\nNous déposons tous fardeaux;\nLa grâce nous délivrera,\nNous donnera couronne et robe.\n\nA la source de la rivière,\nReflétant la face de Dieu,\nLes saints que la mort ne sépare\nChanteront la grâce qui sauve.\n\nBientôt à la pure rivière,\nLe voyage est fini;\nEt tous nos coeurs se réjouiront\nDe la mélodie de paix", 8));
		pg.add(new Page(51, "51. ", "GLOIRE A SON NOM ! Ab", "A la croix où mourut mon Sauveur,\nJe criais pour être purifié;\nLà, le sang fut appliqué à mon coeur;\nGloire à Son Nom!\n\nChoeur\nGloire à Son Nom!\nGloire à Son Nom!\nLà, le sang fut appliqué\nà mon coeur;\nGloire à Son Nom!\nJe suis si merveilleusement sauvé,\nAvec douceur Jésus est en moi,\nLà, à la croix, où Il m'a reçu;\nGloire à Son Nom!\nFontaine qui sauve du péché!\nJe suis heureux de m' y être plongé;\nLà, Jésus me sauve, me rend pur;\nGloire à Son Nom!\nViens à la Fontaine si riche et douce;\nJette ton âme aux pieds du Sauveur;\nPlonge-t' y aujourd'hui et sois pur;\nGloire à Son Nom!", 8));
		pg.add(new Page(52, "52. ", "IL M’A SORTI Eb", "Mon coeur angoissé sous l’oeil\nsévère de Dieu,\nDans la fosse où mes péchés\nm’avaient plongé;\nDe la boue profonde, j’ai crié au Seigneur\nQui tendrement m'emmena au\njour doré.\n\nChoeur\nIl m’a sorti de la boue d'argile,\nIl a placé mes pieds sur le Roc;\nIl met un chant dans mon âme ce jour,\nUn chant de louange, alléluia!\nIl m’a placé près de Lui sur le Rocher,\nMes pas sont affermis, j’y demeurerai;\nAucun risque de tomber tant que\nj’y reste,\nJusqu’au couronnement, je tiendrai\npar Sa Grâce\nIl m’a donné un nouveau chant\nde louange\nDont je chanterai les douces notes\nnuit et jour;\nMon coeur débordant, je suis libre,\nheureux,\nJe loue mon Rédempteur qui m’a\nsecouru.\n\nJe chanterai Sa merveilleuse grâce\npour moi,\nLe louerai jusqu’à faire voir Sa bonté;\nJe chanterai le salut chez moi, partout,\nJusqu'à ce que tous entendent la\nParole, croient Dieu", 8));
		pg.add(new Page(53, "53. ", "BIENTOT DANS LA DOUCEUR G", "’Y a un Pays plus beau que le jour,\nEt par la foi nous pouvons le voir;\nLe Père attend de l'autre côté\nPour nous préparer là un palais.\n\nChoeur\nBientôt dans la douceur,\nNous nous rencontrerons sur cette rive,\nBientôt dans la douceur,\nNous nous rencontrerons sur cette rive.\n\nNous chanterons sur ce beau rivage,\nLes chants mélodieux du bienheureux;\nNos esprits ne s’affligeront plus\nEt plus de soupirs pour le repos.\n\nA notre généreux Père céleste,\nNous offrirons hommages et louanges,\nPour le glorieux don de Son Amour,\nEt les bienfaits consacrant nos jours", 8));
		pg.add(new Page(54, "54. ", "’Y A UNE FONTAINE C", "’Y a une fontaine remplie de sang\nTiré des veines d’Emmanuel,\nLes pécheurs plongés dans ce flot\nPerdent toutes leurs souillures.\n\nPerdent toutes leurs souillures,\nPerdent toutes leurs souillures;\nLes pécheurs plongés dans ce flot\nPerdent toutes leurs souillures.\n\nLe voleur mourant s’est réjoui\nDe voir cette fontaine;\nEt là, vil comme lui, puissé-je être,\nLavé de tout péché.\n\nLavé de tout péché,\nLavé de tout péché;\nEt là, vil comme lui, puissé-je être,\nLavé de tout péché.\n\nAgneau mourant, Ton sang précieux\nNe perd point sa puissance\nJusqu’à ce que l’Eglise de Dieu,\nSauvée, ne pèche plus.\n\nSauvée, ne pèche plus,\nSauvée, ne pèche plus;\nJusqu'à ce que l'Eglise de Dieu,\nSauvée, ne pèche plus.\n\nDepuis que ma foi vit ce flot,\nCoulant de Tes blessures,\nL’amour rédempteur est\nmon thème\nJusqu’au jour de ma mort.\n\nJusqu’au jour de ma mort,\nJusqu’au jour de ma mort;\nL’amour rédempteur est\nmon thème\nJusqu’au jour de ma mort.\n\nPuis dans un chant noble et doux\nJe chanterai Ta puissance,\nLorsque mes lèvres\ntremblantes\nDescendront au tombeau.\n\nDescendront au tombeau,\nDescendront au tombeau;\nLorsque mes lèvres\ntremblantes\nDescendront au tombeau", 8));
		pg.add(new Page(55, "55. ", "OH! QUEL PRECIEUX AMOUR! F", "Oh! quel précieux amour du Père\nPour la race déchue d’Adam,\nLaissant souffrir Son Fils Unique\nPour nous racheter par Sa grâce!", 8));
		pg.add(new Page(56, "56. ", "JESUS NE FAILLIT. Ab", "Qu'amis soient tous infidèles,\nQue doutes, peurs assaillent,\n'Y a Un qui t'aime et prend soin,\nIl ne faillit pas.\n\nChoeur\nJésus ne faillit,\nJésus ne faillit,\nCiel et terre passeront,\nMais Jésus ne faillit.\n\nQue le ciel soit sombre\net triste,\nLe vent violent, fort,\nSouviens-toi qu'Il est tout près,\nIl ne faillit pas.\n\nA l'heure sombre de la vie,\nL'Amour prévaudra;\nCrois en Sa présence sans fin,\nJésus ne faillit", 8));
		pg.add(new Page(57, "57. ", "HYMNE DE BATAILLE DE LA REPUBLIQUE Bb", "Mes yeux ont vu la gloire de la venue\ndu Seigneur;\nIl est en train de fouler la vendange\nde la colère;\nIl a lâché le fatal éclair de Sa terrible\népée;\nSa Vérité est en marche.\n\nChoeur\nGloire! gloire, alléluia!\nGloire! gloire, alléluia!\nGloire! gloire, alléluia!\nSa Vérité est en marche.\n\nJe L’ai vu entouré d’une centaine\nde feux de bivouac;\nIls ont bâti pour Lui un autel dans\nla fraîcheur du soir;\nJe peux lire Sa juste sentence par\nle scintillement des lampes;\nSon jour est vraiment en marche.\n\nIl sonna la trompette qui jamais\nn’annonce la retraite;\nEt Il sonde les coeurs des hommes\ndevant Son trône de jugement;\nO mon âme, hâte-toi de Lui répondre!\nmes pieds, jubilez!\nNotre Dieu est bien en marche.\n\nDans la beauté de lys, Christ naquit\npar delà la mer,\nAvec dans Son sein une gloire qui\nnous transfigure, vous et moi;\nComme Sa mort sanctifia les\nhommes, mourons pour les libérer\nPendant que Dieu est en marche", 8));
		pg.add(new Page(58, "58. ", "AMEN ! F", "Amen! Amen! Amen! Amen, Amen!\nAllez-vous L’aimer? Amen!\nAllez-vous Le louer? Amen!\nAllez-vous L’adorer? Amen!\nAmen, Amen!\nAllez-vous L’aimer? Amen!\nLe servirez-vous? Amen!\nCroyez-vous en Lui? Amen!\nAmen! Amen!\nLa Bible est vraie.\n\nAmen!\nJ’ai la foi en Elle.\n\nAmen!\nC’est la Parole de Dieu.\n\nAmen!\nAmen! Amen!\nNous croyons que Tu viens.\n\nAmen!\nNous sommes prêts à Te rencontrer.\n\nAmen!\nViens Seigneur Jésus.\n\nAmen!\nAmen! Amen!", 8));
		pg.add(new Page(59, "59. ", "L' ITINERANT PREDICATEUR Bb", "L'itinérant prédicateur parcourait le pays,\nUn fusil sur son épaule et une Bible\ndans sa main;\nParlant aux gens de la prairie d’un\nbéni Pays promis;\nIl chevauchait en chantant.\n\nChoeur\nReposant, reposant,\nReposant sur le bras éternel;\nReposant, reposant,\nReposant sur le bras éternel.\n\nIl prêchait la venue du jugement\nde feu et de soufre,\nEt d’un glorieux Paradis sans fin\npour les justifiés;\nComme il traversait les montagnes\non l’entendait qui chantait,\nComme il allait chevauchant.\n\nChoeur\nIl y a force, force, merveilleuse force,\nDans le sang de l’Agneau ;\nIl y a force, force, merveilleuse\nforce,\nDans le sang précieux de\nl’Agneau.\n\nSon vieux fusil était rouillé et\nsuspendu au mur;\nRarement on touchait à sa\npoussiéreuse Bible usée;\nMais son message biblique nous\nrencontrera au jugement,\nLa Vérité est en marche.\n\nChoeur\nGloire! gloire, alléluia!\nGloire! gloire alléluia!\nGloire! gloire alléluia!\nSa Vérité est en marche", 8));
		pg.add(new Page(60, "60. ", "CHAQUE PAS SUR LA ROUTE F", "Sur les traces de Jésus:\nUn pas à la fois;\nEt je vis maintenant,\nDans l’Amour divin.\n\nSans souci du lendemain,\nA chaque jour sa peine;\nSur les traces de Jésus:\nChaque pas sur la route.\n\nEtroit est le sentier\nMais Il m’y conduit;\nA Son ombre je marche,\nFinies toutes mes peurs.\n\nMon esprit devient fort,\nChaque instant, chaque jour,\nCar Jésus dirige\nChaque pas sur la route", 8));
		pg.add(new Page(61, "61. ", "JE NE CHANCELLE PAS. Ab", "Jésus est mon Sauveur, je ne chancelle\npas;\nDans Son amour, Sa grâce,\nJe ne chancelle pas;\nJuste comme un arbre\nplanté près des eaux,\nJe ne chancelle pas.\n\nChoeur\nJe ne chancelle, je ne chancelle pas,\nJe ne chancelle, je ne chancelle pas;\nJuste comme un arbre planté près\ndes eaux,\nJe ne chancelle pas.\n\nDemeurant en mon Christ,\nje ne chancelle pas;\nCaché dans Son amour,\nje ne chancelle pas;\nJuste comme un arbre planté\nprès des eaux,\nJe ne chancelle pas.\n\nSi je Le crois toujours,\nje ne chancelle pas;\nIl ne me déçoit point,\nje ne chancelle pas;\nJuste comme un arbre planté\nprès des eaux,\nJe ne chancelle pas.\n\nJe mange Sa Parole,\nje ne chancelle pas;\nIl est bien le Guide,\nje ne chancelle pas;\nJuste comme un arbre planté\nprès des eaux,\nJe ne chancelle pas.\n\nGloire, alléluia! je ne chancelle\npas;\nAncré dans Jéhovah,\nje ne chancelle pas;\nJuste comme un arbre planté\nprès des eaux,\nJe ne chancelle pas.\n\nEtant dans Son amour,\nje ne chancelle pas;\nJe me confie en Lui,\nje ne chancelle pas;\nJuste comme un arbre planté\nprès des eaux,\nJe ne chancelle pas.\n\nQue l’enfer m’assaille,\nje ne chancelle pas;\nJésus ne me lâche pas,\nje ne chancelle pas;\nJuste comme un arbre planté\nprès des eaux,\nJe ne chancelle pas.\n\nQue la tempête sévisse,\nje ne chancelle pas;\nSur le Rocher des âges,\nje ne chancelle pas;\nJuste comme un arbre planté\nprès des eaux,\nJe ne chancelle pas", 8));
		pg.add(new Page(62, "62. ", "HIER, AUJOURD’HUI, POUR TOUJOURS Bb", "Qu’il est doux le glorieux\nmessage,\nQue la foi proclame;\nHier, aujourd’hui et pour\ntoujours\nJésus est le même,\nIl sauve encore le pécheur,\nGuérit malades, boiteux,\nConsole l’affligé, calme la tempête;\nGloire à Son Nom!\n\nChoeur\nHier, aujourd'hui et pour toujours\nJésus est le même;\nTout peut changer,\nmais Jésus ne changera\njamais!\nGloire à Son Nom,\nGloire à Son Nom;\nTout peut changer,\nmais Jésus ne changera\njamais!\nLui, qui fut l’ami des pécheurs,\nTe cherche, toi, perdu;\nViens, pécheur, t'incliner\nA Ses pieds et repens-toi.\n\nLui qui dit : «Je ne te condamne pas,\nVa et ne pèche plus.\n\n»\nIl te dit ce mot de pardon\nComme aux jours passés.\n\nSur la terre, Il guérissait par\nSa puissante main;\nMaladies et douleurs\nnous quittent\nA Son commandement.\n\nLui, dont la vertu guérit\nLa femme qui Le toucha,\nFera autant à la foi qui\nVeut Sa plénitude.\n\nLui, qui pardonna à Pierre,\nVeut que tu ne craignes pas;\nLui, qui vint à Thomas sans foi,\nOtera tes doutes,\nLui, qui laissa Jean le disciple,\nCoucher sur Son sein,\nT’invite encore avec amour :\n«Repose sur Mon Sein.\n\n»\nLui, qui, en pleines tempêtes,\nMarcha sur la mer,\nPeut encore comme en Galilée,\nCalmer nos tempêtes,\nLui, qui pria avec angoisse\nA Gethsémané,\nBoit avec nous la coupe de peur\nDans notre agonie.\n\nJadis Il partit pour Emmaüs,\nRester avec eux;\nIl veut marcher avec nous sur\nLe chemin de la vie.\n\nBientôt, nous Le verrons encore,\nHâte le jour, Seigneur!\nOui, ce sera bien \"ce même Jésus\"\nComme Il partit", 8));
		pg.add(new Page(63, "63. ", "L’ANCIEN EVANGILE. Ab", "C’est toujours l’ancien Saint-Esprit,\nEt Satan ne peut L’approcher,\nC’est pourquoi les peuples Le craignent;\nMais Il est si bon pour moi.\n\nChoeur\nDonne-moi l’ancien Evangile,\nDonne-moi l’ancien Evangile,\nDonne-moi l’ancien Evangile,\nIl est si bon pour moi.\n\nIl mettra fin à tes mensonges;\nIl te sauvera de la mort;\nIl fera s'enfuir les démons;\nEt Il est si bon pour moi.\n\nIl est bon je n’en veux d’autres,\nCar Il me fait aimer mon frère;\nIl met toutes choses à découvert,\nEt Il est si bon pour moi.\n\nIl était si bon pour nos pères;\nIl fut bon pour Paul et Silas;\nIl était bon pour frère Branham,\nEt Il est si bon pour moi.\n\nIl était bon dans la fournaise;\nIl me fait aimer mon prochain;\nIl agira quand je mourrai,\nNous amènera au Ciel", 8));
		pg.add(new Page(64, "64. ", "EMBARQUEZ Ab", "C’est le vieux bateau de Sion,\nC’est le vieux bateau de Sion,\nC’est le vieux bateau de Sion,\nEmbarquez, embarquez.\n\nIl fit arriver mon vieux père,\nIl fit arriver mon vieux père,\nIl fit arriver mon vieux père,\nEmbarquez, embarquez", 8));
		pg.add(new Page(65, "65. ", "LA DE L’AUTRE COTE Ab", "Oui, j’ai un Père dans l’au-delà,\nOui, j’ai un Père dans l’au-delà,\nOui, j’ai un Père dans l’au-delà,\nLà, de l’autre côté.\n\nUn glorieux jour j’irai Le voir,\nUn glorieux jour j’irai Le voir,\nUn glorieux jour j’irai Le voir,\nLà, de l’autre côté.\n\nQuelle bonne rencontre ce sera!\nQuelle bonne rencontre ce sera!\nQuelle bonne rencontre ce sera!\nLà, de l'autre côté.\n\nCe beau jour peut être demain,\nCe beau jour peut être demain,\nCe beau jour peut être demain,\nLà, de l'autre côté", 8));
		pg.add(new Page(66, "66. ", "ECLAIRE-MOI Ab", "Eclaire-moi, Seigneur, éclaire-moi,\nLaisse la lumière du phare m’éclairer;\nEclaire-moi, Seigneur, éclaire-moi,\nLaisse la lumière du phare m’éclairer", 8));
		pg.add(new Page(67, "67. ", "ETRE COMME LUI. Ab", "De la crèche de Bethléhem vint l’Etranger,\nSur terre, je désire être comme Lui;\nMon fidèle Sauveur, que Sa grâce est riche!\nSur terre, je désire être comme Lui.\n\nChoeur\nEtre comme Jésus, être comme Jésus,\nSur terre je désire être comme Lui;\nDurant mon voyage, de la terre au Ciel,\nJe demande seulement d’être comme Lui.\n\nSaint et tranquille, soumis et humble,\nSur terre, je désire être comme Lui;\nPar grâce, pardonné, héritier du Ciel,\nSur terre, je désire être comme Lui", 8));
		pg.add(new Page(68, "68. ", "TA FIDELITE EST GRANDE Eb", "«Ta fidélité est grande,» ô Dieu mon Père,\nAvec Toi, point d’ombre de variation,\nTu ne changes pas, Tes compassions\nne manquent pas;\nTu seras comme Tu as toujours été.\n\nChoeur\n«Ta fidélité est grande! Ta fidélité\nest grande!»\nChaque matin, je vois de nouvelles\nbontés;\nTa main pourvoit à tout ce dont\nj’ai besoin;\n«Ta fidélité est grande!», pour moi,\nSeigneur.\n\nEté, hiver, printemps et temps\nde moisson,\nSoleil, lune, étoiles là-haut dans\nleurs courses\nSe joignent à la nature en un témoignage\nDe Ta grande fidélité, grâce, amour.\n\nLe pardon du péché et une paix qui dure,\nTa chère présence qui encourage\net guide;\nForce pour ce jour, brillant espoir\npour demain,\nSont miennes ces bénédictions et\ntant d’autres", 8));
		pg.add(new Page(69, "69. ", "OUVRE MES YEUX POUR QUE JE VOIE Ab", "Ouvre mes yeux pour que je voie\nTa Vérité à mon sujet;\nPlace dans mes mains la merveilleuse clé\nQui va ouvrir et m’affranchir.\n\nChoeur\nEn silence, mon Dieu, je T’attends,\nBien prêt à voir Ta volonté;\nOuvre mes yeux, illumine-moi,\nEsprit divin!\nOuvre mes oreilles que j’entende\nLes voix claires de Ta Vérité;\nQuand les ondes sonores frappent\nmes oreilles,\nToute fausseté disparaîtra.\n\nOuvre ma bouche laisse-moi porter\nFraîche Vérité, partout, joyeux;\nOuvre mon coeur, que je me prépare\nA ainsi aimer Tes enfants", 8));
		pg.add(new Page(70, "70. ", "Il EST TOUTE CHOSE POUR MOI F", "Il est toute chose, Il est toute chose\npour moi;\nIl est toute chose, Il est toute chose\npour moi;\nCar Il est mon père, ma mère,\nma soeur et mon frère,\nIl est toute chose pour moi", 8));
		pg.add(new Page(71, "71. ", "JE SAIS C’ETAIT LE SANG F", "Je sais c’était le Sang, je sais c’était\nle Sang,\nJe sais c’était le Sang pour moi;\nLorsque j’étais perdu, à la croix\nIl mourut,\nJe sais c’était le Sang pour moi", 8));
		pg.add(new Page(72, "72. ", "OH! VEUX-TU VEILLER AVEC MOI? Bb", "Oh! veux-tu veiller avec moi une heure,\nComme je vais là-bas, comme je vais\nlà-bas?\nOh! veux-tu veiller avec moi une heure,\nComme je vais là-bas prier?", 8));
		pg.add(new Page(73, "73. ", "OH! OUI, JE TRIOMPHE ! Bb", "Oh! oui, je triomphe! oh! oui, je triomphe!\nOh! oui, je triomphe! oh! oui,\nje triomphe!\nCar j’aime bien Jésus, Il est mon\nSauveur,\nIl m’aime et me sourit", 8));
		pg.add(new Page(74, "74. ", "ESPRIT DU DIEU VIVANT. F", "Esprit Saint du Dieu vivant, viens\nmaintenant sur moi;\nEsprit Saint du Dieu vivant, viens\nmaintenant sur moi;\nBrise-moi! façonne, taille,\nremplis-moi!\nEsprit Saint du Dieu vivant, viens\nmaintenant sur moi", 8));
		pg.add(new Page(75, "75. ", "LA BEAUTE DE JESUS Eb", "Que la beauté de Jésus, Sa pureté\nEt Son merveilleux amour soient\nvus en moi;\nO Toi, Esprit divin, rends pure toute\nma nature,\nQue la beauté de Jésus soit vue en moi", 8));
		pg.add(new Page(76, "76. ", "ENFERME AVEC DIEU C", "Avec Dieu enfermé dans le secret,\nLà, dans l’Esprit, je contemple\nSa face,\nTirant de nouvelles forces pour faire\nla course,\nOh! j’aime m’enfermer avec Dieu!", 8));
		pg.add(new Page(77, "77. ", "TOURNE TON REGARD VERS JESUS F", "O âme, es-tu troublée, fatiguée ?\nNe vois-tu rien que des ténèbres ?\nUn regard au Sauveur apporte\nLumière, abondante vie gratuite.\n\nChoeur\nTourne ton regard vers Jésus,\nContemple Sa merveilleuse face;\nLes choses de la terre pâliront peu à peu\nDans la lumière de Sa gloire et grâce.\n\nDe la mort à la vie éternelle\nPar où Il passa, nous suivons;\nLe péché ne domine plus sur nous\nParce que nous sommes plus que\nvainqueurs.\n\nSa Parole ne te décevra pas;\nCrois en Lui et tout ira bien;\nAlors, va vers ce monde qui se meurt,\nProclamer Son salut parfait!", 8));
		pg.add(new Page(78, "78. ", "NOUS RENDRONS GLOIRE A JESUS Bb", "Nous rendrons gloire à Jésus,\nParlant de Son amour, parlant\nde Son amour;\nNous rendrons gloire à Jésus,\nParlant de Son merveilleux amour", 8));
		pg.add(new Page(79, "79. ", "INONDE MON AME. Ab", "Inonde mon âme, inonde\nmon âme,\nDoux Esprit, inonde mon âme;\nAssis à Tes pieds, mon repos\nest parfait;\nDoux Esprit, inonde mon âme", 8));
		pg.add(new Page(80, "80. ", "AMI DE JESUS. Eb", "Ami de Jésus, ô quelle joie,\nPour un ignoble comme moi,\nD’avoir toujours un tel ami\nPour me conduire au Ciel.\n\nChoeur\nAmi de Jésus,\nCommunion divine,\nO quelle bénie, douce communion,\nJésus est bien mon ami.\n\nAmi quand d’autres amitiés\nCessent ou me déçoivent,\nAmi qui me donne joie et paix,\nAmi quand vient l’ennemi.\n\nUn Ami dans la maladie\nEt quand approche la mort,\nAmi quand je passe la vallée,\nIl m’aide et m’encourage.\n\nAmi quand ma courte vie s’arrête,\nAmi quand passe la terre,\nAmi à voir au seuil du Ciel,\nAmi, enfin, chez moi", 8));
		pg.add(new Page(81, "81. ", "JESUS EST LE SEUL. F", "Quand le jour est sombre devant toi,\nEt les nuages sont très bas,\nIl y a Quelqu’un qui veille sur toi,\nPartout où tu peux aller.\n\nChoeur\nJésus est le seul, oui, Il est bien le seul,\nLaisse-Le s’y prendre jusqu’à la fin\ndu jour;\nTu sais, quand Il parle, les nuages\nse dissipent,\nSeulement parce qu’Il t’aime beaucoup.\n\nO si tu es triste, solitaire,\nSi la vie n’est qu’une tombe vide,\nMurmure à Jésus une prière,\nIl chassera les ténèbres.\n\nQuand tu devras passer la rivière,\nIl sera Ton ami, Ton guide;\nLà, sur l’autre rive tu vivras\nAvec Lui éternellement", 8));
		pg.add(new Page(82, "82. ", "IL VIENT DE NOUVEAU. F", "Veux-tu être compté parmi Ses brebis?\nVeux-tu être compté parmi Ses brebis?\nSois d’un coeur sans tache, veille\net attends de voir cette apparition;\nIl vient de nouveau", 8));
		pg.add(new Page(83, "83. ", "LE LYS DE LA VALLEE F", "J’ai trouvé en Jésus, l’ami qui est\ntoute chose pour moi.\n\nC’est le plus beau d’entre dix mille\npour mon âme;\nIl est le Lys de la Vallée et en Lui\nseul je trouve\nMa purification et ma guérison.\n\nMon réconfort dans les peines, appui\ndans les tourments,\nIl m’invite à Lui confier chaque\nsouci.\n\nAlléluia !\nLa Brillante Etoile du Matin, le Lys\nde la Vallée,\nC’est le plus beau d’entre dix mille\npour mon âme.\n\nIl a pris et porté sur Lui tous mes\nsoucis et peines;\nMa tour forte et puissante dans\nles tentations;\nPour Lui, j’ai tout abandonné et ôté\nde mon coeur\nMes idoles; et par Sa puissance\nIl me garde.\n\nMême si le monde m’abandonne ou\nque Satan me tente,\nPar Jésus j’atteindrai sûrement le but.\n\nAlléluia !\nLa Brillante Etoile du Matin, le Lys\nde la Vallée,\nC’est le plus beau d’entre dix mille\npour mon âme.\n\nIl ne me quittera jamais, ne me\nlaissera ici,\nTant que j’ai la foi et fais Sa volonté;\nUn mur de feu autour de moi,\nmaintenant je ne crains rien;\nMon âme affamée se nourrit\nde Sa manne.\n\nEt nous, ravis dans la gloire, verrons\nSa face bénie,\nLà, à jamais coulent les fleuves\ndes délices.\n\nAlléluia!\nLa Brillante Etoile du Matin, le Lys\nde la Vallée,\nC’est le plus beau d’entre dix mille\npour mon âme", 8));
		pg.add(new Page(84, "84. ", "IL PREND SOIN DE TOI. F", "Il prend soin de toi,\nIl prend soin de toi;\nTant le jour que la nuit,\nIl prend soin de toi", 8));
		pg.add(new Page(85, "85. ", "QUAND J’ATTEINDRAI LA FIN C", "En Galilée, le sable a couvert,\nSur la rive, les pas de l’Etranger;\nEn Judée on n’entendra plus la Voix\nQui calma les vagues en furie.\n\nMais ce jour, joyeux, je suis la voie\nDu Galiléen solitaire.\n\nEt les peines du chemin ne vaudront\nrien,\nQuand j’atteindrai la fin de la route,\nEt les peines du chemin ne vaudront\nrien,\nQuand j’atteindrai la fin de la route.\n\nIl y a tant de collines à gravir\nQue je soupire après le repos,\nCelui qui m’indique le chemin connaît\nCe qui est utile et meilleur.\n\nJe sais, Sa Parole a promis que\nMa force, «elle sera comme mon jour.\n\n»\nEt les peines du chemin ne vaudront rien,\nQuand j’atteindrai la fin de la route,\nEt les peines du chemin ne vaudront\nrien,\nQuand j’atteindrai la fin de la route.\n\nIl m’aime tant qu’Il ne peut me quitter\nNi me donner une épreuve trop forte,\nSon peuple est racheté à grand prix,\nSatan ne peut le réclamer.\n\nBientôt je vais Le voir, Le louer,\nDans la cité du jour sans fin.\n\nEt les peines du chemin ne vaudront rien,\nQuand j’atteindrai la fin de la route,\nEt les peines du chemin ne vaudront\nrien,\nQuand j’atteindrai la fin de la route\nQuand le dernier faible pas est fait,\nLes portails de cette ville apparaissent\nEt qu’alors les merveilleux chants\ndes anges\nRésonneront à mes oreilles.\n\nCe qui maintenant semble mystérieux,\nSera brillant et clair comme jour.\n\nLà, les peines du chemin ne vaudront\nrien,\nQuand j’atteindrai la fin de la route,\nLà, les peines du chemin ne vaudront rien,\nQuand j’atteindrai la fin de la route", 8));
		pg.add(new Page(86, "86. ", "PLACE A LA CROIX Ab", "Sur la croix où Jésus mourut :\nRefuge où l’on peut se cacher,\nEt Sa grâce si gratuite suffit pour moi,\nSa fontaine est profonde et large\ncomme la mer.\n\nChoeur\n’Y a place à la croix pour toi,\n’Y a place à la croix pour toi,\nQu’il y ait des millions, ’y a encore\nune place,\nOui, ’y a place à la croix pour toi.\n\nQue des millions L’aient comme Ami\nEt renoncent aux péchés commis,\nLe Sauveur attend d’ouvrir les portails,\nD’accueillir un pécheur avant qu’il ne\nsoit tard.\n\nLa main de mon Sauveur est forte\nEt l’amour de mon Sauveur demeure;\nSous soleil ou pluie, dans perte ou gain,\nLe sang coule du Calvaire pour laver\nchaque tache", 8));
		pg.add(new Page(87, "87. ", "QUAND L’APPEL RETENTIRA Ab", "Quand la trompette du Seigneur\nsonnera et le temps n’est plus,\nEt viendra l’éternel matin radieux;\nQuand les sauvés de la terre\ns’assembleront sur l’autre rive,\nQuand l’appel retentira, je serai-là.\n\nChoeur\nQuand l’appel retentira là-haut,\nQuand l’appel retentira là-haut,\nQuand l’appel retentira là-haut,\nQuand l’appel retentira, je serai-là.\n\nEn ce beau matin quand les morts\nen Christ ressusciteront,\nPartageant la gloire de Sa résurrection;\nQuand Ses élus se rassembleront\nà leur maison au Ciel,\nQuand l’appel retentira, je serai-là.\n\nAinsi travaillons pour notre Maître\ndu matin au soir,\nParlons de Son merveilleux amour\net soins;\nQuand la sera finie, notre tâche accomplie\nQuand l’appel retentira, je serai-là", 8));
		pg.add(new Page(88, "88. ", "LE PORT DE REPOS. Ab", "Mon âme en triste exil, sur mer\nde la vie,\nPeinait sous péché et détresse,\nJusqu’à ce qu’une douce voix me\ndit : «Choisis-Moi»;\nEt j’entrai au «Port de Repos!»\n\nChoeur\nJ’ai ancré mon âme dans le Port\nde Repos,\nMers houleuses je ne prendrai plus;\nQue tempête balaie mer houleuse,\norageuse,\nEn Jésus je suis en sûreté.\n\nJe me suis livré à Sa tendre étreinte,\nLa foi saisissant la Parole,\nMes chaînes sont tombées et j’ai\nancré mon âme;\nMon Seigneur est Port de Repos.\n\nVieille histoire bénie, c’est le chant\nde mon âme\nDepuis que Dieu m’a rétabli,\nVieille histoire de Jésus qui sauvera\nquiconque\nVivra dans le «Port de Repos!»\nPrécieuse est la pensée de pouvoir\ncomme Jean\nLe bien-aimé, nous reposer\nSur le bras de Jésus où tempête ne\ntrouble!\nEn sûreté au «Port de Repos!».\n\nO viens au Sauveur, Il attend patient pour\nSauver par Sa divine puissance;\nViens ancrer ton âme dans le Port\nde Repos\nEt dis : «Mon Bien-Aimé est mien.\n\n»", 8));
		pg.add(new Page(89, "89. ", "JESUS DOIT-IL SEUL PORTER LA CROIX ? Ab", "Jésus doit-Il seul porter la croix\nEt d’autres ne rien porter?\nNon, il y a une croix pour chacun,\nIl y a une croix pour moi.\n\nLa Croix consacrée je porterai,\nJusqu'à ce que mort me libère,\nPuis, au Ciel, porter ma couronne,\n'Y a une couronne pour moi.\n\nLà-bas, aux pieds percés de Jésus,\nSur le pavement de cristal,\nJoyeux, je poserai ma couronne d’or,\nRépétant Son cher Nom.\n\nO précieuse croix! Glorieuse couronne!\nO jour de résurrection!\nVous, anges, descendez des étoiles\nEt emportez mon âme", 8));
		pg.add(new Page(90, "90. ", "BENI SOIT LE NOM. Ab", "Louange à Lui qui règne au Ciel\nEn suprême majesté;\nQui sacrifia Son Fils pour l’homme\nEn vue de le racheter.\n\nChoeur\nBéni soit le Nom, béni soit le Nom,\nBéni soit le Nom du Seigneur;\nBéni soit le Nom, béni soit le Nom,\nBéni soit le Nom du Seigneur.\n\n(Jésus est le Nom.\n\n)\n(Glorifiez le Nom.\n\n)\nSon Nom est loué toujours plus,\nAu dessus de tous noms,\nA la main droite de Dieu le Père\nOù adorent des foules d’anges.\n\nRédempteur et Ami des hommes,\nHier, ruinés par la chute;\nPlan du salut Tu as conçu,\nPour ce, Tu es mort pour tous.\n\nSon Nom sera le Conseiller,\nPuissant Prince de la paix,\nVainqueur de tous royaumes\nterrestres,\nSon règne ne prendra point fin", 8));
		pg.add(new Page(91, "91. ", "J’IRAI JUSQU'AU BOUT. Ab", "Mon Seigneur, je marche dans\nla Lumière\nQui brille sur moi, Lumière venant\ndu Ciel;\nJ’ai dit adieu aux folies du monde,\nCommençant en Jésus, j’irai jusqu’au\nbout.\n\nChoeur\nOui, jusqu'au bout, j'irai jusqu'au bout,\nJ'irai avec les méprisés du Seigneur,\nPeu importe ce que font les autres,\nJusqu' au bout, Jésus, j’irai jusqu'au bout.\n\nIl y en a beaucoup qui ont commencé\nMais refusent de marcher avec\nla Lumière;\nCertains L’acceptent car Elle est\nnouvelle,\nMais peu seulement espèrent aller\njusqu’au bout.\n\nJ’aimerais marcher avec Jésus seul,\nEt avoir, comme Jacob, une pierre pour\nchevet;\nEtre à chaque instant devant Sa face\nQue sortir du chemin et manquer le but.\n\nFrère, maintenant veux-tu porter ta croix?\nAbandonne le monde, compte-le\ncomme rebut ;\nTout ce que tu as, vends et donne\naux pauvres,\nAlors va jusqu’au bout avec Jésus-\nChrist", 8));
		pg.add(new Page(92, "92. ", "PARLE, MON SEIGNEUR. G", "Ecoutez le Maître de la moisson:\n«Qui va travailler pour Moi ce jour,\nMe ramener les perdus, les mourants,\nLeur indiquer le chemin étroit ?»\n\nChoeur\nParle! mon Seigneur, parle! mon Seigneur,\nParle! je Te répondrai si vite;\nParle! mon Seigneur, parle! mon Seigneur,\nJe répondrai : «Seigneur, envoie-moi».\n\nQuand la braise ardente toucha\nle prophète,\nLe rendant aussi pur que possible,\nQuand la Voix de Dieu dit : «Qui ira\npour nous ?»\nIl répondit : «Maître, envoie-moi.\n\n»\nDes milliers meurent sans grâce,\ndans le péché;\nEntends leurs amers et tristes cris;\nHâte-toi mon frère de les secourir,\nRéponds vite : «O Maître, me voici.\n\n»\nBientôt le temps de la moisson\nprend fin;\nA la fête de la moisson bientôt,\nPuisse le Maître de la moisson\nnous dire :\n«Enfant, tu as très bien travaillé !»", 8));
		pg.add(new Page(93, "93. ", "L’AMOUR DE DIEU. Eb", "L’amour de Dieu est de loin si grand\nQue langue ou plume ne peuvent le dire ;\nIl va plus loin que la plus haute étoile,\nIl atteint le plus bas enfer.\n\nAux coupables, sous les fardeaux,\nDieu donna Son Fils pour vaincre;\nIl réconcilia Son fils errant,\nLui pardonna son péché.\n\nChoeur\nOh! l’amour de Dieu combien riche\net pur!\nIl est sans mesure et fort.\n\nIl demeurera éternellement\nLe chant des saints et des anges.\n\nQuand le temporel va disparaître,\nTrônes et royaumes terrestres\ntombent,\nEt quand les hommes qui refusent\nde prier\nInvoqueront sur rocs et montagnes;\nL'Amour de Dieu demeurera toujours;\nIl est sans mesure et fort,\nGrâce rédemptrice pour la race\nd'Adam;\nLe chant des saints et des anges.\n\nSi nous remplissions l'océan d'encre,\nSi les cieux étaient parchemins;\nSi chaque tige était une plume,\nEt tout homme était écrivain;\nDécrire l'Amour de Dieu Céleste\nDessécherait l'océan,\nLe rouleau ne contiendrait le tout,\nQuoique couvrant tout le ciel", 8));
		pg.add(new Page(94, "94. ", "LA RENCONTRE DANS LES AIRS Ab", "On t’a parlé de l’enfant Moïse dans\nles joncs\nEt de l’intrépide David avec\nsa fronde;\nDe l’histoire que tu chantes sur\nJoseph et ses songes,\nAinsi que celle de Jonas et la baleine.\n\nIl y en a beaucoup, beaucoup\nd’autres dans la Bible,\nJ’aimerais les rencontrer tous,\nJe l’avoue!\nBientôt sûrement, le Seigneur nous\nles fera voir\nA cette rencontre dans les airs.\n\nChoeur\nIl y aura une rencontre dans les airs,\nUn de ces jours, oui, bientôt;\nJe veux te rencontrer, rencontrer là\nDans cette Maison là au Ciel;\nTu suivras des chants que jamais\nmortel n’a entendus,\nCe sera glorieux, je l’avoue!\nLe Fils de Dieu Lui-même sera en tête\nA cette rencontre dans les airs.\n\nBien des choses auront disparu à\ncette rencontre :\nCar le banc des pénitents n’y sera plus;\nIl n’y aura plus de sermons prêchés\nau pécheur,\nCar le pécheur aura rejeté l’appel.\n\nPlus d’afflictions à cause des\nbien-aimés rebelles,\nNi de veillées solitaires d’intercession;\nTous nos fardeaux et nos angoisses\nseront ôtés\nA cette rencontre dans les airs.\n\nLà, les incrédules seront tout à fait\nabsents,\nTous les sceptiques seront absents\nce jour-là;\nPlus de mécontents là qui nous\ndérangeraient,\nEt les Acans seront occupés ailleurs.\n\nLà-bas les Saints porteront Son\n« sceau sur leurs fronts,»\nVêtus d’habits réservés aux rachetés;\nTous ceux qui sont en habits de noces\nseront là,\nA cette rencontre dans les airs", 8));
		pg.add(new Page(95, "95. ", "IL RUISSELLE DE SANG. F", "Le premier à mourrir\npour le plan de l'Esprit,\nFut Jean le Baptiste, mais il mourut\nen homme,\nPuis le Seigneur Jésus, ils L'ont\ncrucifié,\nIl prêcha que l’Esprit sauverait\nles pécheurs.\n\nChoeur\nIl ruisselle de sang, oui, Il ruisselle\nde sang,\nL’Evangile du Saint-Esprit, Il ruisselle\nde sang,\nLe sang des disciples, morts pour la\nVérité,\nL’Evangile du Saint-Esprit, Il ruisselle\nde sang.\n\nIl y avait Pierre et Paul, et puis Jean le\ndivin,\nIls ont donné leurs vies pour que\nl'Evangile brille;\nIls ont mêlé leur sang, comme\nles anciens prophètes,\nPour que la Parole vraie soit\nfidèlement prêchée.\n\nIls lapidèrent Etienne qui condamnait\nle mal,\nExcitant leur colère, ils brisèrent\nsa tête;\nIl mourut dans l'Esprit, il rendit\nson âme\nEt alla rejoindre tous les autres martyrs.\n\nDes âmes sont sous l'autel, criant:\n«Jusqu'à quand?» pour\nQue le Seigneur punisse\ntous ceux qui font le mal;\nIl y en aura beaucoup,\ndont le sang coulera\npour ce Saint Evangile et son flot\ncramoisi", 8));
		pg.add(new Page(96, "96. ", "SAINT, SAINT, SAINT F", "Saint, Saint, Saint ,le Seigneur Dieu\ndes armées!\nCiel et terre sont pleins de Toi,\nCiel et terre Te glorifient,\nO Dieu Très-Haut!", 8));
		pg.add(new Page(97, "97. ", "CE MONDE NE PEUT ME LIER Ab", "Ce vieux monde ne peut me lier,\nJe m’en irai n’importe quand,\nParce que je me suis consacré\nEt je porte mon habit de noces", 8));
		pg.add(new Page(98, "98. ", "LE RETOUR DE NOTRE SEIGNEUR G", "J’attends vraiment la venue du joyeux\njour de Millénium,\nQuand le Seigneur viendra enlever\nson Epouse qui attend;\nMon coeur est plein de ravissement,\ncomme je travaille, veille et prie.\n\nCar notre Seigneur revient encore\nsur terre.\n\nChoeur\nOh! notre Seigneur revient encore\nsur terre!\nOui, notre Seigneur revient encore\nsur terre.\n\nSatan sera lié pour mille ans, nous\nne serons plus tentés,\nQuand Jésus reviendra de nouveau\nsur terre.\n\nLe retour de Jésus sera la réponse\naux cris de peines,\nCar la connaissance du Seigneur\nremplira terre, mer et ciel;\nDieu ôtera toutes maladies, les larmes\nde peines séchées,\nQuand notre Sauveur revient encore\nsur terre.\n\nLes rachetés du Seigneur viendront à\nSion avec joie,\nSur Sa sainte montagne rien ne\ndétruira, ni ne nuira;\nLa paix parfaite et l'amour pur régneront\ndans tous les coeurs,\nQuand Jésus reviendra de nouveau\nsur terre.\n\nAlors péché, mort, chagrin et peine\nde ce monde cesseront,\nDans un règne glorieux avec Jésus\npendant mille ans de paix;\nLa terre entière gémit, crie pour ce jour\nde douce délivrance\nQuand notre Jésus revient encore\nsur terre", 8));
		pg.add(new Page(99, "99. ", "JE LE RECONNAITRAI. F", "Debout quelque part dans l’ombre,\nTu trouveras Jésus,\nIl est Celui qui toujours prend soin,\ncomprend;\nDebout quelque part dans l’ombre,\nTu vas Le trouver,\nTu Le reconnaîtras aux marques\ndans Ses mains.\n\nChoeur\nOui, je vais Le reconnaître,\nRacheté, je serai près de Lui;\nOui, je vais Le reconnaître\nPar les empreintes des clous dans\nSes mains.\n\nQuand mon travail terminé, je passe\nla marée haute;\nQuand je vois le matin brillant et glorieux;\nJe reconnaîtrai mon Sauveur, là,\nsur l'autre rive;\nSon sourire va m'accueillir en premier\nlieu.\n\nMon âme tressaille de joie quand je vois\nSa face bénie\nEt le doux éclat rayonnant de Ses yeux;\nMon coeur Le loue pour Sa bonté, Son\namour, Sa grâce\nQui préparent pour moi une maison au\nCiel.\n\nOh! mes bien-aimés dans la gloire\nm'invitent à venir;\nJe me souviens de notre séparation.\n\nDans la belle vallée d'Eden, ils chantent\nà la maison;\nJe désire en premier rencontrer mon\nDieu.\n\nVêtu d'une robe, Dieu me conduira vers\nles portails\nDe la cité où il n'y aura point de larmes;\nEt je chanterai une gaie chanson avec\nles anges;\nJe désire en premier rencontrer mon\nDieu", 8));
		pg.add(new Page(100, "100. ", "PUIS JESUS VINT C", "Un homme mendiait, assis seul au\nbord d’une route,\nAveugle, il ne voyait la lumière,\nSaisit ses haillons, frissonna dans le noir,\nPuis Jésus vint et chassa ses ténèbres.\n\nChoeur\nQuand Jésus vient, la tentation est vaincue;\nQuand Jésus vient, les larmes sont\nessuyées.\n\nIl ôte la tristesse, remplit de gloire la vie,\nCar tout change quand Jésus vient\ns’établir.\n\nEloigné des siens, du toit,\npar les démons,\nCroupissant dans la misère\nau cimetière;\nSaisi par les démons, il se tailladait,\nPuis Jésus vint, libéra le captif.\n\nImpur! impur! criait le lépreux inquiet,\nSourds, muets se tenaient là délaissés;\nFièvre fit rage, maladie prit sa victime,\nPuis Jésus vint et dissipa toute peur.\n\nAujourd’hui les hommes ont un\npuissant Sauveur,\nIls ne pouvaient vaincre passions, péchés;\nLeurs coeurs brisés les ont laissés\nseuls et tristes,\nPuis Jésus vint et s’établit en eux", 8));
		pg.add(new Page(101, "101. ", "QUAND JE CONTEMPLE LA CROIX F", "En contemplant l’étonnante croix\nOù mourut le Prince de la gloire,\nJe compte comme perte mon plus\ngrand gain,\nEt je méprise tout mon orgueil.\n\nSeigneur, empêche que je me vante,\nSauf de la mort de Christ, mon Dieu;\nToutes choses vaines qui me\ncharment le plus,\nJe les sacrifie pour Son sang.\n\nVois, de Sa tête, Ses mains, Ses pieds,\nCoule l’amour mêlé au chagrin;\nCes deux se sont-ils jamais joints,\nOu épines firent-elles riche couronne?\nSi tous les royaumes étaient miens,\nCe serait un cadeau minime;\nL’amour si étrange, si divin,\nRéclame mon âme, ma vie, mon tout", 8));
		pg.add(new Page(102, "102. ", "PAR L’EAU F", "Jadis des jeunes filles puisaient\nDe l’eau vers le soir, dit-on.\n\nIsaac envoya Eliézer\nPour intercepter Rébecca\nEt lui dire : «Vois ces précieuses perles,\nC’est mon maître qui m’envoie;\nNe veux-tu pas être Sa belle\nEpouse là-bas au pays?»\n\nChoeur\nAu temps du soir il y’aura la Lumière,\nVous trouverez le sentier vers la gloire;\nEnseveli dans l'eau au Nom de Jésus,\nC'est bien cela la lumière aujourd'hui\nJeunes, vieux, repentez-vous du péché,\nLe Saint-Esprit entrera bien en vous;\nC’est la Lumière du soir,\nC' est un fait que Christ et Dieu sont Un.\n\nAinsi les serviteurs de Dieu\nTe parlent d’un Epoux céleste\nA la recherche d’un saint peuple\nQui bientôt sera Son épouse;\nIl nous envoie l’eau rafraîchissante\nCe dernier glorieux jour;\nCeux-là qui seront enlevés,\nDoivent passer à travers l’eau.\n\nEs-tu sur la voie de la ruine\nEt encombré de soucis?\nVois l'oeuvre prompte que Dieu fait\nPour que tu prennes part à Sa gloire.\n\nLa foi qu’Il transmit jadis aux saints\nEst enfin nôtre aujourd’hui;\nPour être en l’Eglise triomphante\nTu dois bien passer par l’eau.\n\nAujourd'hui la puissance est faible,\nT’es-tu demandé pourquoi ?\nVas-tu rester dans ces vieilles choses,\nSuivre la voie faite par l'homme ?\nO vous saints jamais ensevelis\nDans le Nom béni de Dieu,\nLa vérité vous sanctifie ;\nPar là passèrent les apôtres", 8));
		pg.add(new Page(103, "103. ", "N’OUBLIEZ PAS LA PRIERE EN FAMILLE F", "N’oubliez pas la prière en famille,\nJésus veut vous trouver là ;\nIl s'occupera de vous,\nOh! n’oubliez pas la prière en famille!", 8));
		pg.add(new Page(104, "104. ", "ETRE SUR CE ROC F", "Criant «Saint, Saint, Saint»\nau Seigneur,\nCriant «Saint, Saint, Saint» au Seigneur,\nSi possible, je voudrais bien\nEtre sur le même roc que Moïse", 8));
		pg.add(new Page(105, "105. ", "OH ! J'AIME CET HOMME DE GALILEE F", "Dans une crèche il y a longtemps,\nje sais, c'est évident\nQu’un Bébé naquit, Sauveur des pécheurs.\n\nJean Le vit sur le rivage, Lui, l’Agneau\npour toujours,\nOh! Christ, le Crucifié du Calvaire.\n\nChoeur\nOh! que j’aime cet Homme de Galilée,\nde Galilée\nParce qu’Il a fait beaucoup pour moi.\n\nIl pardonna mes péchés, me remplit\ndu Saint-Esprit;\nOh! que j’aime, que j’aime cet Homme\nde Galilée!\nLe publicain vint prier au temple\nce jour-là,\nIl cria : «Seigneur, aie pitié de moi!»\nSes péchés furent pardonnés, une\ndouce paix le remplit;\nIl dit : «Venez voir l’Homme de Galilée.\n\n»\nIl fit marcher les boiteux , fit parler\nles muets,\nCette puissance fut proclamée dans\nl’amour;\nEt Il fit voir les aveugles, cela ne\npouvait être\nQue la grâce de Cet Homme de Galilée.\n\nNicodème vint de nuit, découvrir le\nchemin,\nIl demanda au Fils de l’Homme que faire.\n\nCelui-ci lui dit ces mots : «Tu dois\nnaître de nouveau»,\nPar l’Esprit de Cet Homme de Galilée.\n\nIl révéla les péchés de la femme\nau puits :\nComment, les cinq maris, elle avait eu.\n\nSes péchés furent pardonnés, une\ndouce paix la remplit,\nElle dit :«Venez voir l’Homme\nde Galilée.\n\n»", 8));
		pg.add(new Page(106, "106. ", "TENDS LA MAIN ET TOUCHE LE SEIGNEUR F", "Tends la main, touche le Seigneur\npendant qu’Il passe,\nTu verras qu'Il n'est pas trop pris,\nIl entend ton cri;\nPour pourvoir à tes besoins Il passe\nmaintenant,\nTends la main, touche le Seigneur\npendant qu’Il passe", 8));
		pg.add(new Page(107, "107. ", "DANS CETTE CITE, L’AGNEAU EST LA LUMIERE Bb", "Il y a un pays au delà des étoiles,\nIl y a une cité où il n’y a point de nuit;\nSi nous sommes fidèles, nous irons\nlà bientôt,\nC’est la cité où l’Agneau est la Lumière.\n\nChoeur\nDans cette cité où l’Agneau est\nla Lumière,\nCette cité où il n’y a point de nuit;\nJ'ai un beau palais là-haut,\net libéré des soucis,\nJe m’en irai où l’Agneau est\nla Lumière.\n\nIci nous sommes éclairés, mais nous\nsavons\nQue ce soleil qui luit sur nous\nmaintenant,\nSe changera en nuages quand nous\nirons\nA la cité où l’Agneau est la Lumière.\n\nLà, les fleurs s'épanouissent\ntoujours et le jour\nSera un jour éternel, et point de nuit !\nNos larmes seront essuyées à jamais,\nDans cette cité où l’Agneau est\nla Lumière.\n\nIci nous avons toujours des frustrations,\nEt nos espoirs rencontrent\nles déceptions;\nIci nous pleurons, là-bas sera la joie,\nDans cette cité où l’Agneau est\nla Lumière.\n\nQue le soleil faiblisse ou qu'il y ait\nla nuit,\nMon coeur bienheureux n'a peur\nd'aucun ombrage,\nCar je sais que là au Ciel j'ai\nune maison,\nDans cette cité où l’Agneau est\nla Lumière", 8));
		pg.add(new Page(108, "108. ", "JESUS M’A AFFRANCHI Ab", "Je suis très heureux, Jésus m’a\naffranchi,\nJe suis très heureux, Jésus m'a\naffranchi,\nJe suis très heureux, Jésus m'a\naffranchi,\nGloire, alléluia, Jésus m’a affranchi!\nJe suis très heureux, Jésus m’a sauvé,\nJe suis très heureux, Jésus m'a sauvé,\nJe suis très heureux, Jésus m'a sauvé,\nGloire, alléluia, Jésus m'a sauvé.\n\nEn route vers le Ciel, je crie la victoire,\nEn route vers le Ciel, je crie la victoire,\nEn route vers le Ciel, je crie la victoire,\nGloire, alléluia, je crie la victoire", 8));
		pg.add(new Page(109, "109. ", "QUAND JE M’EN IRAI", "EN VACANCES Bb\nIci, beaucoup de gens vont en vacances\nVers les montagnes, les lacs ou la mer;\nLà, ils se reposent des soucis\net troubles,\nQuel merveilleux temps cela doit être!\nMais être comme eux ne semble pas\nêtre ma part,\nPar temps chaud, froid, je dois\noeuvrer dur,\nCherchant sur les monts les brebis\nperdues,\nRamenant les errants au bercail.\n\nChoeur\nQuand je m’en irai en vacances\nau Ciel,\nOh! quel merveilleux temps ce sera!\nEcoutant les accords du choeur céleste,\nJe verrai la face de mon Sauveur;\nM’asseyant sur les bords de la rivière;\nSous l’ombrage de l’arbre toujours vert,\nJe déposerai mes fardeaux pour\ntoujours,\nViens passer tes vacances avec moi.\n\nUn beau jour je m’en irai en vacances\nDans la cité que Jean nous décrit;\nSa fondation est en pierres précieuses,\nLà, je crierai de joie du coeur!\nOh! aucune des scènes vues\npar les mortels\nNe peut égaler les gloires d’en haut !\nJe passerai mes vacances avec Jésus\nAu lieu qu’Il est allé préparer.\n\nLà-bas, il fera à jamais beau temps,\nAucun nuage ne voilera le ciel;\nSéismes ni cyclones ne menaceront,\nLà, dans ce pays «Qui vient bientôt»;\nTrès bientôt il y aura une excursion,\nJe suis inscrit au tour dans les airs,\nViens donc passer les vacances\navec moi,\nPrends part au festin de notre Epoux.\n\nIci-bas quand nous allons en vacances,\nNous regagnons sitôt la maison;\nQuand je m’en irai en vacances au Ciel,\nDans ces palais en or là au Ciel,\nJe vivrai toujours avec mon Sauveur,\nM’assoirai avec Lui sur Son Trône;\nOh! tous les jours seront de longues\nvacances\nQuand mon Sauveur m’amènera chez Lui", 8));
		pg.add(new Page(110, "110. ", "OH! C’EST JESUS ! C", "Oh! c’est Jésus ! oui, c’est Jésus !\nOui, c’est Jésus dans mon âme;\nCar j’ai touché le bord de Son vêtement,\nEt Son sang m’a rétabli", 8));
		pg.add(new Page(111, "111. ", "ET ALORS ? F", "Quand les industries de nos villes\nauront fourni leurs tout derniers\nproduits,\nQuand nos marchands auront tout\nvendu et licencié leur dernier agent,\nQuand nos banques auront leur\ndernier dollar, payé les dernières\ndividendes,\nQuand le juge dira : «Fermé cette\nnuit» et exigera les comptes.\n\nEt alors?\n\nChoeur\nEt alors ? Et alors ?\nQuand le grand Livre est ouvert,\nEt alors ?\nQuand ceux qui maintenant\nrejettent ce Message, ce soir,\nSeront sommés de dire pourquoi -\nEt alors ?\nQuand sera dite la dernière prière\ndu pasteur, le dernier choeur joué,\nQuand les gens auront entendu\nleur dernier sermon, et que tout se tait,\nQuand la Bible restera fermée sur\nl’autel et que l’église sera vide,\nChacun sera devant son dossier,\nle grand Livre sera ouvert - Et alors?\nQuand les acteurs auront joué leur\ndernière scène, les mimes leur\ndernier tour,\nQuand on aura projeté le tout\ndernier épisode du dernier film,\nQuand les jouisseurs auront\ndisparu; boîtes et dépôts d’alcool\nseront clos,\nEt que le vendeur écoule la\ndernière goutte, qu’il s’en va\ndans les ténèbres,\nQuand la trompette des âges\nsonnera; nous nous tiendrons\ndevant Lui - Et alors ?\nQuand le clairon se sera tu, les troupes\nen marche se seront arrêtées,\nLe capitaine aura repris ses\nordres et le drapeau baissé du mât,\nQuand le blessé qui était au loin\naura été ramené au bercail,\nCe monde qui rejette son\nSauveur sera sommé de dire\npourquoi - Et alors ?", 8));
		pg.add(new Page(112, "112. ", "LA FOI EN JEHOVAH F", "Foi dans le Père et foi dans le Fils,\nFoi dans le Saint-Esprit, ces trois sont Un ;\nLes démons tremblent, les\npécheurs s’éveillent;\nLa foi en Jéhovah ébranle toute chose", 8));
		pg.add(new Page(113, "113. ", "LAISSE-LES G", "Si le monde te privait de son\nargent et son or,\nEt que tu dois vivre misérablement,\nSouviens-toi, dans Sa Parole, comment\nIl nourrit même les oiseaux;\nAbandonne tes fardeaux à ton Seigneur.\n\nChoeur\nLaisse-les, laisse-les,\nAbandonne tes fardeaux à ton Seigneur,\nSi tu crois sans défaillir, Il saura\nte secourir\nAbandonne tes fardeaux à ton Seigneur\nSi ton corps endure la peine sans\nrecouvrer la santé,\nTon âme presque noyée dans\nle désespoir,\nJésus sait ce que tu sens, Il\npeut sauver et guérir;\nAbandonne tes fardeaux à\nton Seigneur.\n\nQuand tes ennemis t’assaillent, ton\ncoeur commence à faiblir,\nN’oublie pas que Dieu répond à la\nprière;\nIl fera une voie pour toi,\nte conduira sûrement;\nAbandonne tes fardeaux à\nton Seigneur.\n\nSi ta jeunesse t'abandonne et\ntu commences à vieillir,\nTon corps se courbe sous le poids\ndes soucis;\nIl ne te quittera pas, Il ira avec toi\nau bout;\nAbandonne tes fardeaux à ton Seigneur", 8));
		pg.add(new Page(114, "114. ", "JE PEUX CROIRE, JE CROIRAI JE CROIS G", "Je peux croire, je croirai, je crois;\nJe peux croire, je croirai, je crois;\nJe peux croire, je croirai, je crois\nQue Jésus me guérit.\n\n(Je ne me confie qu’en mon Seigneur.\n\n)", 8));
		pg.add(new Page(115, "115. ", "N’EST-IL PAS MERVEILLEUX ? Bb", "N’est-Il pas merveilleux,\nmerveilleux, merveilleux ?\nMon Seigneur, n’est-Il pas\nmerveilleux ?\nJ’ai vu et entendu ce que dit Sa Parole;\nMon Jésus n’est-Il pas merveilleux ?", 8));
		pg.add(new Page(116, "116. ", "LE BATEAU DE SAUVETAGE. G", "Les flots du temps nous entraînent,\nMais ce n’est plus pour longtemps;\nNuages orageux de la nuit\nFeront place au jour clair.\n\nAlors prenons tous courage\nCar nous ne sommes pas\ntout seuls;\nLe bateau de sauvetage vient\nRamener les Perles au Ciel.\n\nChoeur\nCourage, mon frère, courage,\nBientôt nos épreuves sont finies!\nSur la rive d’orée\nNous rencontrerons nos bien-aimés.\n\nIci, pèlerins, étrangers,\nNous cherchons une cité;\nLe bateau de sauvetage vient\nRamener les Perles au Ciel.\n\nSatan me tente parfois\nDisant que c’est inutile\nDe marcher au Nom de Jésus\nEt vivre en chrétien;\nMais alors le Maître nous dit :\n«Je veux vous secourir,\nConfiez-vous en Moi,\nJe vous conduirai au Pays.\n\n»\nJ’aperçois par la foi\nLe bateau de sauvetage qui vient,\nComment sur les eaux il s’avance,\nVenant nous secourir,\nNous faire arriver à bon port\nAvec nos bien-aimés.\n\n«Soyez prêts», crie le Capitaine,\n«Bientôt il sera là.\n\n»\nOh! c’est le moment de monter\nà bord\nPendant qu’il passe!\nMais si tu t’arrêtes trop longtemps,\nTu mourras pour toujours;\nLe prix étant payé pour tous,\nLe Capitaine t’invite,\nCe bateau te conduit sûrement au Ciel,\nEmbarque-toi", 8));
		pg.add(new Page(117, "117. ", "IL COULERA COMME UNE RIVIERE C", "Il coulera comme une rivière,\nIl tombera comme la pluie,\nIl viendra comme rosée du matin\ndans la plaine;\nLa connaissance du seigneur\nremplira la terre\nQuand l’Esprit du Seigneur tombera.\n\nCoule, rivière, coule! coule, rivière,\ncoule!\nArrose les nations, partout où\nl’homme peut aller;\nFais croître la vie pour que tous\nles hommes sachent\nQue Tu es la rivière de l’Esprit;\nOh! coule, rivière, coule!", 8));
		pg.add(new Page(118, "118. ", "LE GRAND JUGEMENT C", "J’ai rêvé que l’aube du grand\njugement\nSe levait, la trompette sonnait;\nJ’ai vu des nations être rassemblées\nEn vue du jugement du trône Blanc;\nDu trône vint un Ange très brillant qui\nSe tint sur la terre et la mer,\nAvec Sa main levée vers le Ciel,\nIl jura : «il n’y a plus de temps.»\n\nChoeur\nOh! que des pleurs et des\ngémissements,\nQuand les perdus connurent leur sort !\nIls crièrent aux rochers et montagnes,\nIls prièrent; hélas! c’était trop tard.\n\nL’homme riche était là mais\nson argent\nSe détruisit et disparut;\nAppauvri, il se tint au jugement,\nSes dettes furent trop lourdes\nà payer;\nLe grand homme fut là, mais\nsa grandeur\nResta en arrière à sa mort.\n\nL’ange qui ouvrit les registres n’y\nVit aucune trace de sa grandeur.\n\nLa veuve, les orphelins étaient là,\nDieu s’est souvenu de leurs cris;\nPlus jamais de chagrins là au Ciel,\nDieu a essuyé toutes leurs larmes;\nJoueur d’argent, ivrogne étaient là,\nL’homme qui leur vendait la boisson\nEt ceux qui lui livrèrent la licence,\nTous ensemble sombrèrent en enfer.\n\nL’homme de bonnes moeurs vint\nau jugement mais\nSes farces hypocrites furent toutes\nvaines;\nLes hommes qui ont crucifié Jésus\nPassèrent tout comme ceux de bonnes\nmoeurs;\nL’âme qui a reporté le salut :\n«Un salut? Pas ce soir, après;\nJe manque le temps pour la religion!».\n\nMais ils eurent le temps pour mourir", 8));
		pg.add(new Page(119, "119. ", "J’AI TRAVERSE LE VOILE FENDU Ab", "J’ai traversé le voile fendu où la\ngloire ne manque point,\nAlléluia, alléluia;\nJ’ai traversé le voile fendu où la\ngloire ne manque point,\nParce que je vis dans la présence du Roi", 8));
		pg.add(new Page(120, "120. ", "IL Y A DE LA PLACE A LA FONTAINE Eb", "J’entendais mon doux Sauveur dire,\n'Y a une place à la fontaine pour toi,\nViens ôter les taches du péché,\nTu as une place à la fontaine.\n\nChoeur\nOui, il y a de la place,\nPlace, à la fontaine pour toi;\nOui, il y a de la place,\nTu as une place à la fontaine.\n\nJe Lui confessai mes péchés,\nJ’avais une place à la fontaine;\nMe livrant, mon coeur fut béni,\nTu as une place à la fontaine.\n\nPlongeant dans le flot cramoisi,\nJ’avais une place à la fontaine;\nPar la foi, je suis sanctifié,\nTu as une place à la fontaine.\n\nJ’ai trouvé le flot cramoisi,\nJ’avais une place à la fontaine;\nSon sang m’a rendu blanc\ncomme neige,\nTu as une place à la fontaine.\n\nIl ôta mon péché inné,\nJ’avais une place à la fontaine;\nEt maintenant Il garde mon coeur pur,\nTu as une place à la fontaine.\n\nJe Le loue tant que j’ai le souffle,\nJ’avais une place à la fontaine;\nIl m’a sauvé de l’affreuse mort,\nTu as une place à la fontaine.\n\nSon sang fut versé une bonne fois,\nJ’avais une place à la fontaine;\nNe rejette pas l’appel de grâce,\nTu as une place à la fontaine.\n\nChanter avec les saints au Ciel,\nJ’avais une place à la fontaine;\nLouer Son amour rédempteur,\nTu as une place à la fontaine", 8));
		pg.add(new Page(121, "121. ", "VIENS, ALLONS Ab", "Viens, allons à la Maison de mon Père,\nMaison de mon Père, Maison de\nmon Père.\n\nViens, allons à la Maison de mon Père,\nOù ’y a paix, paix, paix.\n\nJésus sera dans la Maison du Père,\nMaison de mon Père, Maison de mon\nPère.\n\nJésus sera dans la Maison du Père\nOù ’y a paix, paix, paix.\n\nLà, dans la Maison du Père, point de\npeine,\nMaison de mon Père, Maison de mon\nPère.\n\nLà, dans la Maison du Père, point de\npeines ,\n' Y aura joie, vraie joie", 8));
		pg.add(new Page(122, "122. ", "JUSTE UN AUTRE TOUCHER, SEIGNEUR Eb", "Juste un autre toucher, Seigneur,\nQui m’aide en temps de dures épreuves;\nBien que la nuit soit sombre,\nTu envoies un rayon,\nQuand j’obtiens un autre toucher de Toi", 8));
		pg.add(new Page(123, "123. ", "LA CITE BLANCHE DE PERLES Eb", "Il y a une cité sainte et très belle\nDont Dieu est Constructeur et Roi.\n\nJean l’avait vue descendre du Ciel\nEtant en exil à Patmos;\nSon massif et haut mur est en jaspe,\nLa cité elle-même est d’or pur;\nSi ma frêle tente ici est détruite,\nMes yeux contempleront sa gloire.\n\nChoeur\nDans cette cité brillante et blanche\nde perles,\nJ’ai un palais, une harpe et une couronne;\nMaintenant je veille, j’attends et\nje soupire\nAprès cette ville que Jean vit descendre.\n\nCette cité n’admet point de péché,\nNi rien de vil ou de souillant;\nNi douleur, ni maladie n’y entre,\nNi crêpe noir aux poignées de porte;\nChagrins, soucis terrestres oubliés,\nPlus de tentateur qui ennuie;\nPlus de paroles d’adieu prononcées,\nIl n’y a rien qui blesse ou détruit.\n\nN’y a point de chagrins dans\ncette cité,\nNi de larmes qui embuent les yeux,\nIl n’y a point de déception au Ciel,\nNi de convoitises ni de luttes;\nTous les saints sont pleinement\nsanctifiés,\nIls y vivent en bonne harmonie;\nMon coeur est tourné vers cette cité,\nSes bénédictions seront miennes.\n\nMes bien-aimés se rassemblent\nlà-bas,\nMes amis aussi s’en vont là;\nEt bientôt je me joindrai à eux,\nPour vivre dans un jour éternel;\nMaintenant en sûreté avec Jésus,\nDans la gloire après épreuves,\nguerres;\nIls ont vaincu péché et Satan,\nEnfin, ils sont dans cette belle ville", 8));
		pg.add(new Page(124, "124. ", "MARCHER PLUS PRES DE TOI. C", "Je suis faible, Tu es fort,\nJésus, garde-moi du mal;\nJe serai satisfait, tous les jours\nComme je marche, garde moi près\nde Toi.\n\nChoeur\nMarcher toujours avec Toi\nJésus exauce ma prière;\nMarcher toujours près de Toi,\nLaisse qu'il en soit ainsi cher\nSeigneur.\n\nDans ce monde de peines et\npièges,\nEn tombant qui me secourt?\nQui m'aide à porter mon fardeau?\nSeulement Toi, cher Seigneur,\nseulement Toi.\n\nQuand ma faible vie expire\nEt mon temps ne sera plus;\nGuide-moi en sécurité\nVers le rivage de Ton Royaume", 8));
		pg.add(new Page(125, "125. ", "LE MESSAGE DE SA VENUE C", "Nous attendons Sa venue sur\nles nuées du Ciel,\nRevenant sur terre pour enlever\nles Siens;\nPuissions-nous alors être prêts\nlors du cri de minuit\nPour régner avec Christ sur Son trône.\n\nChoeur\nAnnonçons avec joie le Message\nde Son apparition,\nAnnonçons à tous qu’Il vient\nbientôt dans la gloire;\nRéveillez-vous saints du Seigneur,\npourquoi dormir, la fin vient,\nSoyez donc prêts pour l’appel final.\n\nSoupirant après la gloire réservée\naux fidèles\nQui vaincront et remporteront\ntout combat;\nAvancez toujours bravement, vie\néternelle est le prix,\nPour qui l’emportent sur le péché.\n\nNous prions pour la venue du cher\nSauveur béni\nQui a promis la vie à qui croit Sa grâce;\nLe Message étant donné, Sa venue\nest imminente,\nNous verrons le Seigneur face à face.\n\nNous voyons apparaître les signes\nde Sa venue,\nRegardez, les feuilles du figuier\nreverdissent;\nL’Evangile de Son Royaume est\nallé à chaque nation,\nOn peut voir que nous sommes à la fin", 8));
		pg.add(new Page(126, "126. ", "LES BREBIS DE SON PRE F", "Les brebis de Son pré sont ensemble\nPour entendre le Berger parler,\nSa voix semblable au son des\neaux calmes\nMurmurait dans des vases d’argile.\n\nC’est la voix qui a créé toutes choses,\nElle a mis les étoiles en ordre,\nDit des paroles de vie, de sagesse,\nParmi Son peuple aujourd’hui.\n\nPar les prophètes, par le sang acquis,\nPurifiés, soumis et remplis,\nPlacés dans le Corps pour le service,\nComme la Tête du Corps l’a voulu", 8));
		pg.add(new Page(127, "127. ", "ES-TU LAVE DANS LE SANG? Ab", "As-tu rencontré Jésus qui purifie?\nEs-tu lavé dans le sang de l’Agneau?\nAs-tu pleinement confiance en Sa grâce\nmaintenant ?\nEs-tu lavé dans le sang de l’Agneau?\n\nChoeur\nEs-tu lavé dans le sang,\nDe l’Agneau qui purifie les âmes?\nTes habits sont-ils purs, aussi\nblancs que neige?\nEs-tu lavé dans le sang de l’Agneau?\nMarches-tu chaque jour à côté du\nSauveur?\nEs-tu lavé dans le sang de l’Agneau?\nDemeures-tu toujours dans le Crucifié?\nEs-tu lavé dans le sang de l’Agneau?\nQuand l’Epoux viendra, ta robe\nsera-t-elle blanche?\nPure et blanche dans le Sang de\nl’Agneau?\nTon âme sera-t-elle prête pour le\nbeau palais,\nEs-tu lavé dans le sang de l’Agneau?\nDébarrasse-toi de ces habits de péché,\nEt sois lavé dans le sang de l’Agneau;\nIl y a une fontaine qui coule pour l’âme\nimpure;\nOh! sois lavé dans le sang de l’Agneau !", 8));
		pg.add(new Page(128, "128. ", "JESUS M’AIME Eb", "Jésus m’aime ! je le sais,\nCar la Bible me le dit;\nLes enfants Lui appartiennent,\nIls sont faibles, Lui est fort.\n\nChoeur\nOui, Jésus m’aime,\nOui, Jésus m’aime,\nOui, Jésus m’aime,\nLa Bible me le dit.\n\nJésus m’aime ! Il mourut\nPour ouvrir les portes du Ciel;\nIl ôtera mon péché,\nFera entrer Son enfant.\n\nJésus m’aime, m’aime toujours!\nQue je sois malade et faible;\nDe Son brillant trône au Ciel,\nIl vient pour veiller sur moi", 8));
		pg.add(new Page(129, "129. ", "BAPTISE DANS LE CORPS G", "As-tu été baptisé dans le Corps?\nBaptisé du Saint-Esprit;\nIl n’y a qu’un seul moyen pour y entrer,\nComme ils le firent à la Pentecôte.\n\nChoeur\nEs-tu dans l’Eglise triomphante\nEt dans l’Epouse du Sauveur ?\nO viens et sois baptisé dans le Corps\nEt demeure là pour toujours.\n\nIl n’y a qu’une Eglise : l’Epouse\nou le Corps,\nEn Elle nous sommes baptisés;\nPar le seul et vrai Saint-Esprit promis;\nQuoique le monde nous méprise tous.\n\nChaque credo prétendait être le Corps,\nLe fil d’aplomb déclare faux\nLeurs rêves, car Dieu tient à manifester\nL’authentique Epouse du Fils.\n\nPlusieurs pensaient qu’ils étaient\ndans le Corps,\nJusque quand vint l’Esprit-Saint,\nQuand la Parole de Dieu leur fut\nouverte,\nIls entrèrent; ’y a encore des places.\n\nCeux qui sont morts avant que\nl’Esprit-Saint\nNe descende d’en haut sur nous,\nPeuvent par la foi, avec les Saints d’antan,\nSe lever pour Le voir au Ciel.\n\nLorsque l’Epoux viendra, seras-tu prêt,\nTa lampe remplie, allumée?\nTu seras compté parmi les vierges\nfolles,\nSi tu ne marches dans la lumière", 8));
		pg.add(new Page(130, "130. ", "C’EST COMME LE CIEL POUR MOI F", "Nous trouvons bien des gens qui\nne peuvent comprendre\nPourquoi nous sommes si\nheureux, libres;\nNous sommes passés du Jourdain\nau beau Canaan,\nCeci est comme le Ciel pour moi.\n\nChoeur\nCeci est comme le Ciel pour moi,\n(Gloire à Dieu!)\nOh! oui, c’est comme le Ciel pour moi!\nJe suis passé du Jourdain au beau\nCanaan;\nCeci est comme le Ciel pour moi.\n\nOh! quand je suis heureux,\nje chante et je crie!\nSatan ne le croit pas, je sais;\nMais je suis rempli de l’Esprit,\npoint de doutes,\nEt c’est bien cela mon problème", 8));
		pg.add(new Page(131, "131. ", "QUE DONNERAS-TU EN ECHANGE? G", "Frère toi qui, ce jour, es loin du Sauveur,\nRisquant ton âme pour les choses\nqui périssent,\nOh! si aujourd’hui Dieu la rappelait,\nQue donneras-tu en échange de\nton âme?\n\nChoeur\nQue donneras-tu? Que donneras-tu?\nQue donneras-tu en échange de\nton âme?\nOh! si aujourd’hui Dieu la rappelait,\nQue donneras-tu en échange de\nton âme?\nVeux-tu prêter l’oreille, la grâce\nt’appelle?\nLe Sauveur doit-Il toujours supplier?\nNe risque pas ton âme, elle est\ntrès précieuse;\nQue donneras-tu en échange de\nton âme?\nTon âme vaut plus que toutes les\npierres précieuses,\nElle vaut plus qu’argent et or de\nla terre;\nDieu créateur lui a donné\nnaissance!\nQue donneras-tu en échange de\nton âme?\nQuand tu te tiendras bientôt\nà la barre\nEt que tu seras pesé là au Ciel,\nSi la mort était ta sentence finale,\nQue donneras-tu en échange de\nton âme?\n132 UN MERVEILLEUX TEMPS Bb\nUn merveilleux temps est juste devant,\nLe Seigneur que nous aimons,\nDonnera accès à la terre de gloire,\nRévélant Son trône de gloire.\n\nChoeur\nUn merveilleux temps pour toi,\nUn merveilleux temps pour moi;\nSi nous sommes prêts à rencontrer\nJésus - Roi,\nCe sera un merveilleux temps.\n\nUn merveilleux temps est juste devant,\nNos luttes, épreuves sont passées;\nLe voyage du désert est fini,\nEnfin, au Ciel, sains et saufs.\n\nUn merveilleux temps est juste devant,\nLes gémissements cesseront;\nEt tous ceux qui sont esclaves\nmaintenant,\nLe Seigneur les rendra libres", 8));
		pg.add(new Page(133, "133. ", "QUAND IL TENDIT SA MAIN VERS MOI C", "Jadis mon âme était loin du\nchemin du Ciel,\nElle était toute vile et misérable;\nMais paix, joie et amour, mon\nSauveur m’a donné,\nQuand Il tendit Sa main vers moi,\nvers moi.\n\nChoeur\nQuand Il tendit Sa main vers moi,\nQuand Il tendit Sa main vers moi;\nJ’étais perdu, égaré, sans Dieu ni\nSon Fils,\nQuand Il tendit Sa main vers moi,\nvers moi.\n\nJ’étais presque désespéré quand\nIl vint vers moi,\nMontrant que je pouvais être libre;\nPuis Il me releva et me donna\npleine gloire,\nQuand Il tendit Sa main vers moi,\nvers moi.\n\nComme mon coeur se réjouit\ndepuis qu’Il est mon choix,\nEn Lui je m’abrite contre les\ntempêtes;\nJe m’appuie sur Son bras, Il me\ngarde de tout mal,\nDepuis qu’Il a tendu Sa main vers moi.\n\nDepuis que j’ai Sa paix, les joies\ndu Ciel ne cessent;\nSeigneur, je Te confie toute ma vie;\nGuide mes pas, tiens ma main,\nque je reste avec Toi,\nPuisque Tu as tendu Ta main\nvers moi", 8));
		pg.add(new Page(134, "134. ", "RAMENE-LES Ab", "J'écoute la voix du berger\nVenant du désert sombre et triste\nAppelant les brebis perdues,\nEgarées de la bergerie.\n\nChoeur\nRamène-les, ramène-les,\nEt sors-les de la vie du péché;\nRamène-les, ramène-les,\nAmène les perdues à Jésus.\n\nQui aidera ce bon Berger\nA retrouver tous les perdus\nEt les ramener au troupeau\nOù ils seront gardés du froid.\n\nDu désert, écoute leurs cris,\nVenant des montagnes élevées,\nEcoute! le Maître te dit :\n«Va, partout, trouver mes brebis»", 8));
		pg.add(new Page(135, "135. ", "QUE TU ES GRAND ! Bb", "Seigneur mon Dieu! Quand dans\nmon étonnement,\nJe considère les mondes faits par\nTes mains;\nJe vois les étoiles, j’entends les\ntonnerres,\nTa puissance déployée dans l’univers.\n\nChoeur\nMon âme chante à Toi, Dieu mon\nSauveur :\nQue Tu es grand, que Tu es grand!\nMon âme chante à Toi, Dieu mon\nSauveur :\nQue Tu es grand, que Tu es grand!\nQuand dans les bois, dans la forêt\nje marche,\nEt que j’entends les doux chants\ndes oiseaux;\nQuand je regarde du haut de la\nmontagne,\nJ’entends le ruisseau, et je sens\nla brise.\n\nQuand je pense que Dieu n' épargna\npas Son Fils,\nIl L’envoya mourir, oh! quel mystère !\nSur la croix, joyeux, Il porta\nmon fardeau,\nSaigna, mourut pour ôter mon péché.\n\nQuand Christ viendra sous vives\nacclamations,\nIl me prendra, joyeux sera mon coeur;\nJe vais m'incliner dans l'humble\nadoration,\nEt proclamer : Mon Dieu que\nTu es Grand!", 8));
		pg.add(new Page(136, "136. ", "L’ANCIENNE PUISSANCE F", "Tous, dans une chambre haute,\nEtaient d’un commun accord,\nQuand le Saint-Esprit descendit,\nComme promis par le Seigneur.\n\nChoeur\nSeigneur envoie la puissance,\nEnvoie-la maintenant même,\nSeigneur envoie la puissance\nEt baptise tout le monde.\n\nCette puissance vint du Ciel avec\nLe son d'un vent impétueux;\nEt des langues de feu vinrent sur eux\nComme promis par le Seigneur.\n\nCette «ancienne» puissance fut\ndonnée\nA nos pères qui furent fidèles;\nCela fut promis aux croyants,\nNous pouvons aussi l’avoir", 8));
		pg.add(new Page(137, "137. ", "IL Y A FORCE DANS LE SANG Bb", "Veux-tu être affranchi du péché?\nLa force est dans le sang, force dans\nle sang;\nVeux-tu avoir la victoire sur le mal?\nLa force merveilleuse est dans le sang.\n\nChoeur\nIl y a force, force, merveilleuse force\nDans le sang de l’Agneau,\nIl y a force, force, merveilleuse force,\nDans le sang précieux de l’Agneau.\n\nVeux-tu être sans orgueil, sans passions?\nLa force est dans le sang, force dans\nle sang;\nPour être pur, vient au flot du Calvaire,\nLa force merveilleuse est dans le sang.\n\nVeux-tu être blanc, plus blanc que\nla neige?\nLa force est dans le sang, force dans\nle sang;\nLes souillures du péché y sont lavées,\nLa force merveilleuse est dans le sang.\n\nVeux-tu servir Jésus-Christ, ton Roi?\nLa force est dans le sang, force\ndans le sang;\nVeux-tu vivre et chanter Ses louanges?\nLa force merveilleuse est dans le sang", 8));
		pg.add(new Page(138, "138. ", "LE ROC SOLIDE G", "Mon espoir ne se fonde que\nSur justice et sang de Jésus;\nSans foi en un beau fondement\nJe ne m’appuie que sur Son Nom.\n\nChoeur\nSur Christ, Roc Solide, je me tiens;\nLe reste n’est que sable mouvant,\nLe reste n’est que sable mouvant.\n\nQue les ténèbres voilent Sa face,\nJe compte sur Son immuable grâce ;\nDans chaque orage et chaque tempête,\nMon ancre tient derrière le voile.\n\nSes serment, alliance et sang,\nMe gardent de flots submergeants;\nQuand tout cède autour de mon âme,\nIl est mon espoir, mon appui.\n\nQuand Il vient avec la trompette,\nPuissé-je alors être en Lui,\nRevêtu de Sa seule justice\nPour comparaître parfait au trône", 8));
		pg.add(new Page(139, "139. ", "IL DEMEURE Ab", "Je me réjouis nuit et jour,\nComme je marche en pèlerin,\nCar dans toute ma vie je vois\nla main de Dieu,\nEt la raison de ma joie,\nLe secret de tout cela :\nLe Consolateur est avec moi.\n\nChoeur\nIl demeure,\nIl demeure,\nAlléluia, Il est avec moi!\nJe me réjouis nuit et jour\nMarchant sur l’étroit chemin :\nLe Consolateur est avec moi.\n\nJe vivais dans le péché,\nN'ayant point de paix en moi,\nJusqu’au jour où j’ouïs comment\nJésus mourut;\nPuis je tombai à Ses pieds,\nEt une douce paix me remplit,\nLe Consolateur est avec moi !\nIl est avec moi partout\nEt connaît tous mes soucis,\nJe suis heureux et libre comme\nun oiseau;\nLe Saint-Esprit me contrôle,\nJésus satisfait mon âme :\nLe Consolateur est avec moi !\nPlus de désir pour le monde,\nSes plaisirs ont pris des ailes;\nIl y a longtemps je les ai abandonnées;\nToute ma nuit changée en jour,\nEt mes fardeaux enlevés;\nLe Consolateur est avec moi !", 8));
		pg.add(new Page(140, "140. ", "RACHETE Ab", "Racheté, combien j’aime le proclamer!\nRacheté par le sang de l’Agneau;\nEt racheté par Sa grâce infinie,\nJe suis Son enfant pour toujours.\n\nChoeur\nRacheté, racheté,\nRacheté par le sang de l’Agneau;\nRacheté, racheté,\nJe suis Son enfant pour toujours.\n\nRacheté et si heureux en Jésus,\nNulle langue ne peut décrire ma joie;\nJe sais, la Lumière de Sa présence\nEst continuellement avec moi.\n\nJe pense à mon Rédempteur béni,\nJe pense à Lui le long du jour;\nJe chante car je ne peux me taire;\nMon chant a pour thème Son amour.\n\nJe sais, je verrai dans Sa beauté,\nLe Roi dont la loi me réjouit;\nAvec amour Il protège mes pas\nEt m’inspire des chants dans la nuit", 8));
		pg.add(new Page(141, "141. ", "RIEN QUE LE SANG DE JESUS G", "Qu’est-ce qui peut laver mon péché ?\nRien que le sang de Jésus;\nQu’est ce qui peut me parfaire encore?\nRien que le sang de Jésus.\n\nChoeur\nOh! Précieux est le flot\nQui me rend plus blanc que neige !\nJe ne connais d’autre source,\nRien que le sang de Jésus.\n\nPour ma pureté je ne vois\nRien que le sang de Jésus;\nLa plaidoirie pour mon pardon,\nRien que le sang de Jésus.\n\nRien ne peut expier le péché,\nRien que le sang de Jésus;\nIl n'y a rien de bon que j’ai fait,\nRien que le sang de Jésus.\n\nC'est mon espérance et ma paix,\nRien que le sang de Jésus;\nC'est aussi toute ma justice,\nRien que le sang de Jésus.\n\nMaintenant par ceci je vaincrai,\nRien que le sang de Jésus;\nMaintenant j'atteindrai ma maison,\nRien que le sang de Jésus.\n\nGloire! Gloire! ainsi je chante,\nRien que le sang de Jésus;\nToute ma louange j'apporte,\nRien que le sang de Jésus", 8));
		pg.add(new Page(142, "142. ", "JESUS LA LUMIERE DU MONDE Ab", "Saints de lumière, proclamez:\nJésus, la lumière du monde;\nVie et grâce en Son Nom,\nJésus, la lumière du monde.\n\nChoeur\nOui, nous marcherons, dans\nla lumière,\nLà où la miséricorde est versée;\nBrille autour de nous le jour et la nuit,\nJésus, la lumière du monde.\n\nEcoute l’appel du Sauveur,\nJésus, la lumière du monde;\nAmène l’Evangile à tous,\nJésus, la lumière du monde.\n\nPourquoi ne pas Le chercher?\nJésus, la lumière du monde;\nMarche avec la Vérité,\nJésus, la lumière du monde.\n\nViens, confesse-Le comme ton Roi,\nJésus, la lumière du monde;\nLes cloches du Ciel sonneront,\nJésus, la lumière du monde.\n\n143.\n\nQUAND NOUS VERRONS JESUS Eb\nSouvent l’épreuve est dure et le\njour parait long;\nNous sommes tentés de nous\nplaindre, de perdre espoir,\nMais bientôt apparaît Christ pour\nprendre l’Epouse,\nAu jour éternel de Dieu, il n’y aura plus\nde larmes.\n\nChoeur\nQuand nous verrons Jésus,\nc'est le prix de nos peines;\nLes épreuves de la vie paraîtront moindres;\nUn coup d’oeil sur Sa face ôtera\ntout chagrin,\nPoursuivons donc la course jusqu’à\nvoir Christ.\n\nParfois, le ciel est sombre, sans\nrayon de lumière;\nNous sommes ballottés, sans\nsecours humain en vue;\nMais il y a Un au Ciel qui connaît\nnos soucis,\nJésus règle ton problème, va vers\nLui en prière.\n\nBientôt cette vie et toutes les\ntempêtes finiront,\nNous passerons sains et saufs\nla frontière vers la gloire;\nLe tentateur banni, nous\nlaisserons nos fardeaux,\nNous partagerons : couronne, maison,\nharpe, joies du Ciel", 8));
		pg.add(new Page(144, "144. ", "PLUS BLANC QUE LA NEIGE Eb", "Bénie soit la fontaine de sang,\nRévélée au monde des pécheurs;\nBéni soit le cher Fils de Dieu\nQui guérit par Ses meurtrissures.\n\nJ’ai erré loin de Sa bergerie,\nJ'ai causé de la peine à mon coeur,\nLave-moi dans le sang de l’Agneau\nEt je serai plus blanc que la neige.\n\nChoeur\nPlus blanc que la neige!\nPlus blanc que la neige!\nLave-moi dans le sang de l’Agneau,\nEt je serai plus blanc que la neige.\n\nOh! Père j’ai erré loin de Toi,\nSouvent mon coeur s’est égaré;\nMes péchés sont rouge cramoisi,\nL’eau ne peut pas les nettoyer.\n\nJésus, je viens à Ta fontaine,\nNe comptant que sur Ta promesse;\nLave-moi par Ton divin lavage\nEt je serai plus blanc que la neige", 8));
		pg.add(new Page(145, "145. ", "ACCLAMEZ TOUS LA PUISSANCE DU NOM DE JESUS G", "Acclamez le Nom de Jésus!\nQue les anges se prosternent;\nApportez le diadème royal,\nCouronnez-Le Seigneur;\nApportez le diadème royal,\nCouronnez-Le Seigneur.\n\nSemence d’Israël, race élue,\nRachetés de la chute,\nAcclamez-Le, Sa grâce vous sauve,\nCouronnez-Le Seigneur;\nAcclamez-Le, Sa grâce, vous sauve\nCouronnez-Le Seigneur.\n\nPécheurs dont l’amour n’oublie point\nAmertume et dégout,\nPosez vos trophées à Ses pieds,\nCouronnez-Le Seigneur;\nPosez vos trophées à Ses pieds,\nCouronnez-Le Seigneur.\n\nQue toute famille, que toute tribu,\nSur la face de la terre,\nLui attribue toute majesté,\nEt Le couronne Seigneur;\nLui attribue toute majesté,\nEt Le couronne Seigneur.\n\nQu’avec la foule sacrée là-bas\nNous tombions à Ses pieds\nNous chantions le chant éternel,\nLe couronnant Seigneur;\nNous chantions le chant éternel,\nLe couronnant Seigneur", 8));
		pg.add(new Page(146, "146. ", "A LA CROIX Eb", "Hélas! Mon Sauveur saigna-t-Il,\nMon Souverain mourut-Il?\nDut-Il livrer Sa tête sacrée\nPour un ver tel que moi?\n\nChoeur\nA la croix, à la croix où j’ai vu la Lumière\nEt le fardeau de mon coeur fut ôté,\nLà, par la foi, j’ai recouvré la vue\nEt maintenant j’ai la joie tous les jours!\nFut-ce pour les crimes que j'ai commis\nQu’Il gémit sur la croix?\nEtonnante pitié, grâce inouïe\nEt amour infini !\nLe soleil même dut s’obscurcir\nEt dut cacher sa gloire,\nQuand Christ, le Créateur, mourait\nPour le péché de l’homme!\nMais mon chagrin ne peut payer\nMa dette d’amour pour Lui;\nMe voici, Seigneur, je me donne,\nC’est tout ce que je peux faire !", 8));
		pg.add(new Page(147, "147. ", "LE GRAND JE SUIS Ab", "JE SUIS qui a parlé à Moïse dans\nle buisson ardent,\nJE SUIS, le Dieu d’Abraham,\nl’Etoile brillante du matin.\n\nJE SUIS, la Rose de Sharon dès\nle début d’où je vins;\nJE SUIS la création toute entière\net Jésus est Mon Nom.\n\nChoeur\nOh! qui dites-vous que Je suis\net d’où dites-vous que Je viens?\nConnaissez-vous le Père, pouvez-vous\ndire Son Nom?\nEn Jésus demeure la plénitude de\nDieu, voyez-vous?\nJésus est le grand JE SUIS et\nle Seigneur des seigneurs.\n\nJE SUIS fut avant Abraham :\n«Il s’est réjoui de Mon jour.\n\n»\nQuand Jésus dit ces précieux\nmots, vite ils Le lapidèrent.\n\n«Pourquoi Me lapidez-vous?» dit-Il,\nsur un saint doux ton.\n\n«Car Tu dis être le grand JE SUIS,\nToi qui n’es qu’un simple homme».\n\nC’était le jour de la Pentecôte,\noh! comme le feu descendit!\nLe Saint-Esprit descendit et Il\nremplit chacun d’eux.\n\nPuis Pierre dit à la foule :\n«Repentez-vous de vos péchés.\n\n»\nPrès de trois milles âmes furent\nensevelies au Nom de Jésus", 8));
		pg.add(new Page(148, "148. ", "PRESQUE PERSUADE G", "«Presque persuadé» de croire\nmaintenant;\n«Presque persuadé,»\nd’accepter Christ;\nUne âme dit maintenant :\n«Va ton chemin, Esprit,\nUn jour plus convenable je T’appellerai.\n\n»\n«Presque persuadé,» viens,\naujourd'hui;\n«Presque persuadé,» ne refuse\npas;\nJésus t’invite ici, les anges\nattendent tout près;\nDes coeurs si précieux prient :\n«O errant, viens.\n\n»\n«Presque persuadé,» moisson finie!\n«Presque persuadé,» enfin, la ruine!\n«Presque» ne profite pas; «Presque»\nc’est échouer!\nQuels tristes pleurs amers :\n«Presque : perdu.\n\n»", 8));
		pg.add(new Page(149, "149. ", "POINT DE DECEPTION Eb", "Il n’y a point de déception au Ciel,\nNi fatigue, ni chagrin, ni peine;\nNi non plus de coeurs saignants\nbrisés,\nOu de chants au choeur en mineur.\n\nLes nuages de l’horizon terrestre\nN’apparaîtront jamais au Ciel\nCar tout sera bonheur, allégresse\nSans sanglot, sans soupir, non plus.\n\nChoeur\nJe vais à cette magnifique cité\nBâtie par mon Dieu pour les Siens;\nLà, les rachetés de tous les âges\nChantent : «Gloire!» tout autour du\ntrône blanc;\nParfois, j’ai la nostalgie du Ciel\nEt des gloires que j’y contemplerai;\nQuelle joie ce sera quand je vois\nmon Sauveur,\nDans cette magnifique cité en or!\nNous n’y payerons point des loyers,\nIl n’y aura jamais des taxes dues;\nNos habits ne s’useront jamais,\nIls seront toujours nets et neufs.\n\nLà, nous n’aurons jamais faim, ni soif,\nNi langueur dans la pauvreté,\nCar Ses enfants partageront\nToutes les riches bienveillances\ndu Ciel.\n\nPlus de crêpes noirs aux poignées\ndes portes,\nNi de cortèges funèbres au Ciel;\nPlus de tombes sur les collines\nde gloire,\nCar là nous ne mourrons jamais.\n\nLà, les vieux seront jeunes pour toujours,\nEtant changés en un instant,\nImmortels, nous serons tels qu’Il est,\nBrillant plus qu’étoiles et soleil", 8));
		pg.add(new Page(150, "150. ", "QUEL BEAU JOUR G", "Oh! quel beau jour, jour de mon choix\nSur Toi, mon Sauveur et mon Dieu!\nQue mon coeur rayonne de joie,\nExprime partout son ravissement.\n\nChoeur\nQuel beau jour, quel beau jour,\nQuand Jésus ôta mes péchés!\nIl m’apprit à veiller, prier\nEt vivre chaque jour dans la joie.\n\nQuel beau jour, quel beau jour,\nQuand Jésus ôta mes péchés.\n\nQuel engagement qui scelle\nmes voeux\nA Lui qui mérite mon amour!\nPuissent les chants remplir\nSa maison,\nPendant que je vais à l’autel.\n\nL'alliance est faite avec Jésus!\nIl est à moi, je suis à Lui;\nIl me conduit et je Le suis,\nBrûlant de confesser Sa voix", 8));
		pg.add(new Page(151, "151. ", "L’UN D’ENTRE EUX Ab", "Il y a presque partout des peuples\nDont les coeurs enflammés\nDu feu tombé à la Pentecôte,\nqui les a rendus purs\nEt il brûle maintenant dans mon coeur,\nA son Nom toute la gloire!\nJe suis heureux de dire: je suis\nl'un d'entre eux.\n\nChoeur\nL’un d’entre eux, l’un d’entre eux,\nJe suis heureux de dire : Je suis\nl’un d’entre eux;\nL’un d’entre eux, l’un d’entre eux,\nJe suis heureux de dire : je suis\nl’un d’entre eux.\n\nBien que ces peuples, sans\ninstruiction\nNi renommée du monde,\nBaptisés au Nom de Jésus,\nIls reçurent la Pentecôte;\nEt ils parlent maintenant de\nSon immuable puissance,\nJe suis heureux de dire : je suis\nl'un d'entre eux.\n\nRassemblés dans la chambre\nhaute,\nIls priaient tous en Son Nom,\nIls étaient tous baptisés\nDu Saint-Esprit pour le service;\nCe qu’Il fit pour eux en ce temps-là,\nIl peut le faire pour toi,\nJe suis heureux de dire : je suis\nl’un d’entre eux.\n\nViens, mon frère, chercher cette\nbénédiction\nQui te rendra pur,\nFera sonner les cloches de joie,\nEnflammera ton âme,\nEt elle brûle maintenant dans mon\ncoeur,\nA Son Nom toute la gloire.\n\nJe suis heureux de dire : je suis\nl’un d’entre eux", 8));
		pg.add(new Page(152, "152. ", "JE SERAI QUELQUE PART POUR ENTENDRE Ab", "Lorsque le Sauveur m’appellera,\nJ’entendrai et je répondrai;\nLorsqu'Il appelle, je répondrai,\nJe serai quelque part pour entendre\nmon nom.\n\nChoeur\nJe serai quelque part,\nJe serai quelque part,\nQuelque part-là pour entendre mon nom;\nJe serai quelque part,\nJe serai quelque part,\nQuelque part-là pour entendre\nmon nom.\n\nSi mon coeur est droit quand\nIl m’appelle,\nSi mon coeur est droit j’entendrai;\nSi mon coeur est droit quand\nll m’appelle,\nJe serai quelque part pour entendre\nmon nom.\n\nSi ma robe est blanche quand\nIl m’appelle,\nSi ma robe est blanche\nj’entendrai;\nSi ma robe est blanche quand\nIl m’appelle,\nJe serai quelque part pour entendre\nmon nom", 8));
		pg.add(new Page(153, "153. ", "LA SEMAINE DE RETOUR A LA MAISON G", "Dans notre voyage ici bas\nnous avons peines et pertes;\nTantôt c’est une couronne d’épines\ntantôt c’est la lourde croix.\n\nTriste chemin vers le Calvaire, douleurs,\ntourments amers,\nMais ce qui est derrière ces portes\nde perles vaudra tout.\n\nChoeur\nQuand nous serons derrière\nces portes,\nNous apprendrons beaucoup,\nNous aurons une harpe en or\nDe mille cordes peut être,\nNous aurons des chants,\ncris et danses,\nL’Agneau séchera nos larmes;\nLes premiers dix mille ans seront\nNotre semaine de retour.\n\nL'obscurité tombe maintenant\net le temps est très proche\nOù notre Seigneur reviendra\ncomme un éclair du Ciel.\n\nDans l’attente et la souffrance,\nnous crierons gloire à Dieu,\nCar juste un coup d’oeil par ces\nportes de perles vaudra tout.\n\nLe précieux sang du Fils de Dieu\na sauvé, sanctifié,\nPour Son Nom, un peuple\nmerveilleux, appelé Epouse.\n\nBien que négligés, méprisés,\nun jour le Seigneur va\nConduire Ses élus derrière les portes,\nça vaudra tout", 8));
		pg.add(new Page(154, "154. ", "TEL QUE JE SUIS Eb", "Tel que je suis, sans rien à moi,\nSinon Ton sang versé pour moi,\nEt comme Tu m'invites à venir,\nAgneau de Dieu, je viens! je viens!\nTel que je suis, je n'attends pas\nQue j'ôte de mon âme une seule tache,\nTon sang lave chaque tache; à Toi,\nAgneau de Dieu, je viens! Je viens!\nTel que je suis, Tu me reçois,\nTu me pardonnes, soulages et laves,\nCar je crois à Ta promesse, ô\nAgneau de Dieu, je viens! Je viens!\nTel que je suis, Ton grand amour\nA renversé chaque barrière;\nMaintenant pour être à Toi, Toi seul,\nAgneau de Dieu, je viens! Je viens!", 8));
		pg.add(new Page(155, "155. ", "PAIX DANS LA VALLEE Eb", "Eh bien! fatigué mais je dois\nsuivre mon chemin\nJusqu’à ce que le Seigneur\nvienne me prendre, oh! oui;\nLe matin est brillant, l’Agneau est\nla Lumière;\nEt la nuit est aussi claire que\nle jour, oh! oui.\n\nChoeur\n’Y aura paix dans la vallée pour\nmoi, un jour,\n’Y aura paix dans la vallée pour\nmoi, Seigneur, je prie;\n’N’y aura ni tristesse, ni chagrin,\nni trouble à voir;\n’Y aura paix dans la vallée pour moi.\n\nLà, les fleurs s’épanouiront,\nle gazon sera vert;\nEt là, les cieux vont être clairs\net sereins, oh! oui;\nLe soleil brille toujours dans la\nvallée de rêves;\nEt là, il n’y aura jamais de nuages,\noh! oui.\n\nEh bien! l’ours sera doux et\nle loup apprivoisé;\nEt le lion couchera près de l’agneau,\noh! oui;\nUn petit enfant va conduire\nla bête sauvage;\nDe la créature que je suis, je serai\nchangé!", 8));
		pg.add(new Page(156, "156. ", "GRAND EST LE SEIGNEUR ! Bb", "Il y a un nom que j’aime entendre, c’est\ncomme un choeur à mon oreille,\nC’est le Nom du Seigneur Jésus Christ;\nIl est venu du Père Céleste, Il est\nmort sur la croix juste pour nous\nmontrer Son amour;\nJésus, oui, Jésus est Son Nom.\n\nChoeur\nGrand est le Seigneur! Qu’Il est grand!\nGrand est le Père et grand est le Fils,\nGrand est le Saint Esprit et ces\ntrois sont un;\nJésus, oui, Jésus est Son Nom.\n\nSauveur, Il a donné Sa vie pour\nnous libérer du péché;\nC’est le Nom du Seigneur Jésus Christ;\nLe Conseiller, l’Homme de Galilée,\ncalma les eaux en furie et marcha\nsur la mer;\nJésus, oui, Jésus est Son Nom", 8));
		pg.add(new Page(157, "157. ", "MON ANCRE EST EN JESUS Bb", "Sur l’océan de la vie où vagues\npuissantes roulent,\nMon espoir est en Jésus, l’ancre\nbéni de l'âme;\nQuand dures épreuves\nm’assaillent comme se regroupe\nl’orage,\nComptant sur Sa grâce, j’ai plus\nconfiance en Lui.\n\nChoeur\nMon ancre est en Jésus, tempêtes\nde vie je brave,\nMon ancre est en Jésus, je ne\ncrains ni vents ni vagues;\nMon ancre est en Jésus, parce\nqu’Il peut sauver,\nMon ancre est dans le Rocher des âges.\n\nIl me protège du mal, me donne\nla paix bénie,\nSa voix calma les eaux et\nfit cesser leur tumulte.\n\nMon Guide, Libérateur, je confie\ntout à Lui,\nQuand j’ai besoin de Lui, Il est avec moi.\n\nC’est mon Ami, mon Sauveur,\nje suis ancré en Lui,\nIl chasse au loin mes chagrins,\nme garde de la ruine;\nMa foi regarde au-delà des vagues\nde la vie,\nLà, je vois un abri préparé pour moi", 8));
		pg.add(new Page(158, "158. ", "LE SOLEIL COUCHE Eb", "Le soleil couché, merveilleux matin ,\nAvec le Sauveur commence le Ciel.\n\nPlus de peines terrestres, ô glorieuse\naurore;\nLe soleil couché, le jour s’en va.\n\nLe soleil couché, nuages ne sont plus,\nOrages ne menacent, peurs n’agacent\npoint.\n\nO jour de délices, ô jour éternel;\nLe soleil couché, joie éternelle.\n\nLe soleil couché, une main me guide\nVers Dieu le Père, Lui que j'adore;\nSa glorieuse présence, Ses paroles\nd’accueil\nSeront ma part sur le beau rivage.\n\nLe soleil couché, rencontre joyeuse\nAvec nos chers frères qui sont partis.\n\nDans ce beau pays on ne se sépare\nJamais quand le soleil est couché", 8));
		pg.add(new Page(159, "159. ", "UN ENFANT DU ROI F", "Mon Père est riche, en maisons\net terres,\nIl tient en Ses mains tous les trésors\ndu monde!\nDe rubis, de diamant, d'argent et d'or\nSes coffres sont pleins,\nIl a d'immenses richesses.\n\nChoeur\nJe suis enfant du Roi!\nUn enfant du Roi!\nPar Jésus mon Sauveur,\nJe suis enfant du Roi!\nLe Fils de mon Père, le Sauveur\ndes hommes,\nVécut sur la terre en plus pauvre\ndes hommes;\nMaintenant Il règne pour toujours au\nCiel,\nLà, bientôt, Il me donnera une\nmaison.\n\nJ’étais étranger proscrit sur la terre,\nPécheur par nature, étranger\nde naissance!\nMais je suis adopté et mon nom inscrit,\nHéritier d’une robe, d’un palais, d’une\ncouronne.\n\nUne tente, ou cabane pourquoi\nm’en soucier ?\nOn édifie pour moi un palais là-bas!\nBien qu' étant exilé, je chante encore:\nToute gloire à Dieu, je suis enfant\ndu Roi", 8));
		pg.add(new Page(160, "160. ", "TIENS L’IMMUABLE MAIN DE DIEU. G", "Le temps est plein de transitions,\nRien sur terre n'est immuable,\nEspère en des choses éternelles,\nTiens l’immuable main de Dieu!\n\nChoeur\nTiens l’immuable main de Dieu!\nTiens l’immuable main de Dieu!\nEspère en des choses éternelles,\nTiens l’immuable main de Dieu!\nCrois en Dieu qui ne t'abandonne,\nQuoiqu’apportent les années,\nSi les amis t’abandonnent,\nAttache-toi toujours à Lui!\nNe convoite pas les richesses vaines\nQui pourrissent rapidement,\nCherche les trésors célestes\nQui ne passeront jamais!\nQuand s’achèvera ton voyage,\nSi tu étais fidèle à Dieu,\nTon âme ravie dans la gloire,\nTrouvera une belle demeure!", 8));
		pg.add(new Page(161, "161. ", "LE JOUR DE LA REDEMPTION Ab", "Les nations se disloquent, Israël\nse réveille,\nLes signes que les prophètes prédirent;\nLes jours des gentils comptés,\nencombrés d’horreur;\nBientôt sera l’éternité.\n\nChoeur\nLe jour de la rédemption est proche,\nLes coeurs des hommes défaillent\nde peur;\nSois rempli de l’Esprit, ta lampe nette\net claire,\nRegarde! ta rédemption est proche.\n\nLe figuier bourgeonne, Jérusalem\nrestaure\nSa nation longtemps dévastée;\nSa dernière pluie tombe, elle appelle\naujourd’hui :\n«Reviens, ô toi, dispersée.\n\n»\nLes Cieux ébranlés, mais beaucoup\nse trompent;\nSur ce que Dieu fait dans le ciel,\nL’Eglise est la puissance qui secoue\ncette heure :\nLe jour de la rédemption est proche.\n\nLes faux prophètes mentent, ils nient\nla Vérité,\nQue Jésus Christ est notre Dieu;\nQue cette génération nie la révélation,\nNous suivons les pas des apôtres.\n\n162.\n\nCONFIE-TOI SEULEMENT EN LUI Ab\nViens, âme accablée des péchés,\nLa grâce est au Seigneur,\nIl te donnera le repos,\nEn croyant Sa Parole.\n\nChoeur\nConfie-toi seulement en Lui,\nConfie-toi maintenant :\nIl te sauvera, Il te sauvera,\nIl te sauve maintenant.\n\nJésus versa Son sang précieux\nPour te bénir richement :\nPlonge dans le flot cramoisi\nLequel rend blanc comme neige.\n\nJésus, Vérité et Chemin\nQui t’amène au repos;\nAinsi, crois en Lui sans tarder,\nTu seras bien béni.\n\nViens te joindre à cette sainte foule,\nAvance vers la gloire\nPour vivre au pays céleste\nOù joies immortelles coulent", 8));
		pg.add(new Page(163, "163. ", "UN JOUR ! C", "Un jour, quand le Ciel fut plein de Ses\nlouanges,\nUn jour, quand le péché était tout noir,\nAlors vint Jésus pour naître d’une vierge,\nVécut parmi les hommes, Lui, mon\nexemple!\n\nChoeur\nVivant, Il m’aima, mourant, me sauva;\nEnseveli, emporta mes péchés;\nRessuscitant, Il justifia pour toujours;\nUn jour, Il reviendra, quel glorieux jour!\nUn jour, on Le conduisit au mont\nCalvaire,\nOn Le cloua pour mourir sur le bois;\nAccablé des peines, méprisé, rejeté,\nIl prit nos péchés,Lui,mon Rédempteur!\nUn jour, on L’abandonna seul au Jardin,\nAprès souffrances, Il fut enseveli;\nLes anges descendirent pour veiller à\nSa tombe;\nMon Sauveur, Espoir du désespéré!\nUn jour, la tombe ne Le garda\nlongtemps,\nUn jour, la pierre roula loin de la porte;\nAlors Il ressuscita, vainquit la mort;\nMaintenant Il est monté, mon Seigneur!\nUn jour, les cieux brilleront de Sa gloire;\nLa trompette annoncera Sa venue;\nJour merveilleux ramenant mes bien-\naimés;\nGlorieux Sauveur, ce Jésus est à moi!", 8));
		pg.add(new Page(164, "164. ", "DESCENDS, DOUX CHARIOT F", "Je regardais, je vis, au delà\ndu Jourdain,\nVenant m’emmener à la maison;\nUne cohorte d’anges venant après moi,\nVenant m’emmener à la maison.\n\nChoeur\nDescends, doux chariot,\nVenant m’emmener à la maison;\nDescends, doux chariot,\nVenant m’emmener à la maison.\n\nSi tu entres là-bas, avant mon arrivée,\nVenant m’emmener à la maison;\nDis à tous mes amis que je viendrai\naussi,\nVenant m’emmener à la maison", 8));
		pg.add(new Page(165, "165. ", "QUAND SONNERONT LES CLOCHES F", "'Y a un pays sur l’autre rive,\nAppelé «terre de joie sans fin»;\nNous l’atteignons par décision de la foi,\nUn à un nous y entrerons,\nPour être avec les immortels;\nQuand sonneront les cloches d’or\npour toi, pour moi.\n\nChoeur\nN’entends-tu pas les cloches sonner?\nN’entends-tu pas les anges chanter?\nC’est le jubilé «gloire ! alléluia !»\nDans ce lointain pays de joie,\nPar delà la rivière brillante;\nQuand sonneront les cloches d’or\npour toi, pour moi.\n\nQuand notre bateau atteindra L'autre\nrivage de la mer,\nNi péchés, ni peines dans ce port de\ndemain;\nIl n’y aura que bénédictions,\nDouces caresses de notre Père,\nQuand sonneront les cloches d’or\npour toi, pour moi.\n\nQuand nos jours seront terminés,\nQuand, morts, nous dormirons en paix,\nSur l’ordre du Roi, l’Esprit est libéré;\nPlus jamais sujets à l’angoisse,\nNous atteindrons ce beau pays,\nQuand sonneront les cloches d’or\npour toi, pour moi", 8));
		pg.add(new Page(166, "166. ", "QUAND TOUS NOUS SERONS AU CIEL C", "Chantons le grand amour de Jésus,\nSa miséricorde, Sa grâce;\nDans les beaux et bénis palais,\nIl prépare pour nous une place.\n\nChoeur\nQuand tous nous serons au Ciel,\nOh! quel jour de réjouissances ce sera!\nQuand nous verrons Jésus,\nNous chanterons fort la victoire.\n\nDans notre pèlerinage,\nLes nuages couvrent le ciel;\nMais à la fin du voyage,\nPlus d’ombre ni de soupir.\n\nSoyons donc sincères et fidèles,\nConfiant et servant chaque jour;\nJuste L’entrevoir dans la gloire,\nRécompensera nos peines.\n\nCourons vers le prix devant nous !\nBientôt on voit Sa beauté,\nLes portes de perles s’ouvrent,\nNous foulerons les rues d'or", 8));
		pg.add(new Page(167, "167. ", "LA VIEILLE CROIX RUGUEUSE. Bb", "Sur une colline lointaine, se tenaitune\nvieille croix;\nEmblème de souffrance et de honte;\nEt j’aime cette vieille croix où Le Très\nCher mourut\nPour un monde des pécheurs perdus.\n\nChoeur\nAinsi, j'aimerai cette vieille croix,\nJusqu’à ce que je dépose mes armes;\nJe vais m'attacher à la vieille croix\nEt L’échanger contre une couronne.\n\nCette vieille croix rugueuse si méprisée\ndu monde,\nElle a une attraction pour moi;\nLe Cher Agneau de Dieu abandonna\nSa gloire\nPour la porter au triste Calvaire.\n\nDans la vieille croix rugueuse, teintée\nde sang divin,\nUne merveilleuse beauté je vois.\n\nC'est sur cette croix que Jésus souffrit,\nmourut\nPour mon pardon, ma pureté.\n\nA la vieille croix rugueuse, Je serai\nsi fidèle,\nJoyeux je porterai Sa honte;\nUn jour Il m’appellera à ma maison\nlointaine\nPour être toujours dans Sa gloire", 8));
		pg.add(new Page(168, "168. ", "OU IL ME CONDUIT F", "J’entends mon Sauveur appeler,\nJ’entends mon Sauveur appeler,\nJ’entends mon Sauveur appeler:\n«Prends ta croix, viens après moi,\nsuis moi.»\n\nChoeur\nOù Il me conduit je Le suis,\nOù Il me conduit je Le suis,\nOù Il me conduit je Le suis,\nJ’irai avec Lui jusqu’à la fin.\n\nJ’irai avec Lui au jardin,\nJ’irai avec Lui au jardin,\nJ’irai avec Lui au jardin,\nJ’irai avec Lui jusqu’à la fin.\n\nJ’irai avec Lui au jugement,\nJ’irai avec Lui au jugement,\nJ’irai avec Lui au jugement,\nJ’irai avec Lui jusqu’à la fin.\n\nIl me donnera grâce et gloire,\nIl me donnera grâce et gloire,\nIl me donnera grâce et gloire,\nIl ira avec moi jusqu’au bout", 8));
		pg.add(new Page(169, "169. ", "MERVEILLEUX Ab", "Mon coeur chante aujourd’hui de joie,\nd’allégresse :\nJésus sauve, satisfait, bannit\nma tristesse;\nPlus de condamnation, j’ai la paix en moi,\nJésus est merveilleux, puissant pour\ndélivrer.\n\nChoeur\nMerveilleux, merveilleux, Jésus est\npour moi,\nConseiller, Dieu Puissant, Prince de\nla paix;\nIl me sauve, Il me garde du péché,\nde honte;\nMerveilleux est mon Rédempteur,\ngloire à Lui!\nHier esclave, maintenant libre\nde toute condamnation,\nJésus donne liberté et un plein salut,\nLes péchés du passé me sont\npardonnés\nEt mon nom est écrit dans le Livre du Ciel.\n\nAvec mon Seigneur vivant dans\nla sainte union,\nJour après jour, je vis dans la douce\ncommunion\nSa grâce m'a changé dans ma basse\ncondition\nDepuis que mon âme reçut plein salut\ngratuit", 8));
		pg.add(new Page(170, "170. ", "OU IRAI-JE? G", "Vivant dans ce vieux monde plein\nde péchés,\nQui offre à peine consolation;\nM’efforçant à vaincre les tentations\nOù irai-je sinon au Seigneur?\n\nChoeur\nOù irai-je, ô où irai-je\nTrouver un refuge pour mon âme\nEt un ami pour m'aider à la fin,\nOù irai-je sinon au Seigneur?\nMes voisins sont gentils, je les aime tous\nEt nous vivons en harmonie;\nMais quand mon âme désire la\nmanne du Ciel,\nOù irai-je sinon au Seigneur?\nVie sur terre est belle avec les amis,\nLa Parole de Dieu me console;\nMais en face de la froide main de la mort,\nOù irai-je sinon au Seigneur?", 8));
		pg.add(new Page(171, "171. ", "MERVEILLEUSE PAIX. Ab", "Ce soir, loin dans la profondeur\nde mon esprit\nS’élève un chant plus doux que\nle psaume;\nPareil aux accords célestes, ce chant\ntombe sans cesse\nSur mon âme comme un calme infini.\n\nChoeur\nPaix! paix! merveilleuse paix,\nVenant de la part du Père céleste;\nO inonde pour toujours mon esprit,\nje prie,\nDes vagues d’amour insondables.\n\nDans cette merveilleuse paix, quel\ntrésor je possède,\nEnfouie profondément dans mon âme;\nTellement ancrée qu’aucune puissance\nne peut l’ôter\nDurant les jours de l’éternité.\n\nCe soir, je me repose dans cette\nmerveilleuse paix;\nDoux repos sous contrôle de Jésus!\nCar je suis gardé de tout danger\nnuit et jour,\nMon âme est inondée de Sa gloire.\n\nEt je pense qu’en montant vers cette\ncité de paix\nOù je verrai l’Auteur de la paix,\nCette mélodie que chanteront\nles rachetés,\nS’entendra dans ce royaume céleste.\n\nO âme, ici sans repos, sans consolation,\nMarchant sur les rudes sentiers\ndu temps,\nPrends Jésus comme ami avant que\nla nuit tombe;\nOh! accepte cette douce paix\nsi sublime", 8));
		pg.add(new Page(172, "172. ", "LE SOLEIL NE SE COUCHERA JAMAIS F", "Le soleil ne se couchera point\ndans cette ville,\nLe soleil ne se couchera point;\nLes fleurs sont épanouies à jamais,\nLe soleil ne se couchera jamais.\n\nJ’ai vraiment envie d’y aller,\nJ’ai envie d’y aller;\nLes fleurs sont épanouies à jamais,\nLe soleil ne se couchera jamais.\n\nParfois j’ai bien envie de crier,\nJ’ai bien envie de crier;\nLes fleurs sont épanouies à jamais,\nLe soleil ne se couchera jamais", 8));
		pg.add(new Page(173, "173. ", "JE ME MIS A GENOUX ET CRIAI «SAINT» Bb", "Dans mon rêve j’allai à la ville «Gloire»,\nSi belle et brillante,\nEn y entrant, je criai «Saint»,\nTous les anges me rencontrèrent là;\nIls me présentèrent tous les palais,\nEt oh! que n’ai-je pas vu!\nMais je dis : «Je désire voir Jésus,\nCelui qui mourut pour tous.»\n\nChoeur\nAlors je me mis à genoux,\nJe criai : «Saint, Saint, Saint»,\nJe battai les mains chantant : «Gloire,\nGloire, oh! gloire au Fils de Dieu».\n\nEn entrant dans cette ville, mes amis\nMe reconnurent bien,\nEt me montrèrent tout au Ciel,\nQuel spectacle indescriptible!\nJe vis Abraham, Isaac, Jacob,\nMarc, Luc et Timothée,\nMais je dis : «Je désire glorifier\nCelui qui mourut pour moi.\n\n»\nDans mon rêve quand je vis mon\nSauveur,\nOh! gloire, gloire à Dieu!\nEt je tombai juste devant Lui,\nChantant : « Louange au Nom de Dieu;»\nM’inclinant, j’adorai Jéhovah,\nMon ami du Calvaire,\nCar je désirai louer Jésus,\nSauveur d’un pécheur comme moi", 8));
		pg.add(new Page(174, "174. ", "QUAND LES SAINTS ENTRERONT Eb", "Je suis pèlerin, étranger,\nErrant dans ce monde pécheur,\nSur ma route vers cette cité\nLorsque les saints entreront.\n\nChoeur\nQuand les saints entreront,\nLorsque les saints entreront,\nSeigneur, je veux être du nombre\nLorsque les saints entreront.\n\nJe sais, je verrai mon Sauveur\nSi ma vie est libérée,\nLe Ciel m’ouvrira ses portes\nLorsque les saints entreront.\n\nNous rassemblant autour du trône\nEt les portes bien fermées,\nJe crierai : «Gloire! gloire!»\nLorsque les saints entreront.\n\nJ’attends que le chariot descende\nEt je monterai à bord,\nSur les nuées j’irai au Ciel\nLorsque les saints entreront", 8));
		pg.add(new Page(175, "175. ", "JE VEUX ETRE CHRETIEN Eb", "Dans ce monde j’ai essayé toutes choses\nEt je suis heureux de dire\nQu’il n’y a rien comme la religion\nA la bonne et ancienne mode;\nJe marche maintenant à l’ancienne mode\nEt je veux que le monde sache :\n«Etre un Chrétien à l’ancienne mode là,\nJ'aime mieux que tout le reste.»\n\nChoeur\nEtre un Chrétien à l’ancienne mode,\nJ'aime mieux que tout le reste;\nRien n’est comme un chrétien à\nl'ancienne mode\nQui exprime l’amour chrétien;\nJe marche sur la vieille grande route,\nEt je proclame partout où je vais :\n«Etre un Chrétien à l’ancienne mode là,\nJ'aime mieux que tout le reste.\n\n»\nBien des choses que j'aimerais être\nComme je poursuis mon voyage;\nJ’ai désiré être un leader\nComme tout mortel le voudrait;\nJ'aimerais être un millionnaire\nQui distribue des millions,\nMais être Chrétien à l’ancienne mode là,\nJ'aime mieux que tout le reste.\n\nTout est clair depuis ma conversion,\nJe chante, je prie et je crie,\nMes fardeaux enlevés, depuis\nQue le Sauveur m'a sauvé.\n\nJe proclamerai partout au monde,\nComme je voyage ici-bas :\n«Etre un Chrétien à l’ancienne mode là,\nJ'aime mieux que tout le reste.\n\n»", 8));
		pg.add(new Page(176, "176. ", "ASSURANCE BENIE Eb", "Assurance bénie, Jésus est mien!\nOh! quel avant goût de la divine gloire!\nRacheté, héritier du salut,\nLavé dans Son sang, né de l’Esprit.\n\nChoeur\nC’est mon histoire, c’est ma chanson,\nJe loue mon Sauveur le long du jour;\nC’est mon histoire, c’est ma chanson,\nJe loue mon Sauveur le long du jour.\n\nParfaite soumission, parfaites délices,\nVisions d’enlèvement éclatent à ma vue;\nLes anges descendant du Ciel apportent\nEchos de la grâce, murmures d’amour.\n\nParfaite soumission, tout au repos,\nEn mon Sauveur; j'ai joie, bénédiction,\nVeillant, attendant, les yeux levés,\nPlein de Sa bonté, couvert d’Amour", 8));
		pg.add(new Page(177, "177. ", "LA NUEE ET LE FEU Eb", "Comme autrefois, quand les foules\nd’Israël\nEtaient forcées d’être dans le désert,\nIls crurent en leur Dieu pour qu’à la\nlumière\nDu jour parfait Il les mène.\n\nChoeur\nAinsi donc le signe du feu la nuit,\nLe signe de la nuée le jour,\nPlanant en haut, juste devant,\nComme ils parcourent leur chemin,\nSeront un guide, un conducteur,\nJusqu’à franchir le désert,\nCar le Seigneur, notre Dieu, en son temps,\nCertes, mènera à la lumière.\n\nDe long en large, comme un bateau\nsans voile\nSans boussole, guide pour passer\nla vallée,\nLe signe de leur Dieu était toujours près,\nEncourageant leurs faibles coeurs.\n\nDurant leurs errances, ils étaient nourris,\nVers la terre promise, ils étaient conduits;\nPar la main de Dieu sous une conduite\nsûre,\nIls furent conduits à Canaan", 8));
		pg.add(new Page(178, "178. ", "JE NE PASSERAI LE JOURDAIN SEUL Eb", "Quand j’atteindrai la rivière à la fin du jour,\nAu dernier coup de vent de chagrins,\nQuelqu’un m’attendra là pour m’indiquer\nla route,\nJe ne passerai le Jourdain seul.\n\nChoeur\nJe ne passerai le Jourdain seul,\nJésus mourut, expia, mes péchés;\nQuand je verrai la nuit, Il m'attendra là-bas,\nJe ne passerai le Jourdain seul.\n\nBien souvent je suis las, abandonné et\ntriste,\nQuand mes amis semblent tous partis;\nUne pensée me console et rend mon\ncoeur joyeux,\nJe ne passerai le Jourdain seul.\n\nQue les flots de chagrin et de souci déferlent,\nChrist,le Sauveur, prendra soin des Siens,\nIl gardera mon âme jusqu’au bout du\nvoyage,\nJe ne passerai le Jourdain seul", 8));
		pg.add(new Page(179, "179. ", "DOUCEMENT ET TENDREMENT Ab", "Doucement et tendrement Jésus appelle,\nIl nous appelle toi et moi,\nVois-Le aux portails, Il attend et Il veille,\nVeillant pour toi et pour moi.\n\nChoeur\nReviens, reviens,\nA la Maison, ô toi, fatigué;\nArdemment, tendrement Jésus appelle:\n«Pécheur, rentre à la Maison.\n\n»\nPourquoi tarder quand Jésus\nnous implore,\nNous implorant toi et moi,\nPourquoi donc traîner et négliger\nSa grâce,\nSa grâce pour toi et pour moi?\nMaintenant le temps s’enfuit,\nles moments passent,\nS’éloignant de toi et moi;\nLes ombres s’assemblent, la nuit\nde mort vient,\nVenant pour toi et pour moi.\n\nOh! quel merveilleux amour Il a promis,\nPromis à toi et à moi;\nMalgré nos péchés, Il donne\ngrâce et pardon,\nPardon à toi et à moi", 8));
		pg.add(new Page(180, "180. ", "PRES DE TOI G", "Toi, ma portion éternelle,\nPlus qu’un ami ou la vie,\nPendant mon pèlerinage,\nLaisse-moi marcher avec Toi.\n\nPrès de Toi, près de Toi,\nPrès de Toi, près de Toi;\nPendant mon pèlerinage,\nLaisse-moi marcher avec Toi.\n\nMa prière ne sera jamais\nPour les plaisirs de ce monde;\nOui, je souffrirai avec joie,\nLaisse-moi marcher avec Toi.\n\nPrès de Toi, près de Toi,\nPrès de Toi, près de Toi;\nOui, je souffrirai avec joie,\nLaisse-moi marcher avec Toi.\n\nGuide-moi dans la vallée d'ombres,\nEt sur les vagues de la vie;\nPuissé-je, dans la vie éternelle,\nEntrer avec Toi, Seigneur.\n\nPrès de Toi, près de Toi,\nPrès de Toi, près de Toi;\nPuissé-je, dans la vie éternelle,\nEntrer avec Toi, Seigneur", 8));
		pg.add(new Page(181, "181. ", "Y A-T-IL POUR TOI DES RIVIERES? Ab", "«Aie bon courage!» cria Dieu à Josué,\nEn lui pointant la route sur la rivière ;\nL’infranchissable Jourdain! comme\nc’est impossible!\nComme ils marchaient, soumis,\nles eaux s’ouvrirent.\n\nChoeur\n’Y a-t-il pour toi des rivières\ninfranchissables,\nDes montagnes que tu ne peux pas\nfranchir ?\nDieu, spécialiste dans des choses\ndites impossibles,\nFera ce qu’aucune autre puissance\nne peut faire.\n\nPour vaincre, ils devraient surmonter\nles obstacles ;\nLes murs de Jéricho devraient tomber.\n\nIls durent s’écrouler comme on les\ncontournait ;\nDieu ne faillit point, Il tint Ses\npromesses.\n\nDieu reste le même, Sa Parole mérite\nconfiance,\nIl t’ouvrira une voie à travers l’eau ;\nEt Il change les situations de la vie,\nMontagnes et collines Il fendra pour toi", 8));
		pg.add(new Page(182, "182. ", "LA-BAS NOUS NE VIEILLIRONS JAMAIS Eb", "J’ai entendu parler d’un pays si lointain,\nC’est une belle maison pour l’âme;\nEdifiée par Jésus, là, nous ne mourons\npoint,\nLà-bas nous ne vieillirons jamais.\n\nChoeur\nPlus de vieillesse, plus de vieillesse,\nLà-bas nous ne vieillirons jamais;\nPlus de vieillesse, plus de vieillesse,\nLà-bas nous ne vieillirons jamais.\n\nDans cette belle cité, nous n'allons\nplus errer,\nNous serons bientôt dans la douceur;\nNous louerons le Roi dans les âges\néternels,\nDans ce pays nous ne mourrons\npoint.\n\nNotre tâche accomplie, nous\nserons couronnés,\nNos troubles et nos épreuves passés,\nNos peines finies, nos voix seront\nmêlées à celles\nDe nos bien-aimés déjà partis", 8));
		pg.add(new Page(183, "183. ", "ELEVEZ-LE Ab", "Comment joindre la foule, les hommes\nde toutes couches?\nEn réponse, Jésus donna la clé :\n«Et Moi, si Je suis élevé de la terre,\nJ’attirerai les hommes à Moi.»\n\nChoeur\nElevez-Le, élevez-Le,\nDepuis l’éternité Il dit :\n«Et Moi, si Je suis élevé de la terre,\nJ’attirerai les hommes à Moi.\n\n»\nOh! le monde a faim du pain\nde la vie !\nElevez le Sauveur qu’ils Le voient;\nCroyez-Le, ne doutez pas de Ses\nparoles :\n«J’attirerai les hommes à Moi.\n\n»\nN’exaltez ni église, ni prédicateur,\nPrêchez le plein Evangile gratuit;\nEprouvez-Le, vous verrez cette\npromesse vraie :\n«J’attirerai les hommes à Moi.\n\n»\nElevez-Le en vivant comme\nun Chrétien,\nQu'en vous le monde voie\nle Sauveur,\nEt joyeux, les hommes suivront\nCelui qui dit :\n«J’attirerai les hommes à Moi.\n\n»", 8));
		pg.add(new Page(184, "184. ", "TERRE EPOUSE G", "Terre de blé et vin j’ai atteint,\nSes trésors sont gratuitement miens;\nIci brille un jour merveilleux\nCar toute ma nuit s’est dissipée.\n\nChoeur\nO Terre Epouse, douce Terre Epouse!\nMe tenant sur Ta haute montagne,\nPar delà la mer, je regarde\nOù des palais fin prêts m'attendent;\nJe vois la luisante rive de gloire,\nMon Ciel, ma Maison à jamais.\n\nMon Sauveur vient, marche avec moi,\nNous avons une douce communion,\nTendrement conduit par Sa main,\nCar ceci est l'entrée du Ciel.\n\nUn parfum doux qu’amène la brise\nVient des arbres toujours vernaux;\nLes fleurs, ne se fanant jamais,\nPoussent où coulent les fleuves de vie.\n\nLes zéphyrs semblent m’apporter\nDoux sons des mélodies célestes,\nQuand anges et foule vêtue en blanc\nChantent le cantique de rédemption", 8));
		pg.add(new Page(185, "185. ", "LE SEIGNEUR M’A SAUVE Eb", "Oh! quelle joie! le Seigneur m’a sauvé;\nOh! quelle joie! le Seigneur m’a sauvé;\nN’eût été le Seigneur Jésus, oh! où\nserais-je?\nOh! quelle joie! le Seigneur m’a sauvé.\n\nOh! quelle joie! depuis qu’Il m’a sauvé;\nOh! quelle joie! depuis qu’Il m’a sauvé;\nN’eût été le Seigneur Jésus, oh! où\nserais-je?\nOh! quelle joie! le Seigneur m’a sauvé.\n\nN’es-tu pas gai comme Il t’a sauvé?\nN’es-tu pas gai comme Il t’a sauvé?\nN’eût été le Seigneur Jésus, oh! où\nserais-je?\nOh! quelle joie! le Seigneur m’a sauvé.\n\nOh! je chante depuis qu’Il m’a sauvé,\nOh! je chante depuis qu’Il m’a sauvé,\nN’eût été le Seigneur Jésus, oh! où\nserai-je?\nOh! quelle joie! le Seigneur m’a sauvé", 8));
		pg.add(new Page(186, "186. ", "RASSEMBLANT LES GERBES Bb", "Nous irons joyeux, ce jour, moissonner\nau champ lointain,\nRassemblant les belles gerbes;\nDu matin jusqu’au soir\nnous travaillerons avec force,\nRassemblant les belles gerbes.\n\nChoeur\nRassembler les belles gerbes,\nRassembler les belles gerbes;\nGloire à Dieu, nous allons au pays\ndu jour éternel,\nRassembler les belles gerbes.\n\nSur les monts, collines ou plaines,\nnous moissonnerons le grain,\nRassemblant les belles gerbes;\nOui, nous oeuvrerons partout sans\ncraindre ni défaillir,\nRassemblant les belles gerbes.\n\nNous chanterons, prierons et\nobéirons au Maître,\nRassemblant les belles gerbes;\nNous irons dans d'autres terres,\nobéissant au Seigneur,\nRassemblant les belles gerbes", 8));
		pg.add(new Page(187, "187. ", "QUEL AMOUR MERVEILLEUX ! Ab", "Dieu dût aimé un pécheur tel que moi,\nIl a changé ma tristesse en joie\nIl n'eût de repos qu'Il m'ait ramené,\nQuel est ce merveilleux amour !\n\nChoeur\nOh! quel merveilleux amour,\nOh! quel merveilleux amour,\nQue Dieu aimât un pécheur tel que moi,\nQuel est ce merveilleux amour !\nEt Christ s'est donné librement pour moi,\nCela coûta sa mort sur le Calvaire,\nLa langue humaine n'a pas de noble\nthème,\nComme cet amour qui me sauva.\n\nPour un perdu condamné comme moi,\nLe Père pourvut et le Sauveur mourut,\nC'est le rachat pour un esclave indigne\nQui, longtemps, méprisa la grâce.\n\nEt maintenant, en Son coeur je suis fils,\nMe dit que je ne suis plus serviteur;\nLes vagabondages du monde sont\nfinis,\nSes bras sont largement ouverts", 8));
		pg.add(new Page(188, "188. ", "IL DESCENDIT DE SA GLOIRE F", "Mon Dieu, mon Sauveur descendit de\nSa gloire,\nSon Nom était Jésus, histoire toujours\nvivante.\n\nNé dans une mangeoire, étranger pour\nles Siens,\nUn Homme de chagrins, de douleur, de\nlarmes.\n\nChoeur\nOh! combien je L’aime ! combien je\nL’adore !\nMon Soleil,mon Souffle,mon Tout en tout!\nLe grand Créateur devint mon Sauveur,\nTout ce que Dieu est, demeure en Lui.\n\nOh! quelle humiliation, nous offrant\nrédemption!\nQuand en pleines ténèbres, nous étions\nsans espoir;\nDieu de grâce, Dieu tendre,abandonnant\nSa gloire\nPour courtiser, gagner, sauver mon âme.\n\nSans aucun regret, Il devint chair et\nsang,\nIl prit la forme humaine, montra le plan\ncaché.\n\nO glorieux mystère, sacrifice du Calvaire,\nMaintenant je sais,Tu es Le grand\n«JE SUIS»", 8));
		pg.add(new Page(189, "189. ", "JE TE RENCONTRERAI A L’AUBE Eb", "Je te rencontrerai à l’aube sur la\nsplendide rive,\nQuand toute peine aura été ôtée,\nJe serai à l’entrée quand les portes\ns’ouvriront large,\nA la fin d'une longue et triste vie.\n\nChoeur\nJe te rencontrerai à l’aube avec un\n«Bonjour!»\nAssis au bord du fleuve, joyeux, nous\nrenouerons les vieilles amitiés,\nTu me reconnaîtras le matin par mon\nsourire,\nQuand je te rencontrerai à l’aube dans\nla ville en forme de carré.\n\nJe te rencontrerai à l’aube, bientôt, un\nde ces jours,\nJ’échangerai la croix contre une couronne;\nDans ce pays, il n’y aura plus de\ndéception ni mort d’hommes,\nAu coucher du soleil de cette vie.\n\nJe te rencontrerai à l’aube, à la fin de la\nroute,\nDans les rues de cette ville tout en or;\nOù tous nous pourrons être ensemble,\nheureux pour toujours,\nAu fil des années, au fil des âges", 8));
		pg.add(new Page(190, "190. ", "IL T’OBSERVE F", "Tout au long du chemin vers\nla demeure de l’âme,\n‘Y a un Oeil qui t’observe;\nCe grand Oeil est ouvert sur\nchaque pas que tu fais,\n‘Y a un Oeil qui t’observe.\n\nChoeur\nIl t’observe, Il t’observe,\nVeille chaque jour au chemin que\ntu prends;\nIl t’observe, Il t’observe;\nCet Oeil qui voit toute chose,\nte surveille.\n\nEn plein vol de ta vie, sois sur\nle droit chemin,\n’Y a un Oeil qui t’observe\nDieu te dit : «Ne prends pas\nla voie de l’ennemi.\n\n»\n’Y a un Oeil qui t’observe.\n\nVise chaque fois le but : cette\nbelle demeure de l’âme,\n’Y a un Oeil qui t’observe;\nNe t’en détourne point pour\nle présent royaume,\n’Y a un Oeil qui t’observe", 8));
		pg.add(new Page(191, "191. ", "DERRIERE LE RIDEAU DU TEMPS Eb", "Entre le Ciel et la terre s’étale\nun rideau,\nDerrière se trouve un beau pays,\nLà, les maux de cette vie ne peuvent\nplus me toucher;\nDieu, puis-je voir derrière le rideau du\ntemps!\n\nChoeur\nDieu, puis-je voir derrière le rideau de\npeines et de peur,\nPuis-je voir ce ciel ensoleillé!\nÇa fortifierait ma foi, bannirait toute peur;\nDieu, puis-je voir derrière le rideau du\ntemps!\nJe suis seul, sans secours et je veux\nvoir Jésus,\nEntendre les cloches du port sonner,\nLà où mes amis, mes chers bien-aimés\nm’attendent;\nDieu, puis-je voir derrière le rideau du\ntemps!\nTrès nostalgique, très triste, je désire\nvoir Jésus,\nEntendre les cloches du port sonner;\nÇa rendrait ma route agréable, ôtant\ntoute peur;\nDieu, puis-je voir derrière le rideau du\ntemps!", 8));
		pg.add(new Page(192, "192. ", "DU MIEL SUR LE ROC F", "Oh! toi mon frère, connais-tu\nle Sauveur,\nQui est merveilleux, bon, fidèle?\nIl est «le Rocher de ton salut!»\n’Y a du Miel pour toi sur le Roc.\n\nChoeur\nOh! mon frère, ’y a du Miel sur le Roc,\n’Y a du Miel pour toi sur le Roc;\nLaisse le sang couvrir tous tes péchés,\n‘Y a du Miel pour toi sur le Roc.\n\nAs-tu goûté que le Seigneur est bon?\nMarches-tu sur la voie nouvelle?\nAs-tu bu à la Fontaine vivante?\n’Y a du Miel pour toi sur le Roc.\n\nDemandes-tu à Dieu le Père en prière:\n«Qu’est-ce que tu veux que je puisse\nfaire?»\nNe crains point, sûrement Il répondra;\n’Y a du Miel pour toi sur le Roc.\n\nAlors parcours les artères et les rues,\nPrêche au petit ou grand nombre;\nEt dis à chaque frère qui est tombé,\n’Y a du Miel pour toi sur le Roc", 8));
		pg.add(new Page(193, "193. ", "LE CHRIST DEVOILE Eb", "Notre béni Christ de beauté\nEtait voilé aux humains;\nMais par souffrances, chagrin et mort,\nVoile, en deux, Il déchira.\n\nChoeur\nOh! regardez l’homme de chagrin!\nRegardez-Le dévoilé,\nOh! Il est le puissant Conquérant,\nDès qu'Il déchira le voile,\nOh! Il est le puissant Conquérant,\nComme Il déchira le voile.\n\nOui, Il est avec Dieu, le Père,\nLà, intercédant pour vous;\nCar Il est le puissant Vainqueur,\nComme Il déchira le voile.\n\nSaints anges s’inclinent devant Lui,\nLes hommes de la terre Le louent;\nCar Il est le cher Bien-aimé,\nComme Il déchira le voile.\n\nDans le temps, les âges sans fin,\nIl est le seul donateur\nDu grand et profond vrai amour,\nComme Il déchira le voile", 8));
		pg.add(new Page(194, "194. ", "JESUS BRISE TOUTE CHAINE Bb", "Je suis maintenant sur l'autel,\nJe suis maintenant sur l'autel,\nJe suis maintenant sur l'autel,\nQui fut dressé pour moi.\n\nChoeur\nJésus brise toute chaîne,\nJésus brise toute chaîne,\nJésus brise toute chaîne,\nCar Il me libère !\nJe Le louerai pour toujours,\nJe Le louerai pour toujours,\nJe Le louerai pour toujours,\nCar Il me libère !\nJe donnerai à Dieu la gloire,\nJe donnerai à Dieu la gloire,\nJe donnerai à Dieu la gloire,\nCar Il me libère !\nJe crierai Alléluia,\nJe crierai Alléluia,\nJe crierai Alléluia,\nCar Il me libère !\nJe ne doute pas du Sauveur,\nJe ne doute pas du Sauveur,\nJe ne doute pas du Sauveur,\nCar Il me purifie.\n\nJe m'appuie sur Sa Promesse,\nJe m'appuie sur Sa Promesse,\nJe m'appuie sur Sa Promesse,\nPromesse, qui m'est donnée.\n\nSur l'autre rive du Jourdain,\nDans les beaux champs d'Eden\nOù fleurit l'Arbre de Vie,\n'Y a repos pour moi", 8));
		pg.add(new Page(195, "195. ", "C’EST LE SEIGNEUR DE GLOIRE Eb", "Oh! voyez quel genre d’homme qui\nCalme la mer en furie,\nGuérit malades, estropiés,\nBoiteux, fait voir l’aveugle,\nPortes de la prison Il ouvre\nEt libère les captifs;\nVoyez quel genre d’homme Il est,\nQuel genre d’homme est-ce!\n\nChoeur\nC’est le Seigneur de gloire,\nIl est le grand JE SUIS;\nIl est l’Alpha, l’Oméga,\nLe Commencement et la Fin;\nSon Nom est Merveilleux,\nC’est le Prince de la paix;\nIl est le Père éternel\nDurant l’éternité.\n\nOh! voyez quel genre d’homme qui\nDit à la femme au puits :\n«Vie éternelle, Je te donne,\nVie d’une immense richesse.\n\nEt quiconque boira l’eau du puits,\nVivra éternellement.\n\n»\nVoyez quel genre d’homme Il est,\nQuel genre d’homme est-ce !\nOh! voyez quel genre d’homme qui\nGuérit boiteux, infirmes;\n«Tes péchés sont pardonnés, prends\nTon lit marche,» dit-Il.\n\nDebout en puissant Guérisseur,\nIl crie : «Aie foi en Moi;»\nVoyez quel genre d’homme Il est,\nQuel genre d’homme est-ce!\nOh! voyez quel genre d’homme qui\nEst entre Dieu et l’homme!\nSes yeux sont comme une flamme, de feu,\nVan, Il a dans Sa main.\n\nJean Le vit dans les sept Eglises\nComme un soleil radieux.\n\nVoyez quel genre d’homme Il est,\nQuel genre d’homme est-ce!\nOh! voyez quel genre d’homme qui\nEst sur Son trône au Ciel.\n\nDepuis le Ciel, Il règne et\nConduit Ses bien-aimés;\nLion de la tribu de Juda\nEt Racine de David,\nVoyez quel genre d’homme Il est,\nQuel genre d’homme est-ce!", 8));
		pg.add(new Page(196, "196. ", "JE LE LOUERAI Eb", "Quand j’ai vu la fontaine qui lave,\nLarge ouverte pour mes péchés,\nJ’acceptai la cour de l’Esprit\nQui dit: «Veux-tu être pur ?»\n\nChoeur\nJe vais louer, louer l’Agneau,\nImmolé pour les pécheurs;\nVous tous peuples, rendez-Lui\ngloire,\nCar Son sang peut laver chaque\ntache.\n\nLa route étant étroite et droite,\nToutes mes prétentions tombèrent;\nMes plans, ambitions et désirs\nRéduits en cendres à mes pieds.\n\nEt le feu de Dieu sur l’autel\nDe mon coeur fut allumé;\nJe Le louerai pour toujours,\nGloire ! Gloire à Son Nom !\nBéni soit le Nom de Jésus !\nJe suis heureux qu’Il m’ait pris;\nIl pardonna mes transgressions,\nIl a purifié mon coeur", 8));
		pg.add(new Page(197, "197. ", "Il Y A UN GRAND JOUR QUI VIENT G", "Il y a un jour qui vient, un grand jour\nqui vient,\n’Y a un grand jour qui vient très bientôt;\nSaints et pécheurs seront séparés à\ndroite et à gauche,\nEs-tu bien prêt pour ce jour qui vient?\n\nChoeur\nEs-tu bien prêt? Es-tu bien prêt?\nEs-tu prêt pour le jour du jugement?\nEs-tu bien prêt? Es-tu bien prêt?\nPour l’heure du jugement?\nIl y a un jour radieux, jour radieux\nqui vient,\n’Y a un jour radieux qui vient bientôt;\nMais son éclat ne viendra qu’à ceux\nqui aiment le Seigneur,\nEs-tu bien prêt pour ce jour qui vient?\nIl y a un jour triste, jour triste qui vient,\n’Y a un jour triste qui vient bientôt;\nLe pécheur saura son sort :\n«Va-t-en, Je ne te connais pas.\n\n»\nEs-tu bien prêt pour ce jour qui vient?", 8));
		pg.add(new Page(198, "198. ", "IL VIENT BIENTOT Ab", "Pendant ces derniers jours du temps,\nQuelle joie l’espoir glorieux procure,\nBientôt, ô vérité sublime!\nRoi des rois, Seigneur des seigneurs,\nIl règne.\n\nChoeur\nIl vient bientôt, Il vient bientôt;\nJoyeux nous accueillons Son retour;\nQue cela soit matin, midi ou soir,\nC’est vrai, Il vient bientôt.\n\nLes signes sur terre et dans l’air,\nOu peints sur le ciel étoilé,\nTémoins fidèles de Dieu déclarent\nQue la venue du Sauveur est bien pro-\nche.\n\nLes morts en Christ dormant sous\nterre,\nNombreux, ressusciteront tous\nLorsque, par les portails du ciel,\nIl vient préparer notre Paradis.\n\nEt nous, les vivants, enlevés,\nRencontrerons notre Seigneur;\nCette chère espérance n'est pas vaine,\nMais nous nous consolons par cette parole", 8));
		pg.add(new Page(199, "199. ", "QUEL AMI ! F", "Quel ami nous avons en Jésus,\nPortant nos péchés et peines!\nO quel privilège d’apporter\nTout à Dieu dans la prière!\nSouvent nous perdons la paix,\nEn vain nous portons la peine\nParce que nous n’apportons pas\nTout à Dieu dans la prière.\n\nAvons-nous épreuves, tentations?\nY’a-t-il trouble quelque part?\nNe perdons jamais courage,\nAmenons tout au Seigneur.\n\nOù trouver l'ami fidèle\nQui peut partager nos peines?\nJésus connaît nos faiblesses,\nAmenons tout au Seigneur.\n\nSommes-nous faibles,tellement chargés\nEt accablés des soucis ?\nPrécieux Sauveur, notre refuge,\nAmenons tout au Seigneur.\n\nTes amis t'abandonnent-ils?\nAmène tout au Seigneur;\nDans Ses bras Il te gardera,\nLà, tu seras consolé", 8));
		pg.add(new Page(200, "200. ", "JE VAIS A LA TERRE PROMISE. F", "Aux bords du Jourdain je me tiens,\nMes yeux se portent au loin,\nVers le beau pays de Canaan,\nOù se trouvent mes trésors.\n\nChoeur\nJe vais à la terre promise,\nJe vais à la terre promise,\nOh! qui veut venir avec moi?\nJe vais à la terre promise.\n\nSur ces larges plaines étendues\nBrille un jour éternel;\nLà, Dieu le Fils règne à jamais,\nEt dissipe la nuit.\n\nNi souffle malsain, ni vents froids\nSur ce rivage sain\nMaladie, chagrin, peine et mort\nN'y sont jamais sentis.\n\nQuand j’atteindrai ce bel endroit :\nËtre à jamais béni.\n\nQuand je vois la face de mon Père,\nEn Lui, j'aurai repos", 8));
		pg.add(new Page(201, "201. ", "LE GRAND MEDECIN Eb", "Le grand Médecin est ici maintenant,\nLe compatissant Jésus\nRéconforte le coeur brisé.\n\nEcoute la voix de Jésus!\n\nChoeur\nLe plus doux chant de séraphin,\nLe plus doux Nom pour un mortel,\nLe plus doux choeur jamais chanté,\nJésus, béni Jésus.\n\nTes nombreux péchés pardonnés,\nEcoute la voix de Jésus;\nEn route pour le Ciel, va en paix.\n\nPorte une couronne avec Lui.\n\nToute gloire à l’Agneau immolé!\nJe crois maintenant en Jésus;\nJ’aime le Nom béni du Sauveur,\nOh! J’aime le Nom de Jésus!\nSon Nom dissipe mes fautes et peurs,\nPas autre Nom que Jésus;\nMon âme se réjouit d'entendre\nCe précieux Nom de Jésus!", 8));
		pg.add(new Page(202, "202. ", "JE DOIS DIRE A JESUS Eb", "Je dois dire à Jésus tous mes soucis;\nJe ne peux porter seul ces fardeaux;\nDans ma détresse, Il m'aidera bien;\nToujours Il aime et prend soin des Siens.\n\nChoeur\nJe dois le Lui dire, le dire à Jésus!\nJe ne peux porter seul mes fardeaux;\nJe dois le Lui dire, le dire à Jésus!\nJésus peut m'aider, oui, Jésus seul.\n\nJe dois dire à Jésus tous mes ennuis;\nIl est l'Ami bon, compatissant;\nSi je Lui demande, Il délivrera,\nIl mettra vite fin à mes ennuis.\n\nTenté, éprouvé, je veux un Sauveur,\nQui peut m'aider à porter mon poids;\nJe dois le Lui dire, le dire à Jésus;\nPeines et soucis Il m'aide à porter.\n\nOh! combien le monde m'attire\nvers le mal!\nEt mon coeur est tenté de pécher!\nJe dois dire à Jésus, Il m'aidera\nA avoir la victoire sur le monde", 8));
		pg.add(new Page(203, "203. ", "RIEN NE SEPARE G", "Rien ne sépare mon âme du Sauveur,\nRien de ce rêve illusoire du monde :\nJ’ai renoncé au plaisir du péché,\nJésus est mien, rien ne nous sépare.\n\nChoeur\nRien ne sépare mon âme du Sauveur,\nAinsi je peux voir Sa face bénie;\nRien n’empêche la moindre de Ses\nfaveurs,\nLibère la voie! Que rien ne sépare.\n\nLes obstacles tels que plaisirs du\nmonde,\nCoutumes qui paraissent inoffensives,\nNe doivent point séparer mon coeur de\nLui;\nIl est mon Tout, rien ne nous sépare.\n\nLes obstacles comme orgueil ou titre;\nLe moi ou amis n’interviendront,\nMême si j'ai beaucoup de tribulations,\nJ’ai décidé, rien ne nous sépare.\n\nRien ne sépare, même pas les dures\népreuves,\nMême si le monde se ligue contre moi;\nMe reniant, veillant dans la prière,\nJe vaincrai donc sans rien qui sépare", 8));
		pg.add(new Page(204, "204. ", "QUEL JOUR CE SERA ! Ab", "Il vient un jour où les chagrins ne seront\nplus,\nNi nuages dans le Ciel, ni larmes\nvoilant la vue;\nTout est paix éternellement sur ce beau\nrivage doré,\nOh! quel jour, glorieux jour ce sera!\n\nChoeur\nOh! quel jour ce sera quand je verrai\nmon Jésus!\nJe contemplerai Sa face, Lui qui m’a\nsauvé par Sa grâce;\nIl me prendra par la main, me conduira\nen terre promise,\nOh! quel jour, glorieux jour ce sera!\nIl n'y aura ni chagrins ni fardeaux à porter,\nNon plus de maladies, douleurs et\nséparations;\nPour toujours je serai avec Celui\nqui est mort pour moi\nOh! quel jour, glorieux jour ce sera!", 8));
		pg.add(new Page(205, "205. ", "PRES DE LA CROIX F", "Près de la croix garde-moi,\nLà, une précieuse fontaine,\nFlot gratuit et guérissant,\nCoule du Mont Calvaire.\n\nChoeur\nA la croix, à la croix,\nSois ma gloire à jamais;\nJusqu'à ce que sur l'autre rive,\nRavi, je trouve repos.\n\nPrès de la croix, tout tremblant,\nAmour, grâce m’ont trouvé;\nL’Etoile brillante du matin,\nLà, brille autour de moi.\n\nPrès de la croix, ô Agneau\nMontre-moi ses scènes;\nAide-moi à marcher toujours,\nEtant sous ses ombres.\n\nPrès de la croix, j'attendrai,\nVeillant, croyant, toujours,\nJusqu’au jour où j'atteindrai\nL'autre rive dorée", 8));
		pg.add(new Page(206, "206. ", "NE M’OUBLIE PAS Ab", "Ne m’oublie pas, ô doux Sauveur,\nEcoute ma voix;\nQuand Tu répondras aux autres,\nNe m’oublie pas.\n\nChoeur\nSauveur, Sauveur,\nEcoute ma voix;\nQuand aux autres Tu répondras,\nNe m’oublie pas.\n\nLaisse-moi près de Ton trône\nde grâce\nTrouver du repos;\nA genoux dans la contrition,\nViens, secours ma foi.\n\nComptant seulement sur Tes mérites,\nJe cherche Ta face;\nGuéris mon esprit affligé,\nSauve-moi par Ta grâce.\n\nToi, Fontaine de mon réconfort,\nPlus que vie pour moi,\nQui d’autre sur terre ou au Ciel,\nAi-je à part Toi?", 8));
		pg.add(new Page(207, "207. ", "JE VOIS UN FLOT CRAMOISI Eb", "Sur le mont Calvaire de peines,\nPrix du péché payé,\nRayons d’espoir pour demain\nJaillirent sur notre route.\n\nChoeur\nFlot cramoisi du sang je vois,\nIl coule du Calvaire,\nSes vagues touchant le Trône\nde Dieu,\nSe déversent sur moi.\n\nN'y a plus de condamnation\nQui reste pour détourner\nMon âme loin de Son salut;\nIl demeure dans mon coeur.\n\nQuand tristesse et chagrin disent:\n«Pécheur n’ose pas prier;»\nJe lève les yeux vers Jésus,\nEt Il m’invite à dire :\nQuand nous serons au portail\nOù vie règne toujours,\nGrande finale des rachetés\nSera ce doux refrain", 8));
		pg.add(new Page(208, "208. ", "VIENS AU FESTIN Bb", "«Tout est apprêté», viens au festin!\nViens, la table est maintenant dressée;\nToi las, toi affamé, viens donc,\nEt tu seras bien nourri.\n\nChoeur\nEcoute «l’invitation»\nEt que quiconque veut, vienne;\nLoue Dieu pour le plein salut,\nSalut pour quiconque veut.\n\n«Tout est apprêté», viens au festin!\nViens car la porte est large ouverte;\nUne place d’honneur est réservée\nPour toi à côté du Maître.\n\n«Tout est apprêté», viens au festin!\nViens, tant qu’Il attend t’accueillir;\nNe tarde pas comme ce jour est tien,\nDemain pourrait ne pas l’être.\n\n«Tout est apprêté», viens au festin!\nSoucis et luttes du monde oublie.\n\nRégale-toi de l’amour de Dieu,\nEt bois la vie éternelle", 8));
		pg.add(new Page(209, "209. ", "SEIGNEUR, JE REVIENS A LA MAISON Ab", "J’étais errant, plus loin de Dieu,\nMaintenant je reviens;\nLe péché, longtemps, j'ai suivi\nSeigneur, je reviens.\n\nChoeur\nJe reviens à la maison\nPour ne plus errer;\nOuvre large Tes bras d’amour,\nSeigneur, je reviens.\n\nJ'ai perdu de précieuses années,\nMaintenant je reviens;\nJe me repens avec des larmes,\nSeigneur, je reviens.\n\nFatigué du péché, Seigneur,\nMaintenant je reviens;\nJe me confie en Ton amour,\nSeigneur, je reviens.\n\nMon âme malade, mon coeur touché,\nMaintenant je reviens;\nRedonne la force, restaure l’espoir,\nSeigneur, je reviens.\n\nMon seul espoir, ma seule défense,\nMaintenant je reviens;\nEst que Jésus mourut pour moi,\nSeigneur, je reviens.\n\nJe sais, j'ai besoin de Son sang,\nMaintenant je reviens;\nO lave-moi plus blanc que la neige,\nSeigneur, je reviens", 8));
		pg.add(new Page(210, "210. ", "LA PORTE DE L’EST Ab", "Je te rencontrerai à l'aube,\nTout juste à la Porte de l’Est;\nSois prêt, pèlerin fidèle,\nDe peur qu’il ne soit trop tard.\n\nChoeur\nJe te rencontrerai à l'aube,\nTout juste à la Porte de l’Est, oui, là-bas;\nJe te rencontrerai à l'aube,\nJe te rencontrerai à l'aube, oui, là-bas.\n\nSi tu me devances dans la gloire,\nSois près de la Porte de l’Est,\nCar je viendrai ce matin-là,\nTu n’attendras pas longtemps.\n\nGardez allumées, nettes, vos lampes\nVeillez, attendez l’Epoux,\nIl viendra à notre rencontre,\nTout juste à la Porte de l’Est.\n\nQuelle grande joie de rencontrer\nLà, les Saints qui nous attendent,\nQuelle rencontre heureuse et bénie,\nTout juste à la Porte de l’Est!", 8));
		pg.add(new Page(211, "211. ", "JESUS PAYA LE TOUT Eb", "J’entends le Sauveur dire :\n«Malgré ta moindre force,\nFaible enfant veille et prie,\nTrouve en moi tout ton Tout.»\n\nChoeur\nJésus paya tout\nEt je Lui dois tout;\nDe mes péchés cramoisis\nIl m'a lavé comme neige.\n\nSeigneur, vraiment je trouve\nQue seule Ta puissance peut\nEpurer un lépreux\nEt fondre un coeur de pierre.\n\nComme je n’ai rien de bon\nPour réclamer Ta grâce,\nJe blanchirai mes robes\nDans le Sang de l’Agneau", 8));
		pg.add(new Page(212, "212. ", "JE CROIS EN DIEU. Bb", "Je crois en Dieu! Je crois en Dieu!\nIl en sera tel qu’Il l’a dit;\nCrois, obéis, lève les yeux, dis :\n«Oui, je crois, oui, je crois en Dieu.\n\n»\nMaintenant si tu veux le salut,\nLe Saint Esprit et la puissance;\nCrois, obéis et confesse-le :\n«Oui, je crois, oui, je crois en Dieu.\n\n»", 8));
		pg.add(new Page(213, "213. ", "NOUS TRAVAILLERONS JUSQU’A CE QUE JESUS VIENNE F", "Terre de repos, je te désire!\nQuand viendra-t-il le temps,\nOù je déposerai les armes\nPour vivre en paix chez moi?\n\nChoeur\nNous allons travailler,\nJusqu’à ce que Jésus vienne;\nEnsuite à la maison,\nNous serons rassemblés.\n\nJoies sereines sur terre je ne connais\nNi paisible abri sûr;\nCe monde est un désert de peines,\nCe monde n'est pas chez moi.\n\nVers Christ je cours pour le repos;\nIl me dit : «Cesse d’errer.\n\n»\nJe trouve en Son Sein du secours\nAvant d'être au Ciel.\n\nAlors j’ai cherché mon Sauveur,\nMes pas n’erreront plus;\nAvec Lui je braverai la mort\nEt j’atteindrai le Ciel", 8));
		pg.add(new Page(214, "214. ", "LES FENETRES DU CIEL Eb", "Les fenêtres du Ciel sont ouvertes,\nLes bénédictions tombent ce soir,\n’Y a joie, joie, joie dans mon coeur,\nCar Jésus-Christ arrange toutes choses;\nJe Lui avais remis mes haillons,\nIl m’a donné une robe toute blanche,\nCe jour, je me régale de la manne,\nC’est pourquoi j’ai la joie ce soir", 8));
		pg.add(new Page(215, "215. ", "PRECIEUX SOUVENIRS Ab", "Précieux souvenirs, anges invisibles,\nSont envoyés vers mon âme;\nIls traînent toujours tout près de moi,\nEt le passé sacré s’ouvre.\n\nChoeur\nPrécieux souvenirs, ô ils subsistent\nEt toujours inondent mon âme!\nDans le silence d’en plein minuit,\nPrécieuses scènes sacrées s’étalent.\n\nO précieux père, ô tendre mère,\nSurvolent les jours solitaires;\nVieilles scènes d’enfance en famille,\nReviennent comme tendres souvenirs.\n\nDans le silence d’en plein minuit\nJ’entends l’écho du passé;\nChants du vieux temps, donnant la joie,\nProvenant du beau pays.\n\nJe me rappelle maman priant,\nPapa priant à genoux;\nLe soleil se couche, la nuit tombe,\nLeurs prières me suivent toujours.\n\nSur le parcours de toute ma vie,\nJ’ignore ce qu’est le futur;\nPlus je médite, cher est l’espoir,\nChers souvenirs inondent mon âme.\n\nPrécieux souvenirs du prophète,\nInondent mon âme tous les jours;\nJe me souviens de précieuses scènes\nQui ne s'évanouiront jamais.\n\nEt le Message et Son signal\nM’ont dit :«C’est la fin du jour.\n\n»\nJe me souviens qu’Il promit de\nRevenir pour les vainqueurs.\n\nPrécieux souvenirs, glorieuses rencontres,\nSur cette terre, d’une mer à l’autre,\nJ’ouïs le Message du Prophète,\nQui me donna vie, espoir.\n\nPrécieux souvenirs de ce dépôt,\nContenant la Nourriture,\nNous sommes rentrés où il stocka\nLa Manne spirituelle du jour", 8));
		pg.add(new Page(216, "216. ", "LE TEMPS DE LA FIN F", "Je vois l’état pitoyable de la terre,\nDes foules amassent pour leur gain\npropre,\nPeinant pour l’aisance et le confort,\nElles ne voient pas que tout est vain,\nc’en est fait d’elles.\n\nChoeur\nLa fin est là, elle est très proche,\nL’Epouse se rassemble et le monde\ns’écroule,\nIsraël se réveille, les nations se\ndisloquent;\nC’est la fin, notre prophète l’a dit, nous\ncroyons.\n\nMessieurs, c’est l’heure dont parla\nnotre prophète,\nL’Ange est venu avec un Cri,\nA Sa Voix la montagne a tremblé,\nLe Cri fort et clair a dit : «Il n’y a plus de\ntemps.\n\n»\nConsidères-tu le message de la fin?\nConsidères-tu Malachie 4,\nApocalypse 10 : 7 et Luc 17 ?\nCe Message les proclame maintenant\net à jamais", 8));
		pg.add(new Page(217, "217. ", "CE N’EST PAS SECRET C", "Ce n’est pas secret ce que Dieu peut\nfaire,\nIl fera pour toi ce qu’Il fit pour d’autres.\n\nIl te pardonnera à bras large ouvert,\nCe n’est pas secret ce que Dieu fait.\n\nCe n’est pas secret, je crois la Parole,\nMes yeux sont ouverts, mon coeur est\nému.\n\nJe l’ai reconnu dès que j’ai suivi\nLa Parole Parlée par le prophète.\n\nCe n’est pas secret là où j’ai été,\nJ’ai vu le prophète, Il m’a fait entrer.\n\nDans mon coeur ouvert brilla la lumière\nCe n’est pas secret, moi je le suis.\n\nCe n’est pas secret quant à ce qu’il est,\nBien plus qu’un prophète, j’en suis\nconvaincu :\nC’est le septième ange, c’est un fils de\nl’homme,\nL’Elie promis dans le plan de Dieu", 8));
		pg.add(new Page(218, "218. ", "QU’IL EST GRAND NOTRE DIEU! F", "Quand je considère les oeuvres de mon\nDieu,\nLa lune, les étoiles, la route qu’Il suivit,\nLes brebis, les boeufs et les bêtes de\nchamp,\nToutes ces merveilles me font voir qu’Il\nest réel.\n\nChoeur\nGrand est notre Dieu ! grande est Sa\nParole!\nLe plus grand jamais connu, c’est bien\nLui.\n\nIl refoula les eaux de la puissante mer\nrouge\nEt dit : «Je vous conduirai,\nConfiez-vous en Moi.\n\n»\nIl a tant oeuvré par notre prophète\nPour montrer Sa grandeur en ce jour-ci.\n\nIl ne change point; Il est toujours le même,\nAinsi, adore-Le, loue-Le, aime Son\ncher Nom", 8));
		pg.add(new Page(219, "219. ", "AINSI SOIS FIDELE Eb", "En ces jours d’épreuves proches de\nla fin\nQuand Christ descend maintenant de\nla gloire,\nLes coeurs des hommes défaillent et\nprennent peur,\nNous savons que c’est vraiment la fin.\n\nChoeur\nAinsi sois fidèle, crois Sa Parole;\nGarde le Message que tu as reçu;\nEcoute Son prophète, veille au\nMessage;\nMarche dans la Lumière où conduit\nl’étoile.\n\nDans chaque âge une étoile a brillé,\nAidant Son peuple à trouver le Vrai;\nDans ce dernier âge une étoile brille,\nFrère, reçois-la, marche dans la\nLumière.\n\nNe crains pas, ne sois pas effrayé,\nTon prophète dort, il n’est certes pas\nmort;\nL’Epouse est dans l’attente de cette\nVoix,\nEt cette espérance fait notre joie.\n\nIl donna Sa promesse à l’Epouse,\nDu cheval blanc le prophète cria :\n«Je parcourrai encore ce sentier.\n\n»\nL’AINSI DIT LE SEIGNEUR n’échoue\npoint", 8));
		pg.add(new Page(220, "220. ", "BENI SOIT LE LIEN QUI UNIT F", "Béni soit le lien qui\nUnit d'Amour nos coeurs;\nLa communion des âmes soeurs\nEst comme celle d'en-haut.\n\nDevant le trône du Père,\nNous versons nos prières;\nNos peurs, espoirs, nos buts\nsont uns,\nRéconforts et soucis.\n\nNous partageons nos peines,\nAinsi que nos fardeaux;\nEt souvent coulent pour l'un et l'autre\nLes larmes de sympathie.\n\nQuand nous nous séparons,\nCela nous cause la peine;\nMais dans les coeurs nous sommes\nunis,\nEspérant nous revoir", 8));
		pg.add(new Page(221, "221. ", "DIEU SOIT AVEC VOUS C", "Dieu soit avec vous jusqu’à nous revoir!\nPar Ses conseils, Il vous soutenant,\nDans Sa bergerie vous gardant;\nDieu soit avec vous jusqu’à nous revoir!\n\nChoeur\nAu revoir, au revoir !\nRendez-vous aux pieds de Jésus;\nAu revoir, au revoir!\nDieu soit avec vous jusqu'à nous revoir!\nDieu soit avec vous jusqu’à nous revoir!\nVous protégeant sous Ses ailes,\nVous donnant la Manne quotidienne,\nDieu soit avec vous jusqu’à nous revoir!\nDieu soit avec vous jusqu'à nous revoir!\nQuand les périls vous confondent,\nEntourez-vous de Ses bras sûrs;\nDieu soit avec vous jusqu’à nous revoir!\nDieu soit avec vous jusqu’à nous revoir!\nRestez sous la bannière d'Amour,\nBrisez la vague de la mort;\nDieu soit avec vous jusqu’à nous revoir!", 8));
		pg.add(new Page(222, "222. ", "PRENDS AVEC TOI LE NOM DE JESUS. Ab", "Prends le Nom de Jésus avec toi,\nEnfant de tristesse et peines;\nJoie et réconfort Il te donne,\nPrends-Le partout où Tu vas.\n\nChoeur\nPrécieux Nom, Nom si doux!\nEspoir de la terre, joie du Ciel;\nPrécieux Nom, Nom si doux!\nEspoir de la terre, joie du Ciel.\n\nPrends toujours le Nom de Jésus!\nComme bouclier face aux pièges,\nSi les tentations t'environnent,\nMurmure ce Nom en prière.\n\nOh! le précieux Nom de Jésus\nFait frémir nos âmes de joie!\nQuand Ses tendres bras nous\naccueillent,\nNous chanterons Ses cantiques.\n\nFléchissant au Nom de Jésus,\nNous prosternant à Ses pieds,\nRoi des rois nous Le couronnons,\nQuand le voyage est fini", 8));
		pg.add(new Page(223, "223. ", "JE M' ENVOLERAI G", "Un beau matin, quand cette vie est finie,\nJe m'envolerai;\nVers une maison sur le rivage du Ciel,\nJe m'envolerai.\n\nChoeur\nJe m'envolerai, ô gloire,\nJe m'envolerai;\nA la fin, alléluia tout à l'heure,\nJe m'envolerai.\n\nQuand les ombres de cette vie\ndisparaissent,\nJe m'envolerai;\nComme un oiseau s'échappant d'une\nprison,\nJe m'envolerai.\n\nEncore quelques jours d'ennuis et alors\nJe m'envolerai;\nVers un pays où la joie demeure,\nJe m'envolerai", 8));
		pg.add(new Page(224, "224. ", "PLUS PRES DE TOI, MON DIEU Eb", "\nPlus près de Toi, mon Dieu,\nPlus près de Toi !\nQu'il s'agisse d'une croix\nQue je dois porter,\nMon chant sera toujours;\nPlus près de Toi, mon Dieu,\nPlus près de Toi, mon Dieu,\nPlus près de Toi.\n\nPareil au vagabond,\nSoleil se couche,\nTenèbres m'environnent,\nMon repos : une pierre;\nDans mes rèves je serai\nPlus près de Toi, mon Dieu,\nPlus près de Toi, mon Dieu,\nPlus près de Toi.\n\nLà, qu'apparaisse la voie,\nMarches du Ciel;\nTu m'envoies tout cela\nPar miséricorde;\nEt les anges m'appelle\nPlus près de Toi, mon Dieu,\nPlus près de Toi, mon Dieu,\nPlus près de Toi.\n\nMes pensées de veille brillent,\nPar Ta louange,\nJe bâtirai Béthel\nDe mes durs chagrins;\nEtre par mes malheurs\nPlus près de Toi, mon Dieu,\nPlus près de Toi, mon Dieu,\nPlus près de Toi.\n\nQue sur une aile de joie,\nPerçant l'azur,\nSoleil, étoiles et lune\nOubliés, je monte;\nMon chant sera toujours :\nPlus près de Toi, mon Dieu,\nPlus près de Toi, mon Dieu,\nPlus près de Toi", 8));
		pg.add(new Page(225, "225. ", "PRENDS MA MAIN, CHER SEIGNEUR Bb", "\nQuand ma voie devient morne,\nSois tout près, cher Seigneur;\nQuand ma vie sera quasi partie;\nEcoute-moi quand j'appelle,\nTiens ma main que je ne tombe;\nPrends ma main, mène-moi à la maison,\n\nChoeur\nPrends ma main, cher Seigneur ,\nConduis-moi, soutiens-moi;\nFatigué, épuisé, je suis faible;\nSous l'orage, dans la nuit,\nMène-moi vers la lumière;\nPrends ma main, mène-moi à la maison.\n\nQuand les ombres apparaissent,\nAlors la nuit approche,\nLe jour passe et décline; je serai\nAu bord de la rivière;\nTiens ma main, guide mes pas,\nPrends ma main, mène-moi à la maison", 8));
		pg.add(new Page(226, "226. ", "MA RICHESSE, MA GLOIRE Ab", "Ma richesse, ma gloire\nEt ma félicité,\nO Jésus! c'est de croire\nQue Tu m'as racheté.\n\nRempli de confiance\nEn Toi, divin Sauveur,\nJe vis dans l'espérance\nEt je marche sans peur.\n\nRien n'ôte les souillures,\nRien ne guérit le coeur,\nSinon les meurtrissures\nEt le sang du Sauveur.\n\nOui, Jésus seul nous lave\nDe toute iniquité,\nEt procure à l'esclave\nl'heureuse liberté.\n\nOh! que toute la terre\nApporte à ce Sauveur\nSes péchés, sa misère!\nIl fait grâce au pécheur.\n\nSon amour insondable\nLui fit quitter le Ciel\nPour donner au coupable\nUn salut éternel.", 8));


		return pg;
    }
}